// Driver routes integration
// This file shows how to integrate driver routes into the main Express app

import express from 'express';
import driverRoutes from './routes/driver.routes.js';
import { verifyAuth, isDriver } from './middleware/auth.js';

export const setupDriverRoutes = (app) => {
  // Mount all driver routes under /api/driver
  app.use('/api/driver', verifyAuth, isDriver, driverRoutes);

  // Additional driver-specific endpoints could be added here
  // For example: notifications, ratings, performance metrics, etc.

  // Driver routes configured
};

/**
 * EXAMPLE: How to add driver routes to your main server file:
 *
 * import { setupDriverRoutes } from './api/driver.integration.js';
 *
 * const app = express();
 *
 * // ... other middleware setup ...
 *
 * // Setup driver routes
 * setupDriverRoutes(app);
 *
 * // ... rest of your app setup ...
 */

import { useState, useEffect, useRef, useCallback, memo } from 'react'
import { useTranslation } from 'react-i18next'
import InfiniteScroll from 'react-infinite-scroll-component'
import {
  PaperClipIcon,
  PaperAirplaneIcon,
  XMarkIcon,
  ArrowUturnLeftIcon,
  PhoneIcon,
  EllipsisVerticalIcon,
  FaceSmileIcon
} from '@heroicons/react/24/outline'
import { useAuthStore } from '@/store/authStore'
import { chatService } from '@/services/chatService'
import { logger } from '@/utils/logger'
import ChatMessage from './ChatMessage'
import FilePreview from './FilePreview'

const MESSAGES_PER_PAGE = 30
const MAX_FILE_SIZE = 10 * 1024 * 1024 // 10 MB
const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'video/mp4', 'audio/mpeg', 'application/pdf']

const ChatWindow = memo(function ChatWindow({ conversationId, recipient }) {
  const { t } = useTranslation()
  const { user } = useAuthStore()

  const [messages, setMessages] = useState([])
  const [hasMore, setHasMore] = useState(true)
  const [loading, setLoading] = useState(true)
  const [sending, setSending] = useState(false)
  const [text, setText] = useState('')
  const [attachments, setAttachments] = useState([])
  const [replyTo, setReplyTo] = useState(null)
  const [fileError, setFileError] = useState(null)
  const [page, setPage] = useState(0)

  const bottomRef = useRef(null)
  const fileInputRef = useRef(null)
  const inputRef = useRef(null)
  const subscriptionRef = useRef(null)

  // Load initial messages
  useEffect(() => {
    if (!conversationId) return
    setMessages([])
    setPage(0)
    setHasMore(true)
    setLoading(true)
    loadMessages(0)

    // Subscribe to new messages
    subscriptionRef.current = chatService.subscribeToConversation(
      conversationId,
      (newMessage) => {
        setMessages(prev => {
          if (prev.some(m => m.id === newMessage.id)) return prev
          return [...prev, newMessage]
        })
        chatService.markMessagesAsRead(conversationId, user?.id).catch(() => {})
      }
    )

    return () => {
      subscriptionRef.current?.unsubscribe?.()
    }
  }, [conversationId]) // eslint-disable-line react-hooks/exhaustive-deps

  const loadMessages = useCallback(async (pageNum) => {
    try {
      const data = await chatService.getMessages(conversationId, {
        limit: MESSAGES_PER_PAGE,
        offset: pageNum * MESSAGES_PER_PAGE
      })
      const sorted = [...(data || [])].sort((a, b) => new Date(a.created_at) - new Date(b.created_at))
      if (pageNum === 0) {
        setMessages(sorted)
        scrollToBottom()
      } else {
        setMessages(prev => [...sorted, ...prev])
      }
      setHasMore((data?.length || 0) === MESSAGES_PER_PAGE)
    } catch (err) {
      logger.error('ChatWindow: failed to load messages', err)
    } finally {
      setLoading(false)
    }
  }, [conversationId])

  const loadMore = useCallback(() => {
    const next = page + 1
    setPage(next)
    loadMessages(next)
  }, [page, loadMessages])

  const scrollToBottom = () => {
    setTimeout(() => bottomRef.current?.scrollIntoView({ behavior: 'smooth' }), 100)
  }

  const handleFiles = (files) => {
    setFileError(null)
    const valid = []
    for (const file of files) {
      if (!ALLOWED_TYPES.includes(file.type)) {
        setFileError(t('chat.invalidFileType', 'نوع الملف غير مدعوم'))
        continue
      }
      if (file.size > MAX_FILE_SIZE) {
        setFileError(t('chat.fileTooLarge', 'الملف أكبر من 10 ميجابايت'))
        continue
      }
      valid.push({ file, preview: URL.createObjectURL(file), type: file.type, name: file.name, size: file.size })
    }
    setAttachments(prev => [...prev, ...valid].slice(0, 5))
  }

  const removeAttachment = (index) => {
    setAttachments(prev => {
      const next = [...prev]
      URL.revokeObjectURL(next[index].preview)
      next.splice(index, 1)
      return next
    })
  }

  const handleSend = async () => {
    const trimmed = text.trim()
    if (!trimmed && attachments.length === 0) return
    setSending(true)
    try {
      // Upload attachments first
      const uploadedFiles = []
      for (const att of attachments) {
        const result = await chatService.uploadAttachment(att.file, conversationId)
        if (result?.url) {
          uploadedFiles.push({ url: result.url, type: att.type, name: att.name, size: att.size })
        }
      }

      await chatService.sendMessage({
        conversationId,
        senderId: user.id,
        content: trimmed,
        attachments: uploadedFiles,
        replyToId: replyTo?.id
      })

      setText('')
      setAttachments([])
      setReplyTo(null)
      scrollToBottom()
    } catch (err) {
      logger.error('ChatWindow: send failed', err)
    } finally {
      setSending(false)
    }
  }

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSend()
    }
  }

  const handleDelete = async (messageId) => {
    try {
      await chatService.deleteConversation?.(messageId)
      setMessages(prev => prev.filter(m => m.id !== messageId))
    } catch (err) {
      logger.error('ChatWindow: delete failed', err)
    }
  }

  if (!conversationId) {
    return (
      <div className="flex-1 flex items-center justify-center bg-gray-50 dark:bg-gray-900">
        <div className="text-center">
          <div className="w-16 h-16 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mx-auto mb-3">
            <PaperAirplaneIcon className="h-8 w-8 text-green-500" />
          </div>
          <p className="text-gray-500 dark:text-gray-400">{t('chat.selectConversation', 'اختر محادثة للبدء')}</p>
        </div>
      </div>
    )
  }

  return (
    <div className="flex flex-col flex-1 h-full min-h-0 bg-white dark:bg-gray-900" data-testid="chat-window">
      {/* Header */}
      <div className="flex items-center gap-3 px-4 py-3 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 shrink-0">
        <div className="w-9 h-9 rounded-full bg-green-100 dark:bg-green-900 flex items-center justify-center text-sm font-semibold text-green-700 dark:text-green-300">
          {recipient?.full_name?.[0]?.toUpperCase() || '?'}
        </div>
        <div className="flex-1 min-w-0">
          <p className="font-medium text-gray-800 dark:text-gray-100 truncate">
            {recipient?.full_name || t('chat.unknownUser', 'مستخدم')}
          </p>
          <p className="text-xs text-gray-400">{recipient?.role || ''}</p>
        </div>
        <button className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full">
          <EllipsisVerticalIcon className="h-5 w-5 text-gray-500" />
        </button>
      </div>

      {/* Messages */}
      <div
        id="chat-messages-scroll"
        className="flex-1 overflow-y-auto px-4 py-4 space-y-3"
        style={{ display: 'flex', flexDirection: 'column' }}
      >
        {loading ? (
          <div className="flex items-center justify-center h-full">
            <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-green-500" />
          </div>
        ) : (
          <div id="scrollable-messages" className="flex flex-col gap-3 flex-1 overflow-y-auto">
            <InfiniteScroll
              dataLength={messages.length}
              next={loadMore}
              hasMore={hasMore}
              inverse
              scrollableTarget="scrollable-messages"
              loader={
                <div className="text-center py-2">
                  <div className="inline-block animate-spin rounded-full h-4 w-4 border-b-2 border-green-500" />
                </div>
              }
              style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}
            >
              {messages.map((msg, i) => {
                const isOwn = msg.sender_id === user?.id
                const prevMsg = messages[i - 1]
                const showAvatar = !prevMsg || prevMsg.sender_id !== msg.sender_id

                return (
                  <ChatMessage
                    key={msg.id}
                    message={msg}
                    isOwn={isOwn}
                    showAvatar={showAvatar}
                    onDelete={handleDelete}
                    onReply={setReplyTo}
                  />
                )
              })}
            </InfiniteScroll>
            <div ref={bottomRef} />
          </div>
        )}
      </div>

      {/* Reply preview */}
      {replyTo && (
        <div className="mx-4 mb-2 px-3 py-2 bg-green-50 dark:bg-green-900/20 border-l-4 border-green-500 rounded-r-lg flex items-center justify-between">
          <div className="min-w-0">
            <p className="text-xs font-medium text-green-600">{replyTo.sender?.full_name}</p>
            <p className="text-xs text-gray-500 truncate">{replyTo.content}</p>
          </div>
          <button onClick={() => setReplyTo(null)} className="p-1 shrink-0">
            <XMarkIcon className="h-4 w-4 text-gray-400" />
          </button>
        </div>
      )}

      {/* Attachment previews */}
      {attachments.length > 0 && (
        <div className="flex items-center gap-2 px-4 pb-2 overflow-x-auto">
          {attachments.map((att, i) => (
            <FilePreview
              key={i}
              file={{ url: att.preview, type: att.type, name: att.name, size: att.size }}
              compact
              onRemove={() => removeAttachment(i)}
            />
          ))}
        </div>
      )}

      {/* Error */}
      {fileError && (
        <p className="px-4 pb-1 text-xs text-red-500">{fileError}</p>
      )}

      {/* Input bar */}
      <div className="px-4 py-3 border-t border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 shrink-0">
        <div className="flex items-end gap-2 bg-gray-100 dark:bg-gray-700 rounded-2xl px-3 py-2">
          <button
            onClick={() => fileInputRef.current?.click()}
            className="p-1.5 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-full transition-colors shrink-0"
            title={t('chat.attach', 'إرفاق ملف')}
          >
            <PaperClipIcon className="h-5 w-5 text-gray-500" />
          </button>

          <textarea
            ref={inputRef}
            value={text}
            onChange={e => setText(e.target.value)}
            onKeyDown={handleKeyDown}
            rows={1}
            placeholder={t('chat.typeMessage', 'اكتب رسالة...')}
            className="flex-1 bg-transparent resize-none text-sm text-gray-800 dark:text-gray-100 placeholder-gray-400 outline-none max-h-32 min-h-[20px]"
            data-testid="chat-input"
          />

          <button
            onClick={handleSend}
            disabled={sending || (!text.trim() && attachments.length === 0)}
            className="p-1.5 bg-green-500 hover:bg-green-600 disabled:opacity-40 disabled:cursor-not-allowed rounded-full transition-colors shrink-0"
            data-testid="send-message-btn"
          >
            {sending
              ? <div className="h-5 w-5 animate-spin rounded-full border-2 border-white border-t-transparent" />
              : <PaperAirplaneIcon className="h-5 w-5 text-white" />
            }
          </button>
        </div>
      </div>

      <input
        ref={fileInputRef}
        type="file"
        accept={ALLOWED_TYPES.join(',')}
        multiple
        className="hidden"
        onChange={e => handleFiles(Array.from(e.target.files || []))}
      />
    </div>
  )
})

export default ChatWindow

import { memo } from 'react'
import { useTranslation } from 'react-i18next'
import { DocumentIcon, ArrowDownTrayIcon, XMarkIcon } from '@heroicons/react/24/outline'
import { PhotoIcon, MusicalNoteIcon } from '@heroicons/react/24/solid'

/**
 * FilePreview - Renders file attachment previews inside chat messages
 */
const FilePreview = memo(function FilePreview({ file, onDownload, onRemove, compact = false }) {
  const { t } = useTranslation()
  const { url, type, name, size } = file || {}

  const formatSize = (bytes) => {
    if (!bytes) return ''
    if (bytes < 1024) return `${bytes} B`
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`
  }

  const isImage = type?.startsWith('image/')
  const isVideo = type?.startsWith('video/')
  const isAudio = type?.startsWith('audio/')
  const isPDF = type === 'application/pdf'

  return (
    <div className={`relative group rounded-lg overflow-hidden border border-gray-200 dark:border-gray-600 ${compact ? 'max-w-[200px]' : 'max-w-xs'}`}>
      {/* Remove button (before send) */}
      {onRemove && (
        <button
          onClick={onRemove}
          className="absolute top-1 right-1 z-10 p-0.5 rounded-full bg-black/50 text-white opacity-0 group-hover:opacity-100 transition-opacity"
          aria-label={t('common.remove', 'إزالة')}
        >
          <XMarkIcon className="h-4 w-4" />
        </button>
      )}

      {isImage && (
        <div>
          <img
            src={url}
            alt={name || t('chat.image', 'صورة')}
            className="w-full max-h-48 object-cover cursor-pointer hover:opacity-90 transition-opacity"
            onClick={() => window.open(url, '_blank')}
          />
          {!compact && (
            <div className="flex items-center justify-between p-2 bg-gray-50 dark:bg-gray-800">
              <span className="text-xs text-gray-500 truncate">{name}</span>
              {onDownload && (
                <button onClick={onDownload} className="p-1 hover:text-green-600 text-gray-400 shrink-0">
                  <ArrowDownTrayIcon className="h-4 w-4" />
                </button>
              )}
            </div>
          )}
        </div>
      )}

      {isVideo && (
        <div>
          <video src={url} controls className="w-full max-h-48" />
          <div className="flex items-center justify-between p-2 bg-gray-50 dark:bg-gray-800">
            <span className="text-xs text-gray-500 truncate">{name}</span>
            {onDownload && (
              <button onClick={onDownload} className="p-1 hover:text-green-600 text-gray-400">
                <ArrowDownTrayIcon className="h-4 w-4" />
              </button>
            )}
          </div>
        </div>
      )}

      {isAudio && (
        <div className="p-3 bg-gray-50 dark:bg-gray-800 flex items-center gap-2">
          <MusicalNoteIcon className="h-8 w-8 text-green-500 shrink-0" />
          <div className="flex-1 min-w-0">
            <p className="text-xs text-gray-700 dark:text-gray-300 truncate">{name}</p>
            <audio src={url} controls className="w-full mt-1 h-8" />
          </div>
        </div>
      )}

      {isPDF && (
        <a
          href={url}
          target="_blank"
          rel="noopener noreferrer"
          className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-800 hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
        >
          <div className="w-10 h-10 rounded-lg bg-red-100 dark:bg-red-900/30 flex items-center justify-center shrink-0">
            <DocumentIcon className="h-6 w-6 text-red-500" />
          </div>
          <div className="min-w-0">
            <p className="text-sm font-medium text-gray-700 dark:text-gray-300 truncate">{name}</p>
            <p className="text-xs text-gray-400">{formatSize(size)}</p>
          </div>
          <ArrowDownTrayIcon className="h-4 w-4 text-gray-400 shrink-0 ml-auto" />
        </a>
      )}

      {!isImage && !isVideo && !isAudio && !isPDF && (
        <a
          href={url}
          download={name}
          className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-800 hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
        >
          <div className="w-10 h-10 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center shrink-0">
            <PhotoIcon className="h-6 w-6 text-blue-500" />
          </div>
          <div className="min-w-0">
            <p className="text-sm font-medium text-gray-700 dark:text-gray-300 truncate">{name}</p>
            <p className="text-xs text-gray-400">{formatSize(size)}</p>
          </div>
        </a>
      )}
    </div>
  )
})

export default FilePreview

// CookieConsent component - handles user cookie consent preferences
// Note: If you see ERR_BLOCKED_BY_CLIENT, check your ad blocker extensions
import { useState, useEffect } from 'react'
import { XMarkIcon, Cog6ToothIcon } from '@heroicons/react/24/outline'
import { logger } from '../utils/logger.js'

// Safe localStorage wrapper
const safeLocalStorage = {
  getItem: (key) => {
    try {
      return localStorage.getItem(key)
    } catch (e) {
      logger.warn('localStorage not available:', e)
      return null
    }
  },
  setItem: (key, value) => {
    try {
      localStorage.setItem(key, value)
    } catch (e) {
      logger.warn('localStorage not available:', e)
    }
  },
  removeItem: (key) => {
    try {
      localStorage.removeItem(key)
    } catch (e) {
      logger.warn('localStorage not available:', e)
    }
  },
}

const CookieConsent = () => {
  const [showBanner, setShowBanner] = useState(false)
  const [showPreferences, setShowPreferences] = useState(false)
  const [preferences, setPreferences] = useState({
    necessary: true, // Always required
    analytics: false,
    marketing: false,
    functional: false,
  })

  useEffect(() => {
    const consent = safeLocalStorage.getItem('cookie_consent')
    if (!consent) {
      setShowBanner(true)
    } else {
      try {
        const parsed = JSON.parse(consent)
        setPreferences(parsed)
      } catch (e) {
        setShowBanner(true)
      }
    }
  }, [])

  const handleAcceptAll = () => {
    const allAccepted = {
      necessary: true,
      analytics: true,
      marketing: true,
      functional: true,
    }
    safeLocalStorage.setItem('cookie_consent', JSON.stringify(allAccepted))
    setShowBanner(false)
  }

  const handleAcceptSelected = () => {
    safeLocalStorage.setItem('cookie_consent', JSON.stringify(preferences))
    setShowBanner(false)
  }

  const handleRejectAll = () => {
    const minimal = {
      necessary: true,
      analytics: false,
      marketing: false,
      functional: false,
    }
    safeLocalStorage.setItem('cookie_consent', JSON.stringify(minimal))
    setShowBanner(false)
  }

  const resetConsent = () => {
    safeLocalStorage.removeItem('cookie_consent')
    setShowBanner(true)
  }

  if (!showBanner && !showPreferences) {
    // Show small button to reopen preferences
    return (
      <button
        onClick={() => setShowPreferences(true)}
        className="fixed bottom-4 left-4 z-50 p-2 bg-gray-100 hover:bg-gray-200 rounded-full shadow-lg transition-colors"
        title="Cookie Preferences"
      >
        <Cog6ToothIcon className="w-5 h-5 text-gray-600" />
      </button>
    )
  }

  if (showPreferences) {
    return (
      <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl max-w-md w-full p-6">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-xl font-bold text-gray-900">Cookie Preferences</h2>
            <button onClick={() => setShowPreferences(false)} className="text-gray-400 hover:text-gray-600">
              <XMarkIcon className="w-6 h-6" />
            </button>
          </div>

          <div className="space-y-4 mb-6">
            <div className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
              <div>
                <p className="font-medium text-gray-900">Necessary</p>
                <p className="text-xs text-gray-500">Required for the website to function</p>
              </div>
              <input type="checkbox" checked disabled className="toggle" />
            </div>

            <div className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
              <div>
                <p className="font-medium text-gray-900">Analytics</p>
                <p className="text-xs text-gray-500">Help us understand how visitors use the site</p>
              </div>
              <input
                type="checkbox"
                checked={preferences.analytics}
                onChange={(e) => setPreferences({ ...preferences, analytics: e.target.checked })}
                className="toggle"
              />
            </div>

            <div className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
              <div>
                <p className="font-medium text-gray-900">Marketing</p>
                <p className="text-xs text-gray-500">Used to deliver relevant advertisements</p>
              </div>
              <input
                type="checkbox"
                checked={preferences.marketing}
                onChange={(e) => setPreferences({ ...preferences, marketing: e.target.checked })}
                className="toggle"
              />
            </div>

            <div className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
              <div>
                <p className="font-medium text-gray-900">Functional</p>
                <p className="text-xs text-gray-500">Enable enhanced functionality and personalization</p>
              </div>
              <input
                type="checkbox"
                checked={preferences.functional}
                onChange={(e) => setPreferences({ ...preferences, functional: e.target.checked })}
                className="toggle"
              />
            </div>
          </div>

          <div className="flex gap-3">
            <button onClick={() => setShowPreferences(false)} className="btn-outline flex-1">
              Cancel
            </button>
            <button
              onClick={() => {
                safeLocalStorage.setItem('cookie_consent', JSON.stringify(preferences))
                setShowPreferences(false)
              }}
              className="btn-primary flex-1"
            >
              Save Preferences
            </button>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="fixed bottom-0 left-0 right-0 z-50 bg-white border-t border-gray-200 shadow-lg">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
          <div className="flex-1">
            <p className="text-sm text-gray-700">
              🍪 We use cookies to enhance your experience. By continuing to visit this site you agree to our use of cookies.
            </p>
            <div className="flex gap-3 mt-2">
              <button
                onClick={() => setShowPreferences(true)}
                className="text-sm text-green-600 hover:text-green-700 font-medium"
              >
                Manage Preferences
              </button>
              <a href="/privacy" className="text-sm text-gray-500 hover:text-gray-600">
                Privacy Policy
              </a>
              <a href="/terms" className="text-sm text-gray-500 hover:text-gray-600">
                Terms of Service
              </a>
            </div>
          </div>
          <div className="flex gap-3 flex-shrink-0">
            <button
              onClick={handleRejectAll}
              className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
            >
              Reject All
            </button>
            <button
              onClick={handleAcceptSelected}
              className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
            >
              Accept Selected
            </button>
            <button
              onClick={handleAcceptAll}
              className="px-4 py-2 text-sm font-medium text-white bg-green-600 hover:bg-green-700 rounded-lg transition-colors"
            >
              Accept All
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

export default CookieConsent

