import { useState } from 'react'
import { useAuthStore } from '@/store/authStore'
import { supabase } from '@/services/supabase'
import { XMarkIcon, FlagIcon } from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'
import { logger } from '../utils/logger.js'

const ReportAbuseModal = ({ isOpen, onClose, reportedUserId = null, reportType = null, category = 'user', categoryId = null }) => {
  const { user } = useAuthStore()
  const [loading, setLoading] = useState(false)
  const [step, setStep] = useState(1)
  const [selectedType, setSelectedType] = useState(reportType || '')
  const [description, setDescription] = useState('')
  const [evidence, setEvidence] = useState('')

  const reportTypes = [
    {
      id: 'illegal_activity',
      label: 'Illegal Activity',
      icon: '🚫',
      description: 'Selling illegal or prohibited items',
      color: 'red'
    },
    {
      id: 'false_info',
      label: 'False Information',
      icon: '⚠️',
      description: 'Misleading product info or fake reviews',
      color: 'orange'
    },
    {
      id: 'fee_circumvention',
      label: 'Fee Circumvention',
      icon: '💰',
      description: 'Attempting to avoid platform fees',
      color: 'yellow'
    },
    {
      id: 'harassment',
      label: 'Harassment',
      icon: '👥',
      description: 'Abusive, threatening, or discriminatory behavior',
      color: 'purple'
    },
    {
      id: 'security_violation',
      label: 'Security Violation',
      icon: '🔒',
      description: 'Hacking, scraping, or security bypass attempts',
      color: 'blue'
    },
    {
      id: 'spam',
      label: 'Spam',
      icon: '📧',
      description: 'Unsolicited messages or advertisements',
      color: 'gray'
    },
  ]

  const handleSubmit = async () => {
    if (!selectedType) {
      toast.error('Please select a report type')
      return
    }

    if (!description.trim()) {
      toast.error('Please provide a description')
      return
    }

    try {
      setLoading(true)

      const { data, error } = await supabase.rpc('create_user_report', {
        p_reporter_id: user.id,
        p_reported_user_id: reportedUserId,
        p_report_type: selectedType,
        p_category: category,
        p_category_id: categoryId,
        p_description: description,
        p_evidence_urls: evidence ? evidence.split('\n').filter(u => u.trim()) : null,
      })

      if (error) throw error

      toast.success('Report submitted successfully. Our team will review it within 24 hours.')
      handleClose()
    } catch (error) {
      logger.error('Submit report error:', error)
      toast.error('Failed to submit report')
    } finally {
      setLoading(false)
    }
  }

  const handleClose = () => {
    setStep(1)
    setSelectedType('')
    setDescription('')
    setEvidence('')
    onClose()
  }

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl max-w-lg w-full max-h-[90vh] overflow-y-auto">
        {/* Header */}
        <div className="sticky top-0 bg-white border-b border-gray-200 p-4 flex items-center justify-between rounded-t-2xl">
          <h2 className="text-xl font-bold text-gray-900">Report Abuse</h2>
          <button onClick={handleClose} className="text-gray-400 hover:text-gray-600">
            <XMarkIcon className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6">
          {/* Step 1: Select Type */}
          {step === 1 && (
            <div className="space-y-4">
              <p className="text-gray-600 mb-4">
                What type of violation are you reporting?
              </p>
              <div className="grid grid-cols-1 gap-3">
                {reportTypes.map((type) => (
                  <button
                    key={type.id}
                    onClick={() => {
                      setSelectedType(type.id)
                      setStep(2)
                    }}
                    className={`flex items-start gap-3 p-4 border-2 rounded-xl text-left transition-all hover:shadow-md ${
                      selectedType === type.id
                        ? `border-${type.color}-500 bg-${type.color}-50`
                        : 'border-gray-200 hover:border-gray-300'
                    }`}
                  >
                    <span className="text-2xl">{type.icon}</span>
                    <div className="flex-1">
                      <p className="font-semibold text-gray-900">{type.label}</p>
                      <p className="text-sm text-gray-500">{type.description}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Step 2: Details */}
          {step === 2 && (
            <div className="space-y-4">
              <div className="flex items-center gap-2 mb-4">
                <button
                  onClick={() => setStep(1)}
                  className="text-sm text-gray-500 hover:text-gray-700"
                >
                  ← Back
                </button>
              </div>

              <div className="p-3 bg-gray-50 rounded-lg">
                <p className="text-sm text-gray-600">Reporting:</p>
                <p className="font-medium">
                  {reportTypes.find(t => t.id === selectedType)?.label}
                </p>
              </div>

              <div>
                <label className="input-label">Description *</label>
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="input h-32 resize-none"
                  placeholder="Please describe what happened in detail..."
                  maxLength={2000}
                />
                <p className="text-xs text-gray-500 mt-1">
                  {description.length}/2000 characters
                </p>
              </div>

              <div>
                <label className="input-label">Evidence (Optional)</label>
                <textarea
                  value={evidence}
                  onChange={(e) => setEvidence(e.target.value)}
                  className="input h-20 resize-none"
                  placeholder="Paste URLs of screenshots or evidence (one per line)..."
                />
                <p className="text-xs text-gray-500 mt-1">
                  Include links to screenshots, messages, or other evidence
                </p>
              </div>

              <div className="p-3 bg-blue-50 border border-blue-200 rounded-lg">
                <p className="text-xs text-blue-800">
                  ⚠️ <strong>Note:</strong> False reports may result in account suspension. 
                  Please only submit genuine concerns.
                </p>
              </div>

              <button
                onClick={handleSubmit}
                disabled={loading || !description.trim()}
                className="btn-primary w-full disabled:opacity-50"
              >
                {loading ? 'Submitting...' : 'Submit Report'}
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

export default ReportAbuseModal

import { memo, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { ArrowDownTrayIcon } from '@heroicons/react/24/outline'
import { csvExport } from '@/services/reports/csvExport'
import { excelExport } from '@/services/reports/excelExport'
import { pdfExport } from '@/services/reports/pdfExport'
import { logger } from '@/utils/logger'

const ExportButtons = memo(function ExportButtons({
  rows = [],
  columns = [],
  filename = 'report',
  title = '',
  previewElementId = null
}) {
  const { t } = useTranslation()
  const [loading, setLoading] = useState(null)

  const handleExport = async (type) => {
    if (!rows.length) return
    setLoading(type)
    try {
      if (type === 'csv') {
        csvExport.exportToCSV(rows, `${filename}.csv`)
      } else if (type === 'excel') {
        excelExport.exportToExcel(rows, `${filename}.xlsx`)
      } else if (type === 'pdf') {
        if (previewElementId) {
          await pdfExport.exportElementToPDF(previewElementId, `${filename}.pdf`, title)
        } else {
          pdfExport.exportTableToPDF(columns, rows, `${filename}.pdf`, title)
        }
      }
    } catch (err) {
      logger.error('ExportButtons: export failed', err)
    } finally {
      setLoading(null)
    }
  }

  const buttons = [
    { type: 'csv', label: 'CSV', color: 'blue' },
    { type: 'excel', label: 'Excel', color: 'green' },
    { type: 'pdf', label: 'PDF', color: 'red' }
  ]

  return (
    <div className="flex items-center gap-2" data-testid="export-buttons">
      {buttons.map(({ type, label, color }) => (
        <button
          key={type}
          onClick={() => handleExport(type)}
          disabled={!!loading || !rows.length}
          className={`flex items-center gap-1.5 px-3 py-1.5 text-sm rounded-lg border transition-colors disabled:opacity-40 disabled:cursor-not-allowed
            ${color === 'blue' ? 'border-blue-300 text-blue-700 hover:bg-blue-50 dark:border-blue-700 dark:text-blue-400 dark:hover:bg-blue-900/20' : ''}
            ${color === 'green' ? 'border-green-300 text-green-700 hover:bg-green-50 dark:border-green-700 dark:text-green-400 dark:hover:bg-green-900/20' : ''}
            ${color === 'red' ? 'border-red-300 text-red-700 hover:bg-red-50 dark:border-red-700 dark:text-red-400 dark:hover:bg-red-900/20' : ''}
          `}
          data-testid={`export-${type}`}
        >
          {loading === type ? (
            <div className="h-3.5 w-3.5 animate-spin rounded-full border-2 border-current border-t-transparent" />
          ) : (
            <ArrowDownTrayIcon className="h-3.5 w-3.5" />
          )}
          {label}
        </button>
      ))}
    </div>
  )
})

export default ExportButtons

import { useState, useEffect, useRef, useCallback, memo } from 'react'
import { useTranslation } from 'react-i18next'
import { useNavigate } from 'react-router-dom'
import { MagnifyingGlassIcon, XMarkIcon } from '@heroicons/react/24/outline'
import { algoliaService } from '@/services/search/algoliaService'
import { logger } from '@/utils/logger'

const DEBOUNCE_MS = 300

const SearchBar = memo(function SearchBar({ placeholder, className = '', onSearch }) {
  const { t } = useTranslation()
  const navigate = useNavigate()

  const [query, setQuery] = useState('')
  const [suggestions, setSuggestions] = useState([])
  const [open, setOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [activeIndex, setActiveIndex] = useState(-1)

  const inputRef = useRef(null)
  const debounceRef = useRef(null)
  const wrapperRef = useRef(null)

  // Close dropdown on outside click
  useEffect(() => {
    const handler = (e) => {
      if (!wrapperRef.current?.contains(e.target)) setOpen(false)
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [])

  const fetchSuggestions = useCallback(async (q) => {
    if (!q || q.length < 2) { setSuggestions([]); return }
    setLoading(true)
    try {
      const hits = await algoliaService.getSearchSuggestions(q)
      setSuggestions(hits.slice(0, 6))
    } catch (err) {
      logger.error('SearchBar suggestions error', err)
    } finally {
      setLoading(false)
    }
  }, [])

  const handleChange = (e) => {
    const val = e.target.value
    setQuery(val)
    setActiveIndex(-1)
    setOpen(true)

    clearTimeout(debounceRef.current)
    debounceRef.current = setTimeout(() => fetchSuggestions(val), DEBOUNCE_MS)
  }

  const handleSubmit = (searchQuery) => {
    const q = (searchQuery || query).trim()
    if (!q) return
    setOpen(false)
    if (onSearch) {
      onSearch(q)
    } else {
      navigate(`/search?q=${encodeURIComponent(q)}`)
    }
  }

  const handleKeyDown = (e) => {
    if (!open) return
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      setActiveIndex(i => Math.min(i + 1, suggestions.length - 1))
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      setActiveIndex(i => Math.max(i - 1, -1))
    } else if (e.key === 'Enter') {
      if (activeIndex >= 0 && suggestions[activeIndex]) {
        handleSubmit(suggestions[activeIndex].name)
      } else {
        handleSubmit()
      }
    } else if (e.key === 'Escape') {
      setOpen(false)
    }
  }

  const clearQuery = () => {
    setQuery('')
    setSuggestions([])
    inputRef.current?.focus()
  }

  return (
    <div ref={wrapperRef} className={`relative ${className}`} data-testid="search-bar">
      <div className="flex items-center border border-gray-300 dark:border-gray-600 rounded-xl bg-white dark:bg-gray-800 px-3 py-2 focus-within:ring-2 focus-within:ring-green-500 gap-2">
        <MagnifyingGlassIcon className="h-5 w-5 text-gray-400 shrink-0" />
        <input
          ref={inputRef}
          type="search"
          value={query}
          onChange={handleChange}
          onKeyDown={handleKeyDown}
          onFocus={() => query.length >= 2 && setOpen(true)}
          placeholder={placeholder || t('search.placeholder', 'ابحث عن منتجات...')}
          className="flex-1 bg-transparent text-sm text-gray-800 dark:text-gray-100 placeholder-gray-400 outline-none"
          aria-label={t('search.label', 'بحث')}
          autoComplete="off"
        />
        {loading && (
          <div className="h-4 w-4 animate-spin rounded-full border-2 border-green-500 border-t-transparent shrink-0" />
        )}
        {query && !loading && (
          <button onClick={clearQuery} className="p-0.5 hover:text-gray-600 text-gray-400 shrink-0">
            <XMarkIcon className="h-4 w-4" />
          </button>
        )}
        <button
          onClick={() => handleSubmit()}
          className="px-3 py-1 bg-green-500 hover:bg-green-600 text-white text-sm rounded-lg transition-colors shrink-0"
        >
          {t('search.search', 'بحث')}
        </button>
      </div>

      {/* Suggestions dropdown */}
      {open && suggestions.length > 0 && (
        <ul
          className="absolute top-full mt-1 w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl shadow-lg z-50 overflow-hidden"
          role="listbox"
        >
          {suggestions.map((hit, i) => (
            <li
              key={hit.objectID}
              role="option"
              aria-selected={i === activeIndex}
              onMouseDown={() => handleSubmit(hit.name)}
              className={`flex items-center gap-3 px-4 py-2.5 cursor-pointer text-sm ${
                i === activeIndex
                  ? 'bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-300'
                  : 'text-gray-700 dark:text-gray-200 hover:bg-gray-50 dark:hover:bg-gray-700'
              }`}
            >
              <MagnifyingGlassIcon className="h-4 w-4 text-gray-400 shrink-0" />
              <span
                dangerouslySetInnerHTML={{
                  __html: hit._highlightResult?.name?.value || hit.name
                }}
              />
              {hit.category && (
                <span className="text-xs text-gray-400 ml-auto shrink-0">{hit.category}</span>
              )}
            </li>
          ))}
        </ul>
      )}
    </div>
  )
})

export default SearchBar

import { useState } from 'react'
import { useAuthStore } from '@/store/authStore'
import { mfaService } from '@/services/authServices'
import { ShieldCheckIcon, XMarkIcon, CheckIcon, QrCodeIcon, EnvelopeIcon } from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'

const MFASetup = ({ isOpen, onClose }) => {
  const { refreshProfile } = useAuthStore()
  const [step, setStep] = useState(1) // 1: method selection, 2: setup, 3: complete
  const [method, setMethod] = useState(null) // 'email' or 'totp'
  const [loading, setLoading] = useState(false)
  const [totpData, setTotpData] = useState(null)
  const [backupCodes, setBackupCodes] = useState(null)
  const [verificationCode, setVerificationCode] = useState('')

  const handleEnableEmail = async () => {
    try {
      setLoading(true)
      const result = await mfaService.enableWithEmail()

      if (result.success) {
        setMethod('email')
        setStep(3)
        await refreshProfile()
        toast.success('Email MFA enabled successfully!')
      } else {
        toast.error(result.error || 'Failed to enable MFA')
      }
    } catch (error) {
      toast.error('Failed to enable MFA')
    } finally {
      setLoading(false)
    }
  }

  const handleEnableTOTP = async () => {
    try {
      setLoading(true)
      // Generate TOTP secret but DON'T enable MFA yet
      const result = await mfaService.generateTOTPSecret()

      if (result.success) {
        setMethod('totp')
        setTotpData(result)
        setStep(2) // Show QR code and verification
        // MFA is NOT enabled yet - will be enabled after verification
      } else {
        toast.error(result.error || 'Failed to generate TOTP secret')
      }
    } catch (error) {
      toast.error('Failed to generate TOTP secret')
    } finally {
      setLoading(false)
    }
  }

  const handleVerifyTOTP = async () => {
    if (!verificationCode || verificationCode.length !== 6) {
      toast.error('Please enter a 6-digit code')
      return
    }

    try {
      setLoading(true)
      // Verify the code against the generated secret
      const { success, error } = await mfaService.verifyCode(verificationCode)

      if (success) {
        // NOW enable MFA in the database
        const enableResult = await mfaService.enableWithTOTP(totpData.secret)

        if (enableResult.success) {
          setStep(3)
          setBackupCodes(enableResult.backupCodes)
          await refreshProfile()
          toast.success('TOTP verified and MFA enabled!')
        } else {
          toast.error(enableResult.error || 'Failed to enable MFA')
        }
      } else {
        toast.error(error || 'Invalid code')
      }
    } catch (error) {
      toast.error('Failed to verify code')
    } finally {
      setLoading(false)
    }
  }

  const handleComplete = () => {
    setStep(1)
    setMethod(null)
    setTotpData(null)
    setBackupCodes(null)
    setVerificationCode('')
    onClose()
  }

  const downloadBackupCodes = () => {
    const content = `
Qotoof - Backup Codes
==========================
Save these codes in a safe place. Each code can only be used once.

${backupCodes.map((code, i) => `${i + 1}. ${code}`).join('\n')}

Generated: ${new Date().toLocaleString()}
    `.trim()

    const blob = new Blob([content], { type: 'text/plain' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'qotoof-backup-codes.txt'
    a.click()
    URL.revokeObjectURL(url)
  }

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl max-w-md w-full p-6 relative">
        {/* Close button */}
        <button
          onClick={handleComplete}
          className="absolute top-4 right-4 text-gray-400 hover:text-gray-600"
        >
          <XMarkIcon className="w-6 h-6" />
        </button>

        {/* Header */}
        <div className="text-center mb-6">
          <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <ShieldCheckIcon className="w-8 h-8 text-green-600" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900">Enable Two-Factor Authentication</h2>
          <p className="text-gray-600 mt-2">Add an extra layer of security to your account</p>
        </div>

        {/* Step 1: Method Selection */}
        {step === 1 && (
          <div className="space-y-4">
            <div className="grid grid-cols-1 gap-4">
              {/* Email Method */}
              <button
                onClick={handleEnableEmail}
                disabled={loading}
                className="flex items-center gap-4 p-4 border-2 border-gray-200 rounded-xl hover:border-green-500 hover:bg-green-50 transition-all disabled:opacity-50"
              >
                <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center flex-shrink-0">
                  <EnvelopeIcon className="w-6 h-6 text-blue-600" />
                </div>
                <div className="text-left flex-1">
                  <h3 className="font-semibold text-gray-900">Email Verification</h3>
                  <p className="text-sm text-gray-600">Receive a 6-digit code via email</p>
                </div>
              </button>

              {/* TOTP Method */}
              <button
                onClick={handleEnableTOTP}
                disabled={loading}
                className="flex items-center gap-4 p-4 border-2 border-gray-200 rounded-xl hover:border-green-500 hover:bg-green-50 transition-all disabled:opacity-50"
              >
                <div className="w-12 h-12 bg-purple-100 rounded-lg flex items-center justify-center flex-shrink-0">
                  <QrCodeIcon className="w-6 h-6 text-purple-600" />
                </div>
                <div className="text-left flex-1">
                  <h3 className="font-semibold text-gray-900">Authenticator App</h3>
                  <p className="text-sm text-gray-600">Use Google Authenticator, Authy, etc.</p>
                </div>
              </button>
            </div>

            <p className="text-xs text-gray-500 text-center mt-4">
              You can disable 2FA at any time from your security settings
            </p>
          </div>
        )}

        {/* Step 2: TOTP Setup */}
        {step === 2 && totpData && (
          <div className="space-y-6">
            {/* QR Code */}
            <div className="text-center">
              <p className="text-sm text-gray-600 mb-4">
                Scan this QR code with your authenticator app
              </p>
              <div className="bg-white p-4 rounded-xl border-2 border-gray-200 inline-block">
                <img
                  src={`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(totpData.qrCodeUrl)}`}
                  alt="QR Code"
                  className="w-48 h-48"
                />
              </div>
            </div>

            {/* Manual Entry */}
            <div className="bg-gray-50 p-4 rounded-xl">
              <p className="text-xs text-gray-600 mb-2">Manual entry key:</p>
              <code className="text-sm font-mono bg-white px-3 py-2 rounded block break-all">
                {totpData.secret}
              </code>
            </div>

            {/* Verification */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Enter the 6-digit code from your app
              </label>
              <input
                type="text"
                value={verificationCode}
                onChange={(e) => setVerificationCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                placeholder="000000"
                maxLength={6}
                className="input text-center text-2xl tracking-widest font-mono"
              />
              <button
                onClick={handleVerifyTOTP}
                disabled={loading || verificationCode.length !== 6}
                className="btn-primary w-full mt-3 disabled:opacity-50"
              >
                {loading ? 'Verifying...' : 'Verify Code'}
              </button>
            </div>
          </div>
        )}

        {/* Step 3: Complete */}
        {step === 3 && (
          <div className="space-y-6">
            {/* Success */}
            <div className="text-center">
              <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <CheckIcon className="w-8 h-8 text-green-600" />
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-2">
                Two-Factor Authentication Enabled!
              </h3>
              <p className="text-gray-600">
                Your account is now protected with {method === 'email' ? 'email' : 'authenticator app'} verification
              </p>
            </div>

            {/* Backup Codes */}
            {backupCodes && (
              <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4">
                <h4 className="font-semibold text-gray-900 mb-2">⚠️ Save Your Backup Codes</h4>
                <p className="text-sm text-gray-600 mb-3">
                  These codes can be used to access your account if you lose your authenticator app.
                  Store them in a safe place.
                </p>
                <div className="grid grid-cols-2 gap-2 mb-3">
                  {backupCodes.map((code, index) => (
                    <code key={index} className="text-sm font-mono bg-white px-2 py-1 rounded text-center">
                      {code}
                    </code>
                  ))}
                </div>
                <button
                  onClick={downloadBackupCodes}
                  className="btn-secondary w-full text-sm"
                >
                  📥 Download Backup Codes
                </button>
              </div>
            )}

            <button
              onClick={handleComplete}
              className="btn-primary w-full"
            >
              Done
            </button>
          </div>
        )}

        {/* Loading */}
        {loading && (
          <div className="absolute inset-0 bg-white bg-opacity-75 flex items-center justify-center rounded-2xl">
            <div className="text-center">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-green-600 mx-auto mb-3"></div>
              <p className="text-gray-600">Please wait...</p>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

export default MFASetup

import { Navigate, useLocation } from 'react-router-dom';
import { useAuthStore } from '@/store/authStore';
import { useEffect, useState } from 'react';
import LoadingSpinner from '@/components/ui/LoadingSpinner';

/**
 * مكون الحماية بناءً على الدور
 * @param {React.ReactNode} children - العناصر التي سيتم عرضها إذا كانت الحماية تسمح
 * @param {string} requiredRole - الدور المطلوب للوصول
 * @param {string[]} allowedRoles - الأدوار المسموح لها بالوصول (اختياري)
 * @param {boolean} redirectToDefault - إعادة التوجيه إلى المسار الافتراضي إذا لم يكن لدى المستخدم إذن
 */
export const ProtectedRoute = ({ children, requiredRole, allowedRoles, redirectToDefault = true }) => {
  const { profile, loading } = useAuthStore();
  const location = useLocation();
  const [hasPermission, setHasPermission] = useState(null);

  useEffect(() => {
    // التحقق من التحميل
    if (loading) {
      setHasPermission(null);
      return;
    }

    // التحقق من تسجيل الدخول
    if (!profile) {
      setHasPermission(false);
      return;
    }

    // التحقق من الدور
    if (requiredRole) {
      // إذا كان المستخدم لا يملك الدور المطلوب
      if (profile.role !== requiredRole) {
        setHasPermission(false);
        return;
      }
    }

    // التحقق من الأدوار المسموح بها
    if (allowedRoles) {
      if (!allowedRoles.includes(profile.role)) {
        setHasPermission(false);
        return;
      }
    }

    // إذا اجتاز جميع الشروط
    setHasPermission(true);
  }, [profile, loading, requiredRole, allowedRoles]);

  // أثناء التحقق
  if (hasPermission === null) {
    return <LoadingSpinner />;
  }

  // إذا لم يكن مسجلاً أو ليس لديه إذن
  if (!hasPermission) {
    if (redirectToDefault) {
      // إعادة التوجيه إلى المسار الافتراضي بناءً على الدور
      const redirectPath = useAuthStore.getState().getRedirectPath(profile?.role || null);
      return <Navigate to={redirectPath} state={{ from: location }} replace />;
    } else {
      // إعادة التوجيه إلى صفحة تسجيل الدخول
      return <Navigate to="/auth/login" state={{ from: location }} replace />;
    }
  }

  // إذا كان لديه إذن، عرض المحتوى
  return children;
};

/**
 * مكون للتحقق من المصادقة فقط (بدون التحقق من الدور)
 * @param {React.ReactNode} children - العناصر التي سيتم عرضها إذا كانت الحماية تسمح
 */
export const AuthenticatedRoute = ({ children }) => {
  const { profile, loading } = useAuthStore();
  const location = useLocation();

  if (loading) {
    return <LoadingSpinner />;
  }

  if (!profile) {
    return <Navigate to="/auth/login" state={{ from: location }} replace />;
  }

  return children;
};

/**
 * مكون للتحقق من عدم تسجيل الدخول (لصفحات مثل تسجيل الدخول)
 * @param {React.ReactNode} children - العناصر التي سيتم عرضها إذا كانت الحماية تسمح
 */
export const UnauthenticatedRoute = ({ children }) => {
  const { profile, loading } = useAuthStore();
  const location = useLocation();

  if (loading) {
    return <LoadingSpinner />;
  }

  if (profile) {
    // إذا كان مسجلاً، أعد توجيهه إلى لوحة التحكم الافتراضية
    const redirectPath = useAuthStore.getState().getRedirectPath(profile.role);
    return <Navigate to={redirectPath} replace />;
  }

  return children;
};

import { useState, useEffect } from 'react'
import { useAuthStore } from '@/store/authStore'
import { sessionService } from '@/services/vendorSecurity'
import {
  ComputerDesktopIcon,
  DevicePhoneMobileIcon,
  XMarkIcon,
  TrashIcon,
  ExclamationTriangleIcon
} from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'
import { logger } from '@/utils/logger'

const SessionManager = ({ isOpen, onClose }) => {
  const { revokeSession, revokeAllOtherSessions, signOut } = useAuthStore()
  const [sessions, setSessions] = useState([])
  const [loading, setLoading] = useState(true)
  const [revoking, setRevoking] = useState(null)

  useEffect(() => {
    if (isOpen) {
      loadSessions()
    }
  }, [isOpen])

  const loadSessions = async () => {
    try {
      setLoading(true)
      const data = await sessionService.getActiveSessions()
      setSessions(data)
    } catch (error) {
      logger.error('Load sessions error:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleRevokeSession = async (sessionId) => {
    try {
      setRevoking(sessionId)
      const result = await revokeSession(sessionId)

      if (result.success) {
        toast.success('Session revoked')
        await loadSessions()
      } else {
        toast.error(result.error || 'Failed to revoke session')
      }
    } catch (error) {
      toast.error('Failed to revoke session')
    } finally {
      setRevoking(null)
    }
  }

  const handleRevokeAll = async () => {
    if (!confirm('Are you sure you want to sign out all other devices?')) {
      return
    }

    try {
      const result = await revokeAllOtherSessions()

      if (result.success) {
        toast.success('All other sessions revoked')
        await loadSessions()
      } else {
        toast.error(result.error || 'Failed to revoke sessions')
      }
    } catch (error) {
      toast.error('Failed to revoke sessions')
    }
  }

  const getDeviceIcon = (deviceInfo) => {
    const deviceType = deviceInfo?.deviceType || 'desktop'

    switch (deviceType) {
      case 'mobile':
        return <DevicePhoneMobileIcon className="w-6 h-6" />
      case 'tablet':
        return <DevicePhoneMobileIcon className="w-6 h-6" />
      default:
        return <ComputerDesktopIcon className="w-6 h-6" />
    }
  }

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl max-w-2xl w-full max-h-[80vh] flex flex-col">
        {/* Header */}
        <div className="p-6 border-b border-gray-200">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-2xl font-bold text-gray-900">Active Sessions</h2>
              <p className="text-sm text-gray-600 mt-1">
                Manage your active sessions across devices
              </p>
            </div>
            <button
              onClick={onClose}
              className="text-gray-400 hover:text-gray-600"
            >
              <XMarkIcon className="w-6 h-6" />
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {loading ? (
            <div className="text-center py-12">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-green-600 mx-auto mb-4"></div>
              <p className="text-gray-600">Loading sessions...</p>
            </div>
          ) : sessions.length === 0 ? (
            <div className="text-center py-12">
              <ComputerDesktopIcon className="w-16 h-16 text-gray-300 mx-auto mb-4" />
              <p className="text-gray-600">No active sessions found</p>
            </div>
          ) : (
            <div className="space-y-4">
              {/* Current Session */}
              {sessions.filter(s => s.is_current).map(session => (
                <div
                  key={session.id}
                  className="p-4 bg-green-50 border-2 border-green-200 rounded-xl"
                >
                  <div className="flex items-start gap-4">
                    <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center flex-shrink-0">
                      {getDeviceIcon(session.device_info)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="font-semibold text-gray-900">
                          {session.device_info?.browser || 'Unknown Browser'}
                        </span>
                        <span className="px-2 py-0.5 bg-green-100 text-green-800 text-xs font-medium rounded-full">
                          Current Session
                        </span>
                      </div>
                      <p className="text-sm text-gray-600">
                        {session.device_info?.os || 'Unknown OS'} • {session.device_info?.deviceType || 'Unknown Device'}
                      </p>
                      <div className="flex items-center gap-4 mt-2 text-xs text-gray-500">
                        <span>Last active: {formatLastActive(session.last_active)}</span>
                        <span>Expires: {formatExpires(session.expires_at)}</span>
                      </div>
                    </div>
                  </div>
                </div>
              ))}

              {/* Other Sessions */}
              {sessions.filter(s => !s.is_current).map(session => (
                <div
                  key={session.id}
                  className="p-4 bg-gray-50 border border-gray-200 rounded-xl hover:bg-gray-100 transition-colors"
                >
                  <div className="flex items-start gap-4">
                    <div className="w-12 h-12 bg-gray-200 rounded-lg flex items-center justify-center flex-shrink-0">
                      {getDeviceIcon(session.device_info)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-1">
                        <span className="font-semibold text-gray-900">
                          {session.device_info?.browser || 'Unknown Browser'}
                        </span>
                        <button
                          onClick={() => handleRevokeSession(session.id)}
                          disabled={revoking === session.id}
                          className="text-red-600 hover:text-red-700 disabled:opacity-50"
                        >
                          {revoking === session.id ? (
                            <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-red-600"></div>
                          ) : (
                            <TrashIcon className="w-5 h-5" />
                          )}
                        </button>
                      </div>
                      <p className="text-sm text-gray-600">
                        {session.device_info?.os || 'Unknown OS'} • {session.device_info?.deviceType || 'Unknown Device'}
                      </p>
                      <div className="flex items-center gap-4 mt-2 text-xs text-gray-500">
                        <span>Last active: {formatLastActive(session.last_active)}</span>
                        <span>Created: {formatDate(session.created_at)}</span>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-gray-200 space-y-3">
          {/* Warning */}
          {sessions.length > 3 && (
            <div className="flex items-start gap-3 p-4 bg-yellow-50 border border-yellow-200 rounded-lg">
              <ExclamationTriangleIcon className="w-5 h-5 text-yellow-600 flex-shrink-0 mt-0.5" />
              <div className="text-sm">
                <p className="font-medium text-yellow-900">Too many active sessions?</p>
                <p className="text-yellow-700">
                  If you don't recognize some of these sessions, revoke all other sessions immediately.
                </p>
              </div>
            </div>
          )}

          {/* Actions */}
          <div className="flex gap-3">
            <button
              onClick={handleRevokeAll}
              disabled={sessions.length <= 1}
              className="btn-secondary flex-1 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Sign Out All Other Devices
            </button>
            <button
              onClick={onClose}
              className="btn-primary flex-1"
            >
              Done
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

// Helper functions
function formatLastActive(timestamp) {
  if (!timestamp) return 'Unknown'
  const date = new Date(timestamp)
  const now = new Date()
  const diffMs = now - date
  const diffMins = Math.floor(diffMs / 60000)
  const diffHours = Math.floor(diffMs / 3600000)
  const diffDays = Math.floor(diffMs / 86400000)

  if (diffMins < 1) return 'Just now'
  if (diffMins < 60) return `${diffMins}m ago`
  if (diffHours < 24) return `${diffHours}h ago`
  if (diffDays < 7) return `${diffDays}d ago`
  return date.toLocaleDateString()
}

function formatExpires(timestamp) {
  if (!timestamp) return 'Unknown'
  const date = new Date(timestamp)
  return date.toLocaleDateString()
}

function formatDate(timestamp) {
  if (!timestamp) return 'Unknown'
  const date = new Date(timestamp)
  return date.toLocaleDateString()
}

export default SessionManager

// Enhanced DeliveryComplete component with mandatory photo, signature, and condition check
import { useState, useRef, useEffect } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { useAuthStore } from '@/store/authStore'
import { Card, LoadingSpinner } from '@/components/ui'
import { supabase } from '@/services/supabase'
import { CameraIcon, CheckCircleIcon, ArrowLeftIcon } from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'
import { logger } from '@/utils/logger'

const CONDITION_OPTIONS = [
  { value: 'excellent', label: 'Excellent', emoji: '✨', color: 'green' },
  { value: 'good', label: 'Good', emoji: '👍', color: 'blue' },
  { value: 'fair', label: 'Fair', emoji: '⚠️', color: 'yellow' },
  { value: 'damaged', label: 'Damaged', emoji: '❌', color: 'red' }
]

const DeliveryComplete = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  useAuthStore()
  const [loading, setLoading] = useState(true)
  const [submitting, setSubmitting] = useState(false)
  const [delivery, setDelivery] = useState(null)

  // Form state
  const [_deliveryPhoto, setDeliveryPhoto] = useState(null)
  const [deliveryPhotoUrl, setDeliveryPhotoUrl] = useState(null)
  const [buyerSignature, setBuyerSignature] = useState(null)
  const [buyerSignatureUrl] = useState(null)
  const [deliveryCondition, setDeliveryCondition] = useState('')
  const [buyerName, setBuyerName] = useState('')
  const [deliveryNotes, setDeliveryNotes] = useState('')
  const [checklist, setChecklist] = useState({
    buyer_confirmed_receipt: false,
    buyer_reported_issues: false,
    delivery_issues: ''
  })

  const signatureCanvasRef = useRef(null)
  const fileInputRef = useRef(null)

  useEffect(() => {
    loadDeliveryDetails()
  }, [id])

  const loadDeliveryDetails = async () => {
    try {
      const { data, error } = await supabase
        .from('deliveries')
        .select(`
          *,
          order:orders(*)
        `)
        .eq('id', id)
        .single()

      if (error) throw error
      setDelivery(data)
    } catch (error) {
      logger.error('Error loading delivery:', error)
      toast.error('Failed to load delivery details')
    } finally {
      setLoading(false)
    }
  }

  const handlePhotoUpload = async (e) => {
    const file = e.target.files[0]
    if (!file) return

    if (file.size > 10 * 1024 * 1024) {
      toast.error('Photo size must be less than 10MB')
      return
    }

    try {
      const fileExt = file.name.split('.').pop()
      const fileName = `delivery-proofs/${id}_${Date.now()}.${fileExt}`

      const { error } = await supabase.storage
        .from('delivery-proofs')
        .upload(fileName, file, {
          cacheControl: '3600',
          upsert: false
        })

      if (error) throw error

      const { data: urlData } = supabase.storage
        .from('delivery-proofs')
        .getPublicUrl(fileName)

      setDeliveryPhoto(file)
      setDeliveryPhotoUrl(urlData.publicUrl)
      toast.success('✅ Delivery photo uploaded')
    } catch (error) {
      logger.error('Upload error:', error)
      toast.error('Failed to upload photo')
    }
  }

  const _captureSignature = () => {
    // Simple signature capture using canvas
    const canvas = signatureCanvasRef.current
    if (!canvas) return

    const ctx = canvas.getContext('2d')
    let isDrawing = false
    let lastX = 0
    let lastY = 0

    const startDrawing = (e) => {
      isDrawing = true
      const rect = canvas.getBoundingClientRect()
      lastX = e.clientX - rect.left
      lastY = e.clientY - rect.top
    }

    const draw = (e) => {
      if (!isDrawing) return
      const rect = canvas.getBoundingClientRect()
      const x = e.clientX - rect.left
      const y = e.clientY - rect.top

      ctx.beginPath()
      ctx.moveTo(lastX, lastY)
      ctx.lineTo(x, y)
      ctx.strokeStyle = '#000'
      ctx.lineWidth = 2
      ctx.stroke()

      lastX = x
      lastY = y
    }

    const stopDrawing = () => {
      isDrawing = false
    }

    canvas.addEventListener('mousedown', startDrawing)
    canvas.addEventListener('mousemove', draw)
    canvas.addEventListener('mouseup', stopDrawing)
    canvas.addEventListener('mouseout', stopDrawing)

    // Touch events for mobile
    canvas.addEventListener('touchstart', (e) => {
      e.preventDefault()
      const touch = e.touches[0]
      const mouseEvent = new MouseEvent('mousedown', {
        clientX: touch.clientX,
        clientY: touch.clientY
      })
      canvas.dispatchEvent(mouseEvent)
    })

    canvas.addEventListener('touchmove', (e) => {
      e.preventDefault()
      const touch = e.touches[0]
      const mouseEvent = new MouseEvent('mousemove', {
        clientX: touch.clientX,
        clientY: touch.clientY
      })
      canvas.dispatchEvent(mouseEvent)
    })

    canvas.addEventListener('touchend', (e) => {
      e.preventDefault()
      const mouseEvent = new MouseEvent('mouseup')
      canvas.dispatchEvent(mouseEvent)
    })
  }

  const saveSignature = () => {
    const canvas = signatureCanvasRef.current
    if (!canvas) return

    const dataUrl = canvas.toDataURL('image/png')
    setBuyerSignature(dataUrl)
    toast.success('✅ Signature captured')
  }

  const clearSignature = () => {
    const canvas = signatureCanvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    ctx.clearRect(0, 0, canvas.width, canvas.height)
    setBuyerSignature(null)
  }

  const handleSubmit = async () => {
    // Validation
    if (!deliveryPhotoUrl) {
      toast.error('❌ Delivery photo is mandatory')
      return
    }

    if (!deliveryCondition) {
      toast.error('❌ Please select delivery condition')
      return
    }

    if (!buyerName.trim()) {
      toast.error('❌ Please enter recipient name')
      return
    }

    setSubmitting(true)

    try {
      // Upload signature if exists
      let signatureUrl = buyerSignatureUrl
      if (buyerSignature) {
        const signatureBlob = await fetch(buyerSignature).then(r => r.blob())
        const signatureFile = new File([signatureBlob], `signature_${Date.now()}.png`, { type: 'image/png' })

        const { data: sigData } = await supabase.storage
          .from('signatures')
          .upload(`signatures/${id}_${Date.now()}.png`, signatureFile)

        if (sigData) {
          const { data: urlData } = supabase.storage
            .from('signatures')
            .getPublicUrl(sigData.path)
          signatureUrl = urlData.publicUrl
        }
      }

      // Update delivery
      const { error: updateError } = await supabase
        .from('deliveries')
        .update({
          status: 'delivered',
          delivery_photo_url: deliveryPhotoUrl,
          buyer_signature_url: signatureUrl,
          buyer_name_received: buyerName,
          delivery_condition: deliveryCondition,
          driver_notes: deliveryNotes,
          delivered_at: new Date().toISOString()
        })
        .eq('id', id)

      if (updateError) throw updateError

      // Create checklist record
      if (checklist.buyer_confirmed_receipt || checklist.buyer_reported_issues) {
        await supabase
          .from('delivery_checklist')
          .insert({
            delivery_id: id,
            buyer_confirmed_receipt: checklist.buyer_confirmed_receipt,
            buyer_reported_issues: checklist.buyer_reported_issues,
            delivery_issues: checklist.delivery_issues
          })
      }

      toast.success('🎉 Delivery completed successfully!')
      navigate('/driver/dashboard')
    } catch (error) {
      logger.error('Submit error:', error)
      toast.error(error.message || 'Failed to complete delivery')
    } finally {
      setSubmitting(false)
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  if (!delivery) {
    return (
      <div className="text-center py-16">
        <p className="text-gray-500">Delivery not found</p>
      </div>
    )
  }

  return (
    <div className="max-w-2xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="flex items-center gap-3 mb-6">
        <button onClick={() => navigate(-1)} className="p-2 hover:bg-gray-100 rounded-lg">
          <ArrowLeftIcon className="w-5 h-5" />
        </button>
        <h1 className="text-2xl font-bold text-gray-900">Complete Delivery</h1>
      </div>

      {/* Special Instructions Alert */}
      {delivery?.special_instructions && (
        <Card className="p-4 mb-6 bg-yellow-50 border-yellow-200">
          <h3 className="font-semibold text-yellow-900 mb-2">⚠️ Special Instructions:</h3>
          <p className="text-sm text-yellow-800">{delivery.special_instructions}</p>
        </Card>
      )}

      {/* Fragile Items Alert */}
      {delivery?.is_fragile && (
        <Card className="p-4 mb-6 bg-red-50 border-red-200">
          <h3 className="font-semibold text-red-900 mb-2">📦 Fragile Items!</h3>
          <p className="text-sm text-red-800">Handle with care. Take extra precautions during delivery.</p>
        </Card>
      )}

      {/* Step 1: Delivery Photo (MANDATORY) */}
      <Card className="p-6 mb-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
          <CameraIcon className="w-5 h-5" />
          Delivery Photo <span className="text-red-500">*</span>
        </h2>

        {deliveryPhotoUrl ? (
          <div className="space-y-3">
            <img src={deliveryPhotoUrl} alt="Delivery proof" className="w-full rounded-lg" />
            <button
              onClick={() => { setDeliveryPhoto(null); setDeliveryPhotoUrl(null) }}
              className="text-sm text-red-600 hover:underline"
            >
              Remove and retake
            </button>
          </div>
        ) : (
          <div>
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              capture="environment"
              onChange={handlePhotoUpload}
              className="hidden"
            />
            <button
              onClick={() => fileInputRef.current?.click()}
              className="w-full p-8 border-2 border-dashed border-gray-300 rounded-lg hover:border-green-500 hover:bg-green-50 transition-colors"
            >
              <CameraIcon className="w-12 h-12 mx-auto text-gray-400 mb-3" />
              <p className="text-sm font-medium text-gray-700">Take Delivery Photo</p>
              <p className="text-xs text-gray-500 mt-1">Photo is mandatory to complete delivery</p>
            </button>
          </div>
        )}
      </Card>

      {/* Step 2: Product Condition */}
      <Card className="p-6 mb-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Product Condition at Delivery</h2>
        <div className="grid grid-cols-2 gap-3">
          {CONDITION_OPTIONS.map((option) => (
            <button
              key={option.value}
              onClick={() => setDeliveryCondition(option.value)}
              className={`p-4 rounded-lg border-2 transition-colors ${
                deliveryCondition === option.value
                  ? `border-${option.color}-500 bg-${option.color}-50`
                  : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              <span className="text-2xl">{option.emoji}</span>
              <p className="text-sm font-medium mt-2">{option.label}</p>
            </button>
          ))}
        </div>
      </Card>

      {/* Step 3: Recipient Name */}
      <Card className="p-6 mb-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Recipient Information</h2>
        <input
          type="text"
          placeholder="Name of person who received the delivery"
          value={buyerName}
          onChange={(e) => setBuyerName(e.target.value)}
          className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
        />
      </Card>

      {/* Step 4: Buyer Signature (Optional but recommended) */}
      <Card className="p-6 mb-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Buyer Signature (Optional)</h2>
        <canvas
          ref={signatureCanvasRef}
          width={500}
          height={200}
          className="w-full border-2 border-gray-300 rounded-lg bg-white touch-none"
          style={{ cursor: 'crosshair' }}
        />
        <div className="flex gap-3 mt-3">
          <button
            onClick={saveSignature}
            className="flex-1 btn-primary"
          >
            Save Signature
          </button>
          <button
            onClick={clearSignature}
            className="flex-1 btn-outline"
          >
            Clear
          </button>
        </div>
      </Card>

      {/* Step 5: Delivery Checklist */}
      <Card className="p-6 mb-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Delivery Checklist</h2>
        <div className="space-y-3">
          <label className="flex items-center gap-3">
            <input
              type="checkbox"
              checked={checklist.buyer_confirmed_receipt}
              onChange={(e) => setChecklist({ ...checklist, buyer_confirmed_receipt: e.target.checked })}
              className="w-5 h-5 text-green-600 rounded"
            />
            <span className="text-sm">Buyer confirmed receipt of items</span>
          </label>
          <label className="flex items-center gap-3">
            <input
              type="checkbox"
              checked={checklist.buyer_reported_issues}
              onChange={(e) => setChecklist({ ...checklist, buyer_reported_issues: e.target.checked })}
              className="w-5 h-5 text-red-600 rounded"
            />
            <span className="text-sm">Buyer reported any issues</span>
          </label>
          {checklist.buyer_reported_issues && (
            <textarea
              placeholder="Describe the issues reported..."
              value={checklist.delivery_issues}
              onChange={(e) => setChecklist({ ...checklist, delivery_issues: e.target.value })}
              className="w-full px-4 py-3 border border-gray-300 rounded-lg mt-2"
              rows={3}
            />
          )}
        </div>
      </Card>

      {/* Step 6: Additional Notes */}
      <Card className="p-6 mb-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Additional Notes (Optional)</h2>
        <textarea
          placeholder="Any additional notes about the delivery..."
          value={deliveryNotes}
          onChange={(e) => setDeliveryNotes(e.target.value)}
          className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
          rows={3}
        />
      </Card>

      {/* Submit Button */}
      <button
        onClick={handleSubmit}
        disabled={submitting || !deliveryPhotoUrl || !deliveryCondition || !buyerName}
        className="w-full btn-primary py-4 text-lg font-semibold disabled:opacity-50 disabled:cursor-not-allowed"
      >
        {submitting ? (
          <LoadingSpinner size="sm" />
        ) : (
          <>
            <CheckCircleIcon className="w-5 h-5 inline mr-2" />
            Complete Delivery
          </>
        )}
      </button>
    </div>
  )
}

export default DeliveryComplete

// DriverVerification component - Handles driver license and insurance upload
import { useState, useEffect } from 'react'
import { useAuthStore } from '@/store/authStore'
import { Card, LoadingSpinner } from '@/components/ui'
import { DocumentIcon, CheckCircleIcon, XCircleIcon, ClockIcon, ArrowUpTrayIcon } from '@heroicons/react/24/outline'
import { supabase } from '@/services/supabase'
import toast from 'react-hot-toast'
import { logger } from '@/utils/logger'

const DOCUMENT_TYPES = [
  {
    type: 'driver_license',
    label: "Driver's License",
    icon: '🪪',
    required: true,
    description: 'Valid driver license (front and back)',
    fields: ['document_number', 'issue_date', 'expiry_date']
  },
  {
    type: 'vehicle_insurance',
    label: 'Vehicle Insurance',
    icon: '🛡️',
    required: true,
    description: 'Current vehicle insurance certificate',
    fields: ['document_number', 'expiry_date']
  },
  {
    type: 'vehicle_registration',
    label: 'Vehicle Registration',
    icon: '🚗',
    required: false,
    description: 'Vehicle registration document',
    fields: ['document_number']
  }
]

const DriverVerification = () => {
  const { user, profile } = useAuthStore()
  const [documents, setDocuments] = useState([])
  const [loading, setLoading] = useState(true)
  const [uploading, setUploading] = useState(false)
  const [selectedDoc, setSelectedDoc] = useState(null)
  const [formData, setFormData] = useState({
    document_number: '',
    issue_date: '',
    expiry_date: ''
  })

  useEffect(() => {
    if (user) loadDocuments()
  }, [user])

  const loadDocuments = async () => {
    try {
      const { data, error } = await supabase
        .from('driver_verification_documents')
        .select('*')
        .eq('driver_id', user.id)
        .order('created_at', { ascending: false })

      if (error) throw error
      setDocuments(data || [])
    } catch (error) {
      logger.error('Error loading documents:', error)
      toast.error('Failed to load documents')
    } finally {
      setLoading(false)
    }
  }

  const handleFileUpload = async (e, docType) => {
    const file = e.target.files[0]
    if (!file) return

    // Validate file
    if (file.size > 5 * 1024 * 1024) {
      toast.error('File size must be less than 5MB')
      return
    }

    if (!file.type.startsWith('image/')) {
      toast.error('Only image files are allowed')
      return
    }

    setUploading(true)
    setSelectedDoc(docType)

    try {
      // Upload to storage
      const fileExt = file.name.split('.').pop()
      const fileName = `${user.id}/${docType}_${Date.now()}.${fileExt}`
      const { data: uploadData, error: uploadError } = await supabase.storage
        .from('driver-documents')
        .upload(fileName, file, {
          cacheControl: '3600',
          upsert: false
        })

      if (uploadError) throw uploadError

      // Get public URL
      const { data: urlData } = supabase.storage
        .from('driver-documents')
        .getPublicUrl(fileName)

      // Create document record
      const { error: dbError } = await supabase
        .from('driver_verification_documents')
        .insert({
          driver_id: user.id,
          document_type: docType,
          document_url: urlData.publicUrl,
          document_number: formData.document_number || null,
          issue_date: formData.issue_date || null,
          expiry_date: formData.expiry_date || null,
          status: 'pending'
        })

      if (dbError) throw dbError

      // Notify all admins about the new document submission
      const { data: admins } = await supabase
        .from('profiles')
        .select('id, first_name')
        .eq('role', 'admin')

      if (admins && admins.length > 0) {
        const adminNotifications = admins.map(admin => ({
          user_id: admin.id,
          title: '📄 Driver Document Submitted for Review',
          message: `${profile?.first_name || 'A driver'} has uploaded ${docType.replace('_', ' ')} for verification. Please review.`,
          type: 'driver_verification',
          data: JSON.stringify({
            driver_id: user.id,
            document_type: docType,
            driver_name: `${profile?.first_name || ''} ${profile?.last_name || ''}`
          })
        }))

        const { error: notifError } = await supabase
          .from('notifications')
          .insert(adminNotifications)

        if (notifError) {
          logger.error('Failed to notify admins:', notifError)
        }
      }

      toast.success('Document uploaded successfully. Waiting for admin review.')
      loadDocuments()
      setFormData({ document_number: '', issue_date: '', expiry_date: '' })
    } catch (error) {
      logger.error('Upload error:', error)
      toast.error('Failed to upload document')
    } finally {
      setUploading(false)
      setSelectedDoc(null)
    }
  }

  const getStatusIcon = (status) => {
    switch (status) {
      case 'approved':
        return <CheckCircleIcon className="w-5 h-5 text-green-600" />
      case 'rejected':
        return <XCircleIcon className="w-5 h-5 text-red-600" />
      default:
        return <ClockIcon className="w-5 h-5 text-yellow-600" />
    }
  }

  const getStatusColor = (status) => {
    switch (status) {
      case 'approved':
        return 'bg-green-50 border-green-200'
      case 'rejected':
        return 'bg-red-50 border-red-200'
      default:
        return 'bg-yellow-50 border-yellow-200'
    }
  }

  const getDocumentStatus = (docType) => {
    const doc = documents.find(d => d.document_type === docType)
    return doc?.status || 'not_uploaded'
  }

  const isVerified = profile?.license_verified && profile?.insurance_verified

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Verification Status Banner */}
      <Card className={`p-6 border-2 ${isVerified ? 'bg-green-50 border-green-200' : 'bg-yellow-50 border-yellow-200'}`}>
        <div className="flex items-start gap-4">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center ${isVerified ? 'bg-green-100' : 'bg-yellow-100'}`}>
            {isVerified ? (
              <CheckCircleIcon className="w-7 h-7 text-green-600" />
            ) : (
              <ClockIcon className="w-7 h-7 text-yellow-600" />
            )}
          </div>
          <div className="flex-1">
            <h3 className={`text-lg font-semibold ${isVerified ? 'text-green-900' : 'text-yellow-900'}`}>
              {isVerified ? '✅ Verified Driver' : '⏳ Verification Pending'}
            </h3>
            <p className={`text-sm mt-1 ${isVerified ? 'text-green-700' : 'text-yellow-700'}`}>
              {isVerified
                ? 'All your documents are verified. You can accept deliveries.'
                : 'Please upload all required documents to start accepting deliveries.'}
            </p>
            {!isVerified && (
              <div className="mt-3 flex gap-2 text-xs">
                {!profile?.license_verified && (
                  <span className="px-2 py-1 bg-red-100 text-red-700 rounded">❌ License Required</span>
                )}
                {!profile?.insurance_verified && (
                  <span className="px-2 py-1 bg-red-100 text-red-700 rounded">❌ Insurance Required</span>
                )}
              </div>
            )}
          </div>
        </div>
      </Card>

      {/* Document Upload Cards */}
      {DOCUMENT_TYPES.map((docType) => {
        const status = getDocumentStatus(docType.type)
        const existingDoc = documents.find(d => d.document_type === docType.type)

        return (
          <Card key={docType.type} className="p-6">
            <div className="flex items-start justify-between mb-4">
              <div className="flex items-start gap-3">
                <span className="text-3xl">{docType.icon}</span>
                <div>
                  <h4 className="font-semibold text-gray-900 flex items-center gap-2">
                    {docType.label}
                    {docType.required && <span className="text-red-500 text-xs">*</span>}
                  </h4>
                  <p className="text-sm text-gray-500 mt-1">{docType.description}</p>
                </div>
              </div>
              {status !== 'not_uploaded' && getStatusIcon(status)}
            </div>

            {existingDoc && (
              <div className={`p-3 rounded-lg border mb-4 ${getStatusColor(status)}`}>
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium capitalize">{status}</p>
                    {existingDoc.admin_notes && (
                      <p className="text-xs text-gray-600 mt-1">Note: {existingDoc.admin_notes}</p>
                    )}
                    {existingDoc.expiry_date && (
                      <p className="text-xs text-gray-500 mt-1">
                        Expires: {new Date(existingDoc.expiry_date).toLocaleDateString()}
                      </p>
                    )}
                  </div>
                  <a
                    href={existingDoc.document_url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-sm text-green-600 hover:underline"
                  >
                    View Document
                  </a>
                </div>
              </div>
            )}

            {/* Upload Form */}
            {status === 'not_uploaded' || status === 'rejected' ? (
              <div className="space-y-3">
                {docType.fields.includes('document_number') && (
                  <input
                    type="text"
                    placeholder="Document Number"
                    value={formData.document_number}
                    onChange={(e) => setFormData({ ...formData, document_number: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  />
                )}

                {docType.fields.includes('issue_date') && (
                  <input
                    type="date"
                    placeholder="Issue Date"
                    value={formData.issue_date}
                    onChange={(e) => setFormData({ ...formData, issue_date: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  />
                )}

                {docType.fields.includes('expiry_date') && (
                  <input
                    type="date"
                    placeholder="Expiry Date"
                    value={formData.expiry_date}
                    onChange={(e) => setFormData({ ...formData, expiry_date: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  />
                )}

                <label className="flex items-center justify-center w-full p-4 border-2 border-dashed border-gray-300 rounded-lg cursor-pointer hover:border-green-500 hover:bg-green-50 transition-colors">
                  <div className="text-center">
                    <ArrowUpTrayIcon className="w-8 h-8 mx-auto text-gray-400 mb-2" />
                    <p className="text-sm text-gray-600">
                      {uploading && selectedDoc === docType.type ? 'Uploading...' : 'Click to upload image'}
                    </p>
                    <p className="text-xs text-gray-500 mt-1">PNG, JPG up to 5MB</p>
                  </div>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => handleFileUpload(e, docType.type)}
                    disabled={uploading}
                    className="hidden"
                  />
                </label>
              </div>
            ) : (
              <p className="text-sm text-gray-500 text-center py-4">
                {status === 'pending' ? '⏳ Waiting for admin review...' : '✅ Document verified'}
              </p>
            )}
          </Card>
        )
      })}

      {/* Important Notice */}
      <Card className="p-4 bg-blue-50 border-blue-200">
        <h4 className="font-semibold text-blue-900 mb-2">📋 Important Notes:</h4>
        <ul className="text-sm text-blue-800 space-y-1">
          <li>• Driver's License and Vehicle Insurance are <strong>mandatory</strong></li>
          <li>• You cannot accept deliveries until your documents are verified</li>
          <li>• Documents are reviewed by admin within 24-48 hours</li>
          <li>• You will receive a notification when your documents expire</li>
          <li>• Make sure document photos are clear and all details are visible</li>
        </ul>
      </Card>
    </div>
  )
}

