const DriverSelection = ({ selectedDriver, onChange, vendorLocation, deliveryAddress }) => {
  const [drivers, setDrivers] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  useEffect(() => {
    loadAvailableDrivers()
  }, [vendorLocation])

  const loadAvailableDrivers = async () => {
    setLoading(true)
    setError(null)
    try {
      // Get available drivers near the vendor location
      let query = supabase
        .from('profiles')
        .select('*')
        .eq('role', 'driver')
        .eq('is_available_for_delivery', true)

      // If vendor has location, filter by nearby drivers (within 50km)
      if (vendorLocation?.lat && vendorLocation?.lng) {
        // Note: For production, use PostGIS for proper distance calculation
        // This is a simplified version
        query = query.not('latitude', 'is', null).not('longitude', 'is', null)
      }

      const { data, error: queryError } = await query

      if (queryError) throw queryError
      setDrivers(data || [])
    } catch (err) {
      logger.error('Error loading drivers:', err)
      setError('Failed to load available drivers')
    } finally {
      setLoading(false)
    }
  }

  if (loading) {
    return (
      <div className="p-4 bg-gray-50 rounded-xl">
        <div className="flex items-center gap-3">
          <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-green-600"></div>
          <p className="text-sm text-gray-600">Loading available drivers...</p>
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="p-4 bg-red-50 border border-red-200 rounded-xl">
        <p className="text-sm text-red-600">{error}</p>
      </div>
    )
  }

  if (drivers.length === 0) {
    return null // Parent component will handle no drivers case
  }

  return (
    <div className="space-y-3">
      <h3 className="font-semibold text-gray-900 flex items-center gap-2">
        <TruckIcon className="w-5 h-5" />
        Select a Driver ({drivers.length} available)
      </h3>

      <div className="space-y-2 max-h-64 overflow-y-auto">
        {drivers.map((driver) => (
          <label
            key={driver.id}
            className={`flex items-center gap-3 p-4 border-2 rounded-xl cursor-pointer transition-all ${
              selectedDriver === driver.id
                ? 'border-green-500 bg-green-50'
                : 'border-gray-200 hover:border-gray-300'
            }`}
          >
            <input
              type="radio"
              name="driver"
              value={driver.id}
              checked={selectedDriver === driver.id}
              onChange={() => onChange(driver.id)}
              className="text-green-500"
            />
            <div className="w-10 h-10 bg-green-100 rounded-full flex items-center justify-center flex-shrink-0">
              <span className="text-green-600 font-semibold text-sm">
                {driver.first_name?.[0]}{driver.last_name?.[0]}
              </span>
            </div>
            <div className="flex-1 min-w-0">
              <p className="font-medium text-gray-900">
                {driver.first_name} {driver.last_name}
              </p>
              <div className="flex items-center gap-2 text-sm text-gray-500">
                <div className="flex items-center gap-0.5">
                  {[...Array(5)].map((_, i) => (
                    i < 4 ? (
                      <StarIconSolid key={i} className="w-3.5 h-3.5 text-yellow-400" />
                    ) : (
                      <StarIcon key={i} className="w-3.5 h-3.5 text-gray-300" />
                    )
                  ))}
                </div>
                <span>4.0</span>
                {driver.vehicle_type && (
                  <>
                    <span>•</span>
                    <span className="capitalize">{driver.vehicle_type}</span>
                  </>
                )}
              </div>
            </div>
            <div className="text-right">
              <span className="text-xs text-green-600 font-medium flex items-center gap-1">
                <CheckCircleIcon className="w-4 h-4" />
                Available
              </span>
            </div>
          </label>
        ))}
      </div>
    </div>
  )
}

