/**
 * Login.jsx - صفحة تسجيل الدخول
 * 
 * مسؤوليات:
 * 1. جمع بيانات المستخدم (email + password)
 * 2. التحقق من صحة البيانات
 * 3. إرسال طلب المصادقة إلى Supabase
 * 4. معالجة الأخطاء (خطأ في البيانات، حساب معطل، إلخ)
 * 5. إعادة التوجيه إلى الصفحة المناسبة حسب الدور
 */

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '@/services/supabase';
import toast from 'react-hot-toast';
import { z } from 'zod';
import { EyeIcon as Eye, EyeSlashIcon as EyeOff, EnvelopeIcon as Mail, LockClosedIcon as Lock } from '@heroicons/react/24/outline';

// === Zod Schema للتحقق من البيانات ===
const loginSchema = z.object({
  email: z.string().email('البريد الإلكتروني غير صحيح'),
  password: z.string().min(6, 'كلمة المرور يجب أن تكون 6 أحرف على الأقل'),
});

export default function Login() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    email: '',
    password: '',
  });
  const [errors, setErrors] = useState({});
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  // === معالجة التغيير في الحقول ===
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value,
    }));
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: '',
      }));
    }
  };

  // === معالجة الـ submit ===
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      loginSchema.parse(formData);
    } catch (error) {
      const fieldErrors = {};
      error.errors.forEach(err => {
        fieldErrors[err.path[0]] = err.message;
      });
      setErrors(fieldErrors);
      return;
    }

    setIsLoading(true);

    try {
      // === تسجيل الدخول عبر Supabase ===
      const { data, error } = await supabase.auth.signInWithPassword({
        email: formData.email,
        password: formData.password,
      });

      if (error) {
        if (error.message.includes('Invalid login credentials')) {
          toast.error('بريد إلكتروني أو كلمة مرور غير صحيحة');
        } else if (error.message.includes('Email not confirmed')) {
          toast.error('الرجاء تأكيد بريدك الإلكتروني أولاً');
          navigate('/verify-email', { state: { email: formData.email } });
          return;
        } else {
          toast.error(error.message || 'حدث خطأ في تسجيل الدخول');
        }
        return;
      }

      // === الحصول على بيانات المستخدم ===
      const { data: profile } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', data.user.id)
        .single();

      if (!profile) {
        toast.error('حدث خطأ في جلب بيانات المستخدم');
        return;
      }

      // === تسجيل النشاط في audit log ===
      await supabase.from('audit_logs').insert({
        user_id: data.user.id,
        action: 'LOGIN',
        details: { ip: 'detected-by-function' },
      });

      toast.success('تم تسجيل الدخول بنجاح');

      const roleRoutes = {
        admin: '/admin/dashboard',
        vendor: '/vendor/dashboard',
        driver: '/driver/dashboard',
        buyer: '/marketplace',
      };

      const redirectTo = roleRoutes[profile.role] || '/marketplace';
      navigate(redirectTo);

    } catch (error) {
      console.error('Login error:', error);
      toast.error('حدث خطأ غير متوقع');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 to-blue-50 flex items-center justify-center px-4">
      <div className="w-full max-w-md">
        {/* === Header === */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">قطوف</h1>
          <p className="text-gray-600">منصة بيع الخضار والفواكه بالجملة</p>
        </div>

        {/* === Login Form === */}
        <form
          onSubmit={handleSubmit}
          className="bg-white rounded-lg shadow-lg p-8 space-y-6"
        >
          {/* === Email Field === */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              البريد الإلكتروني
            </label>
            <div className="relative">
              <Mail className="absolute right-3 top-3 w-5 h-5 text-gray-400" />
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                placeholder="example@mail.com"
                className={`w-full pl-3 pr-10 py-2 border rounded-lg focus:outline-none focus:ring-2 ${
                  errors.email
                    ? 'border-red-500 focus:ring-red-500'
                    : 'border-gray-300 focus:ring-green-500'
                }`}
                disabled={isLoading}
              />
            </div>
            {errors.email && (
              <p className="text-red-500 text-sm mt-1">{errors.email}</p>
            )}
          </div>

          {/* === Password Field === */}
          <div>
            <div className="flex justify-between items-center mb-2">
              <label className="block text-sm font-medium text-gray-700">
                كلمة المرور
              </label>
              <a
                href="/forgot-password"
                className="text-sm text-green-600 hover:text-green-700"
              >
                هل نسيت كلمتك؟
              </a>
            </div>
            <div className="relative">
              <Lock className="absolute right-3 top-3 w-5 h-5 text-gray-400" />
              <input
                type={showPassword ? 'text' : 'password'}
                name="password"
                value={formData.password}
                onChange={handleChange}
                placeholder="أدخل كلمة المرور"
                className={`w-full pl-10 pr-10 py-2 border rounded-lg focus:outline-none focus:ring-2 ${
                  errors.password
                    ? 'border-red-500 focus:ring-red-500'
                    : 'border-gray-300 focus:ring-green-500'
                }`}
                disabled={isLoading}
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute left-3 top-3 text-gray-400 hover:text-gray-600"
              >
                {showPassword ? (
                  <EyeOff className="w-5 h-5" />
                ) : (
                  <Eye className="w-5 h-5" />
                )}
              </button>
            </div>
            {errors.password && (
              <p className="text-red-500 text-sm mt-1">{errors.password}</p>
            )}
          </div>

          {/* === Submit Button === */}
          <button
            type="submit"
            disabled={isLoading}
            className="w-full bg-green-600 hover:bg-green-700 disabled:bg-gray-400 text-white font-medium py-2 rounded-lg transition duration-200 flex items-center justify-center gap-2"
          >
            {isLoading ? 'جاري تسجيل الدخول...' : 'تسجيل الدخول'}
          </button>

          {/* === Divider === */}
          <div className="relative">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-gray-300"></div>
            </div>
            <div className="relative flex justify-center text-sm">
              <span className="px-2 bg-white text-gray-500">أو</span>
            </div>
          </div>

          {/* === Sign Up Link === */}
          <div className="text-center">
            <p className="text-gray-600">
              ليس لديك حساب؟{' '}
              <a
                href="/register"
                className="text-green-600 hover:text-green-700 font-medium"
              >
                اشترك الآن
              </a>
            </p>
          </div>
        </form>

        {/* === Footer === */}
        <div className="mt-8 text-center text-sm text-gray-600">
          <p>تسجيلك يعني موافقتك على</p>
          <div className="flex justify-center gap-4 mt-2">
            <a href="/privacy" className="hover:text-green-600">
              سياسة الخصوصية
            </a>
            <span>•</span>
            <a href="/terms" className="hover:text-green-600">
              شروط الخدمة
            </a>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useMutation, useQuery } from '@tanstack/react-query';
import { useTranslation } from 'react-i18next';
import Card from '../../../components/ui/Card';
import Button from '../../../components/ui/Button';
import Badge from '../../../components/ui/Badge';
import Modal from '../../../components/ui/Modal';

export default function DeliveryTracker() {
  const { t } = useTranslation();
  const [selectedDelivery, setSelectedDelivery] = useState(null);
  const [showModal, setShowModal] = useState(false);

  const { data: deliveries = [], refetch } = useQuery({
    queryKey: ['driver-deliveries'],
    queryFn: async () => {
      const response = await fetch('/api/driver/deliveries');
      if (!response.ok) throw new Error(t('common.error'));
      return response.json();
    },
  });

  const updateDeliveryMutation = useMutation({
    mutationFn: async ({ deliveryId, status }) => {
      const response = await fetch(`/api/driver/deliveries/${deliveryId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status }),
      });
      if (!response.ok) throw new Error(t('common.error'));
      return response.json();
    },
    onSuccess: () => {
      refetch();
      setShowModal(false);
    },
  });

  const handleStatusUpdate = (deliveryId, newStatus) => {
    updateDeliveryMutation.mutate({ deliveryId, status: newStatus });
  };

  const getStatusColor = (status) => {
    const colors = {
      pending: 'bg-yellow-100 text-yellow-800',
      in_progress: 'bg-blue-100 text-blue-800',
      completed: 'bg-green-100 text-green-800',
      cancelled: 'bg-red-100 text-red-800',
    };
    return colors[status] || 'bg-gray-100';
  };

  return (
    <>
      <Card title={t('driver.myDeliveries') || 'My Deliveries'} className="mb-8">
        <div className="space-y-4">
          {deliveries.map((delivery) => (
            <div key={delivery.id} className="border dark:border-gray-700 p-4 rounded-lg hover:shadow-md transition">
              <div className="flex justify-between items-start mb-3">
                <div className="flex-1">
                  <h4 className="font-bold text-lg">Order #{delivery.orderId}</h4>
                  <p className="text-sm text-gray-600 dark:text-gray-400">{delivery.customerName}</p>
                </div>
                <Badge label={delivery.status.toUpperCase()} className={getStatusColor(delivery.status)} />
              </div>

              <div className="grid grid-cols-2 gap-4 mb-4 text-sm">
                <div>
                  <p className="text-gray-600 dark:text-gray-400">From</p>
                  <p className="font-medium">{delivery.pickupLocation}</p>
                </div>
                <div>
                  <p className="text-gray-600 dark:text-gray-400">To</p>
                  <p className="font-medium">{delivery.deliveryLocation}</p>
                </div>
              </div>

              <div className="flex gap-4 justify-between items-center">
                <div className="text-sm">
                  <p className="text-gray-600">Payment</p>
                  <p className="font-bold text-lg">{delivery.amount.toFixed(2)} DH</p>
                </div>
                <div className="flex gap-2">
                  {delivery.status === 'pending' && (
                    <Button
                      size="sm"
                      onClick={() => {
                        setSelectedDelivery(delivery);
                        setShowModal(true);
                      }}
                    >
                      Start Delivery 🚗
                    </Button>
                  )}
                  {delivery.status === 'in_progress' && (
                    <Button
                      size="sm"
                      variant="success"
                      onClick={() => handleStatusUpdate(delivery.id, 'completed')}
                    >
                      Mark Complete ✅
                    </Button>
                  )}
                  <Button
                    size="sm"
                    variant="secondary"
                    onClick={() => {
                      setSelectedDelivery(delivery);
                      setShowModal(true);
                    }}
                  >
                    Details 👁️
                  </Button>
                </div>
              </div>
            </div>
          ))}
          {deliveries.length === 0 && (
            <p className="text-center py-8 text-gray-500 dark:text-gray-400">
              No deliveries available. Check back soon!
            </p>
          )}
        </div>
      </Card>

      {selectedDelivery && (
        <Modal
          isOpen={showModal}
          onClose={() => setShowModal(false)}
          title={`Delivery Details - Order #${selectedDelivery.orderId}`}
        >
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-gray-600 dark:text-gray-400">Customer</label>
              <p className="text-lg font-semibold">{selectedDelivery.customerName}</p>
            </div>
            <div>
              <label className="text-sm font-medium text-gray-600 dark:text-gray-400">Pickup Location</label>
              <p className="text-lg font-semibold">{selectedDelivery.pickupLocation}</p>
            </div>
            <div>
              <label className="text-sm font-medium text-gray-600 dark:text-gray-400">Delivery Location</label>
              <p className="text-lg font-semibold">{selectedDelivery.deliveryLocation}</p>
            </div>
            <div>
              <label className="text-sm font-medium text-gray-600 dark:text-gray-400">Amount</label>
              <p className="text-lg font-semibold">{selectedDelivery.amount.toFixed(2)} DH</p>
            </div>
            <Button variant="primary" className="w-full" onClick={() => setShowModal(false)}>
              Close
            </Button>
          </div>
        </Modal>
      )}
    </>
  );
}

import { useState } from 'react';
