  const { data: profile = {}, refetch } = useQuery({
    queryKey: ['driver-profile'],
    queryFn: async () => {
      const response = await fetch('/api/driver/profile');
      if (!response.ok) throw new Error(t('common.error'));
      return response.json();
    },
  });

