/**
 * 📸 ProductDetail Component
 * Full product page with images, specs, reviews, ratings and purchase options
 * Features: Image zoom, gallery, reviews form, related products, stock management
 * 
 * @component
 * @returns {React.ReactElement} Product detail page
 */

import { useState, useCallback, useEffect } from 'react';
import PropTypes from 'prop-types';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery, useMutation } from '@tanstack/react-query';
import { useTranslation } from 'react-i18next';
import clsx from 'clsx';

// Store & UI imports
import { useCartStore } from '../../../store/cartStore';
import Button from '../../../components/ui/Button';
import Input from '../../../components/ui/Input';
import Card from '../../../components/ui/Card';
import Alert from '../../../components/ui/Alert';
import StarRating from '../../../components/ui/StarRating';
import Badge from '../../../components/ui/Badge';
import LoadingSpinner from '../../../components/ui/LoadingSpinner';
import SkeletonLoaders from '../../../components/ui/SkeletonLoaders';
import ErrorBoundary from '../../../components/ErrorBoundary';

// ============================================
// PRODUCT DETAIL COMPONENT
// ============================================

/**
 * ProductDetail - Full product details page component
 */
export default function ProductDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { t } = useTranslation();
  const addItem = useCartStore((state) => state.addItem);

  // Local state
  const [selectedImage, setSelectedImage] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');
  const [showReviewForm, setShowReviewForm] = useState(false);

  // Fetch product details
  const {
    data: product,
    isLoading,
    error,
  } = useQuery({
    queryKey: ['product', id],
    queryFn: async () => {
      const response = await fetch(`/api/products/${id}`);
      if (!response.ok) throw new Error(t('common.error'));
      return response.json();
    },
  });

  // Fetch reviews
  const { data: reviews = [] } = useQuery({
    queryKey: ['reviews', id],
    queryFn: async () => {
      const response = await fetch(`/api/products/${id}/reviews`);
      if (!response.ok) throw new Error(t('common.error'));
      return response.json();
    },
  });

  // Fetch related products
  const { data: relatedProducts = [] } = useQuery({
    queryKey: ['relatedProducts', product?.category],
    queryFn: async () => {
      const response = await fetch(
        `/api/products?category=${product?.category}&limit=4`
      );
      if (!response.ok) throw new Error(t('common.error'));
      return response.json();
    },
    enabled: !!product?.category,
  });

  // Add to cart mutation
  const { mutate: addToCart, isPending: isAdding } = useMutation({
    mutationFn: async () => {
      const response = await fetch('/api/cart/add', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          productId: product.id,
          quantity,
        }),
      });

      if (!response.ok) throw new Error(t('common.error'));
      return response.json();
    },

    onSuccess: () => {
      // Add to local store
      addItem({
        id: product.id,
        name: product.name,
        price: product.price,
        discount: product.discount,
        quantity,
        image: product.images[0],
      });
    },
  });

  // ============================================
  // HANDLERS
  // ============================================

  const handleQuantityChange = useCallback((value) => {
    const quantity = parseInt(value, 10);
    if (quantity > 0 && quantity <= product?.stock) {
      setQuantity(quantity);
    }
  }, [product?.stock]);

  const handleAddToCart = useCallback(() => {
    if (product) {
      addToCart();
    }
  }, [product, addToCart]);

  const handleBuyNow = useCallback(() => {
    if (product) {
      addToCart();
      // Mutation will handle adding to store, then navigate
      setTimeout(() => navigate('/checkout'), 500);
    }
  }, [product, addToCart, navigate]);

  // ============================================
  // CALCULATIONS
  // ============================================

  const discountedPrice = product
    ? product.price * (1 - (product.discount || 0) / 100)
    : 0;

  const averageRating = reviews.length > 0
    ? (reviews.reduce((sum, r) => sum + r.rating, 0) / reviews.length).toFixed(1)
    : 0;

  // ============================================
  // RENDER STATES
  // ============================================

  if (isLoading) {
    return (
      <ErrorBoundary>
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-8">
          <div className="max-w-6xl mx-auto px-4">
            <SkeletonLoaders.Product />
          </div>
        </div>
      </ErrorBoundary>
    );
  }

  if (error || !product) {
    return (
      <ErrorBoundary>
        <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-8">
          <div className="max-w-6xl mx-auto px-4">
            <Alert type="error" message={t('product.notFound')} />
            <Button
              onClick={() => navigate('/marketplace')}
              variant="primary"
              className="mt-4"
            >
              {t('common.backToStore')}
            </Button>
          </div>
        </div>
      </ErrorBoundary>
    );
  }

  // ============================================
  // RENDER
  // ============================================

  return (
    <ErrorBoundary>
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-8">
        <div className="max-w-6xl mx-auto px-4">
          {/* Breadcrumb */}
          <div className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400 mb-6">
            <button
              onClick={() => navigate('/marketplace')}
              className="hover:text-blue-600 dark:hover:text-blue-400"
            >
              {t('common.marketplace')}
            </button>
            <span>/</span>
            <button
              onClick={() => navigate(`/marketplace?category=${product.category}`)}
              className="hover:text-blue-600 dark:hover:text-blue-400"
            >
              {product.category}
            </button>
            <span>/</span>
            <span className="font-medium text-gray-900 dark:text-white">
              {product.name}
            </span>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Image Section */}
            <div className="lg:col-span-2">
              <ImageGallery
                images={product.images}
                selectedImage={selectedImage}
                onSelectImage={setSelectedImage}
                productName={product.name}
                discount={product.discount}
                stock={product.stock}
              />
            </div>

            {/* Details Section */}
            <div>
              <ProductInfo
                product={product}
                quantity={quantity}
                onQuantityChange={handleQuantityChange}
                discountedPrice={discountedPrice}
                onAddToCart={handleAddToCart}
                onBuyNow={handleBuyNow}
                isAdding={isAdding}
                stock={product.stock}
                rating={averageRating}
                reviewCount={reviews.length}
              />
            </div>
          </div>

          {/* Tabs Section */}
          <div className="mt-12">
            <TabsSection
              product={product}
              reviews={reviews}
              activeTab={activeTab}
              onTabChange={setActiveTab}
              onShowReviewForm={() => setShowReviewForm(true)}
              averageRating={averageRating}
            />
          </div>

          {/* Related Products */}
          {relatedProducts.length > 0 && (
            <div className="mt-12">
              <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-6">
                {t('product.relatedProducts')}
              </h2>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                {relatedProducts.map((relProduct) => (
                  <ProductCardMini
                    key={relProduct.id}
                    product={relProduct}
                    onSelect={() => navigate(`/marketplace/product/${relProduct.id}`)}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Review Form Modal */}
          {showReviewForm && (
            <ReviewFormModal
              productId={product.id}
              onClose={() => setShowReviewForm(false)}
            />
          )}
        </div>
      </div>
    </ErrorBoundary>
  );
}

// ============================================
// SUB-COMPONENTS
// ============================================

function ImageGallery({
  images,
  selectedImage,
  onSelectImage,
  productName,
  discount,
  stock,
}) {
  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg overflow-hidden">
      {/* Main Image */}
      <div className="relative bg-gray-100 dark:bg-gray-700 aspect-square overflow-hidden">
        <img
          src={images[selectedImage]}
          alt={productName}
          className="w-full h-full object-cover hover:scale-110 transition-transform duration-300"
        />

        {/* Discount Badge */}
        {discount > 0 && (
          <Badge
            className="absolute top-4 right-4 bg-red-500 text-white"
            label={`-${discount}%`}
          />
        )}

        {/* Stock Status */}
        {stock === 0 && (
          <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
            <span className="text-white text-lg font-bold">Out of Stock</span>
          </div>
        )}
      </div>

      {/* Thumbnail Gallery */}
      {images.length > 1 && (
        <div className="flex gap-4 p-4 overflow-x-auto">
          {images.map((image, index) => (
            <button
              key={index}
              onClick={() => onSelectImage(index)}
              className={clsx(
                'flex-shrink-0 w-20 h-20 rounded-lg overflow-hidden border-2',
                selectedImage === index
                  ? 'border-blue-500'
                  : 'border-gray-300 dark:border-gray-600'
              )}
            >
              <img
                src={image}
                alt={`${productName}-${index}`}
                className="w-full h-full object-cover"
              />
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function ProductInfo({
