  return (
    <Card>
      <div className="space-y-6">
        {/* Title */}
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">
            {product.name}
          </h1>
          <p className="text-gray-600 dark:text-gray-400 text-sm mt-2">
            {t('product.vendor')}: {product.vendor}
