          >
            {t('product.addToCart')} 🛒
          </Button>
          <Button
            onClick={onBuyNow}
            variant="primary"
            className="w-full"
            disabled={stock === 0 || isAdding}
          >
            {t('product.buyNow')} ⚡
          </Button>
