        <div className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400 bg-gray-100 dark:bg-gray-700 p-3 rounded">
          <span>🔒</span>
          <span>{t('product.securePayment')}</span>
        </div>
      </div>
    </Card>
  );
