function ReviewFormModal({ productId, onClose }) {
  const { t } = useTranslation();
  const [rating, setRating] = useState(5);
  const [text, setText] = useState('');
  const [author, setAuthor] = useState('');

  const { mutate: submitReview, isPending } = useMutation({
    mutationFn: async () => {
      const response = await fetch(`/api/products/${productId}/reviews`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ rating, text, author }),
      });

      if (!response.ok) throw new Error(t('common.error'));
      return response.json();
    },

    onSuccess: () => {
      onClose();
    },
  });

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <Card className="w-full max-w-md">
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-4">
          {t('product.writeReview')}
        </h2>

        <div className="space-y-4">
          <Input
            label={t('product.name')}
            value={author}
            onChange={(e) => setAuthor(e.target.value)}
          />

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              {t('product.rating')}
            </label>
            <StarRating rating={rating} onRate={setRating} />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              {t('product.comment')}
            </label>
            <textarea
              value={text}
              onChange={(e) => setText(e.target.value)}
              rows="4"
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-900 dark:text-white"
              placeholder={t('product.enterComment')}
            />
          </div>

          <div className="flex gap-4">
            <Button onClick={onClose} variant="secondary" className="flex-1">
              {t('common.cancel')}
            </Button>
            <Button
              onClick={() => submitReview()}
              variant="primary"
              className="flex-1"
              loading={isPending}
            >
              {t('common.submit')}
            </Button>
          </div>
        </div>
      </Card>
    </div>
  );
}

