            alreadyAccepted={profile?.vendor_guidelines_accepted || false}
          />

          <div className="flex gap-3 pt-4">
            <button type="button" onClick={() => navigate(-1)} className="btn-outline flex-1">
              {t('common.cancel', 'Cancel')}
