import { useState, useEffect, useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import { useNavigate } from 'react-router-dom'
import { useCartStore } from '@/store/cartStore'
import { useAuthStore } from '@/store/authStore'
import { Card, LoadingSpinner, Input, DriverSelection, NoDriverAvailable, LocationPicker } from '@/components/ui'
import { CreditCardIcon, BanknotesIcon, TruckIcon, CheckIcon, ChevronRightIcon, MapPinIcon, BuildingLibraryIcon, ClockIcon, TagIcon, XMarkIcon } from '@heroicons/react/24/outline'
import { formatPrice } from '@/utils/currency'
import toast from 'react-hot-toast'
import { supabase } from '@/services/supabase'
import { platformSettings } from '@/services/platformSettings'
import { calculateShippingCost, getEstimatedDeliveryTime } from '@/services/shippingCalculator'
import { logger } from '@/utils/logger'

const CheckoutSimplified = () => {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { user, profile } = useAuthStore()
  const { items, getSubtotal, getTax, clearCart } = useCartStore()

  // Calculate totals using useMemo for performance
  const subtotal = useMemo(() => getSubtotal(), [getSubtotal])
  const tax = useMemo(() => getTax(), [getTax])
  const [shippingCost, setShippingCost] = useState(0)
  const [shippingLoading, setShippingLoading] = useState(false)
  const [shippingInfo_data, setShippingInfoData] = useState(null)
  const [estimatedDeliveryTime, setEstimatedDeliveryTime] = useState(null)
  const [loading, setLoading] = useState(false)
  const [step, setStep] = useState(1)
  const [paymentMethod, setPaymentMethod] = useState('cod')
  const [selectedBank, setSelectedBank] = useState(null)
  const [selectedDriver, setSelectedDriver] = useState(null)
  const [_availableDrivers, setAvailableDrivers] = useState([])
  const [loadingDrivers, setLoadingDrivers] = useState(false)
  const [noDriversAvailable, setNoDriversAvailable] = useState(false)
  const [vendorLocation, setVendorLocation] = useState(null)
  const [shippingInfo, setShippingInfo] = useState({
    fullName: profile?.first_name ? `${profile.first_name} ${profile.last_name}` : '',
    phone: profile?.phone || '',
    address: profile?.address || '',
    city: profile?.city || '',
    notes: '',
  })
  const [deliveryLocation, setDeliveryLocation] = useState({
    lat: profile?.latitude || null,
    lng: profile?.longitude || null,
  })
  const [errors, setErrors] = useState({})

  // Coupon state
  const [couponCode, setCouponCode] = useState('')
  const [appliedCoupon, setAppliedCoupon] = useState(null)
  const [couponLoading, setCouponLoading] = useState(false)
  const couponDiscount = useMemo(() => {
    if (!appliedCoupon) return 0
    if (appliedCoupon.discount_type === 'percentage') {
      return subtotal * (appliedCoupon.discount_value / 100)
    }
    return Math.min(appliedCoupon.discount_value, subtotal) // fixed amount, capped at subtotal
  }, [appliedCoupon, subtotal])
  const total = useMemo(() => subtotal + tax + shippingCost - couponDiscount, [subtotal, tax, shippingCost, couponDiscount])

  // Load available drivers when reaching step 2
  useEffect(() => {
    if (step === 2 && items.length > 0) {
      loadAvailableDrivers()
    }
  }, [step, items.length])

  // Load vendor location when items change
  useEffect(() => {
    if (items.length > 0 && items[0]?.vendor_id) {
      loadVendorLocation(items[0].vendor_id)
    }
  }, [items])

  // Recalculate shipping when driver, city, or delivery location changes
  useEffect(() => {
    if (step >= 2 && shippingInfo.city && items.length > 0 && deliveryLocation.lat && deliveryLocation.lng) {
      recalculateShipping()
    }
  }, [selectedDriver, shippingInfo.city, deliveryLocation, step, vendorLocation, items.length])

  const loadVendorLocation = async (vendorId) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('city, latitude, longitude')
        .eq('id', vendorId)
        .maybeSingle()

      if (error) throw error

      if (data) {
        setVendorLocation({
          city: data.city,
          lat: data.latitude,
          lon: data.longitude,
        })
      }
    } catch (error) {
      logger.error('Error loading vendor location:', error)
    }
  }

  const recalculateShipping = async () => {
    if (!shippingInfo.city || items.length === 0) {
      setShippingCost(0)
      setEstimatedDeliveryTime(null)
      return
    }

    setShippingLoading(true)

    try {
      // Use delivery location coordinates (from GPS or map picker)
      const buyerLat = deliveryLocation?.lat || null
      const buyerLon = deliveryLocation?.lng || null

      const result = await calculateShippingCost({
        vendorCity: vendorLocation?.city,
        vendorLat: vendorLocation?.lat,
        vendorLon: vendorLocation?.lon,
        buyerCity: shippingInfo.city,
        buyerLat,
        buyerLon,
        driverId: selectedDriver,
      })

      setShippingCost(result.cost)
      setShippingInfoData(result)

      // Calculate estimated delivery time
      if (result.distance) {
        const estTime = getEstimatedDeliveryTime(result.distance)
        setEstimatedDeliveryTime(estTime)
      } else {
        setEstimatedDeliveryTime('45-60 min')
      }
    } catch (error) {
      logger.error('Error calculating shipping:', error)
      // Fallback to default
      setShippingCost(15.0)
      setEstimatedDeliveryTime('45-60 min')
    } finally {
      setShippingLoading(false)
    }
  }

  const loadAvailableDrivers = async () => {
    setLoadingDrivers(true)
    setNoDriversAvailable(false)
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, vehicle_type, rating')
        .eq('role', 'driver')
        .eq('is_available_for_delivery', true)

      if (error) throw error

      if (data && data.length > 0) {
        setAvailableDrivers(data)
        setNoDriversAvailable(false)
      } else {
        setAvailableDrivers([])
        setNoDriversAvailable(true)
      }
    } catch (error) {
      logger.error('Error loading drivers:', error)
      setAvailableDrivers([])
      setNoDriversAvailable(true)
    } finally {
      setLoadingDrivers(false)
    }
  }

  // ============================================
  // Coupon Validation
  // ============================================

  const validateCoupon = async (code) => {
    if (!code.trim()) return
    setCouponLoading(true)
    try {
      const { data: coupon, error } = await supabase
        .from('coupons')
        .select('*')
        .eq('code', code.toUpperCase().trim())
        .eq('is_active', true)
        .maybeSingle()

      if (error) throw error
      if (!coupon) {
        toast.error('Invalid coupon code')
        return
      }

      // Check expiry
      if (coupon.expires_at && new Date(coupon.expires_at) < new Date()) {
        toast.error('This coupon has expired')
        return
      }

      // Check max uses
      if (coupon.max_uses) {
        const { count } = await supabase
          .from('coupon_redemptions')
          .select('*', { count: 'exact', head: true })
          .eq('coupon_id', coupon.id)
        if (count >= coupon.max_uses) {
          toast.error('This coupon has been used up')
          return
        }
      }

      // Check min order amount
      if (coupon.min_order_amount && subtotal < coupon.min_order_amount) {
        toast.error(`Minimum order is ${formatPrice(coupon.min_order_amount)}`)
        return
      }

      // Check user hasn't used this coupon before
      const { count: userCount } = await supabase
        .from('coupon_redemptions')
        .select('*', { count: 'exact', head: true })
        .eq('coupon_id', coupon.id)
        .eq('user_id', user.id)
      if (userCount > 0) {
        toast.error('You have already used this coupon')
        return
      }

      setAppliedCoupon(coupon)
      toast.success(`Coupon applied! ${coupon.discount_type === 'percentage' ? `${coupon.discount_value}%` : formatPrice(coupon.discount_value)} off`)
    } catch (err) {
      logger.error('Coupon validation error:', err)
      toast.error('Failed to validate coupon')
    } finally {
      setCouponLoading(false)
    }
  }

  if (!user) {
    navigate('/login', { state: { from: '/checkout' } })
    return null
  }

  if (items.length === 0) {
    return (
      <div className="text-center py-16">
        <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
          <TruckIcon className="w-10 h-10 text-gray-400" />
        </div>
        <h2 className="text-xl font-bold text-gray-900 mb-2">{t('checkout.emptyCart')}</h2>
        <p className="text-gray-500 mb-6">{t('checkout.addProductsFirst')}</p>
        <button onClick={() => navigate('/marketplace')} className="btn-primary">
          {t('checkout.browseProducts')}
        </button>
      </div>
    )
  }

  const validateStep1 = () => {
    const newErrors = {}
    if (!shippingInfo.fullName.trim()) newErrors.fullName = 'الاسم مطلوب'
    if (!shippingInfo.phone.trim()) newErrors.phone = 'رقم الهاتف مطلوب'
    if (!shippingInfo.city.trim()) newErrors.city = 'المدينة مطلوبة'
    if (!shippingInfo.address.trim()) newErrors.address = 'العنوان مطلوب'
    if (!deliveryLocation.lat || !deliveryLocation.lng) {
      newErrors.location = 'يرجى تحديد موقعك الدقيق على الخريطة'
    }
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleNext = () => {
    if (step === 1 && validateStep1()) {
      setStep(2)
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()

    setLoading(true)
    try {
      // Re-validate coupon just before payment to prevent expired/over-limit coupons
      if (appliedCoupon) {
        const { data: freshCoupon, error: couponError } = await supabase
          .from('coupons')
          .select('id, is_active, valid_until, max_uses, current_uses')
          .eq('id', appliedCoupon.id)
          .single()

        const couponInvalid =
          couponError ||
          !freshCoupon ||
          !freshCoupon.is_active ||
          (freshCoupon.valid_until && new Date(freshCoupon.valid_until) < new Date()) ||
          (freshCoupon.max_uses !== null && freshCoupon.current_uses >= freshCoupon.max_uses)

        if (couponInvalid) {
          setAppliedCoupon(null)
          setCouponCode('')
          toast.error('انتهت صلاحية الكوبون أو تم استنفاده. يرجى المتابعة بدونه أو إدخال كوبون آخر.')
          setLoading(false)
          return
        }
      }

      // Fetch current commission rate from platform settings
      let commissionRate = 2.0 // fallback default
      try {
        const settings = await platformSettings.getSettings()
        commissionRate = settings?.commission_rate ?? 2.0
      } catch (e) {
        // If settings fetch fails, fall back to default
        console.warn('Failed to fetch commission rate, using default:', e)
      }

      // Group items by vendor
      const vendorItems = {}
      items.forEach(item => {
        if (!vendorItems[item.vendor_id]) vendorItems[item.vendor_id] = []
        vendorItems[item.vendor_id].push(item)
      })

      // Create orders for each vendor
      const orders = []
      const PLATFORM_COMMISSION_RATE = commissionRate // Use dynamic rate from platform settings
      const subtotalTotal = items.reduce((sum, item) => sum + (item.price_per_unit || item.price || 0) * item.quantity, 0)

      for (const [vendorId, vItems] of Object.entries(vendorItems)) {
        const subtotal = vItems.reduce((sum, item) => sum + (item.price_per_unit || item.price || 0) * item.quantity, 0)

        // Commission calculations
        const buyerCommission = parseFloat((subtotal * (PLATFORM_COMMISSION_RATE / 100)).toFixed(2))
        const vendorCommission = parseFloat((subtotal * (PLATFORM_COMMISSION_RATE / 100)).toFixed(2))
        const vendorAmount = parseFloat((subtotal - vendorCommission).toFixed(2))

        // Coupon discount — apply proportionally if multi-vendor
        const orderCouponDiscount = appliedCoupon
          ? parseFloat((couponDiscount * (subtotal / subtotalTotal)).toFixed(2))
          : 0
        const buyerTotal = parseFloat((subtotal + buyerCommission + shippingCost - orderCouponDiscount).toFixed(2))

        // Calculate shipping cost (driver will also pay 2% commission on this)
        const driverCommission = parseFloat((shippingCost * (PLATFORM_COMMISSION_RATE / 100)).toFixed(2))
        const driverAmount = parseFloat((shippingCost - driverCommission).toFixed(2))

        const { data, error } = await supabase
          .from('orders')
          .insert({
            buyer_id: user.id,
            vendor_id: vendorId,
            driver_id: selectedDriver || null,
            subtotal: subtotal,
            shipping_cost: shippingCost,
            tax: 0,
            total: buyerTotal,
            buyer_commission: buyerCommission,
            buyer_total: buyerTotal,
            vendor_amount: vendorAmount,
            driver_commission: driverCommission,
            driver_amount: driverAmount,
            status: selectedDriver ? 'pending' : 'awaiting_driver',
            shipping_address: shippingInfo.address,
            shipping_city: shippingInfo.city,
            shipping_country: 'Morocco',
            shipping_latitude: deliveryLocation.lat || null,
            shipping_longitude: deliveryLocation.lng || null,
            buyer_notes: shippingInfo.notes,
          })
          .select()
          .single()

        if (error) throw error

        // Create payment record — use buyerTotal (includes commission, shipping, coupon)
        const { error: paymentError } = await supabase
          .from('payments')
          .insert({
            order_id: data.id,
            amount: buyerTotal,
            payment_method: paymentMethod,
            status: 'pending',
          })

        if (paymentError) throw paymentError

        // Create order items
        const orderItems = vItems.map(item => ({
          order_id: data.id,
          product_id: item.id,
          quantity: item.quantity,
          unit_price: item.price_per_unit || item.price || 0,
          total: (item.price_per_unit || item.price || 0) * item.quantity,
        }))

        const { error: itemsError } = await supabase
          .from('order_items')
          .insert(orderItems)

        if (itemsError) throw itemsError

        // If no driver selected, the auto-dispatch system will handle it
        // The database trigger will create a delivery record when vendor accepts
        orders.push(data)
      }

      // Record coupon redemption (only once, after all orders created)
      if (appliedCoupon) {
        await supabase
          .from('coupon_redemptions')
          .insert({
            coupon_id: appliedCoupon.id,
            user_id: user.id,
            order_id: orders[0].id,
            discount_amount: couponDiscount,
          })
      }

      clearCart()
      setAppliedCoupon(null)
      setCouponCode('')

      // Enrich order data with items, buyer, vendor, and payment_method for the confirmation page
      const enrichedOrders = await Promise.all(
        orders.map(async (order) => {
          // Fetch order items
          const { data: orderItems } = await supabase
            .from('order_items')
            .select('*, product:products(name)')
            .eq('order_id', order.id)

          // Fetch payment method
          const { data: paymentData } = await supabase
            .from('payments')
            .select('method')
            .eq('order_id', order.id)
            .maybeSingle()

          // Fetch buyer profile
          const { data: buyerData } = await supabase
            .from('profiles')
            .select('first_name, last_name, email, phone')
            .eq('id', order.buyer_id)
            .maybeSingle()

          // Fetch vendor profile
          const { data: vendorData } = await supabase
            .from('profiles')
            .select('store_name, city')
            .eq('id', order.vendor_id)
            .maybeSingle()

          return {
            ...order,
            items: orderItems || [],
            payment_method: paymentData?.method || paymentMethod,
            buyer: buyerData || {},
            vendor: vendorData || {},
          }
        })
      )

      // Send order confirmation email
      try {
        const { emailService } = await import('@/services/emailService')
        const { data: buyerProfile } = await supabase
          .from('profiles')
          .select('first_name, last_name, email')
          .eq('id', user.id)
          .maybeSingle()

        if (buyerProfile?.email) {
          await emailService.sendOrderConfirmation(enrichedOrders[0], {
            name: `${buyerProfile.first_name || ''} ${buyerProfile.last_name || ''}`.trim(),
            email: buyerProfile.email,
          })
        }
      } catch (emailErr) {
        // Don't fail checkout if email fails
        logger.error('Order confirmation email failed:', emailErr)
      }

      if (paymentMethod === 'bank') {
        toast.success(`🎉 تم تقديم الطلب! يرجى إكمال التحويل البنكي إلى ${selectedBank || 'البنك المحدد'}`)
      } else if (paymentMethod === 'cod') {
        toast.success('🎉 تم تقديم الطلب بنجاح! الدفع عند الاستلام')
      } else {
        toast.success('🎉 تم تقديم الطلب بنجاح!')
      }

      navigate('/order-confirmation', {
        state: {
          order: enrichedOrders[0],
          paymentMethod,
          selectedBank: paymentMethod === 'bank' ? selectedBank : null,
        }
      })
    } catch (error) {
      logger.error('Checkout error:', error)
      toast.error(error.message || 'Failed to place order')
    } finally {
      setLoading(false)
    }
  }

  const steps = [
    { num: 1, label: 'Shipping' },
    { num: 2, label: 'Delivery' },
    { num: 3, label: 'Payment' },
  ]

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8" role="main" aria-label="Checkout page">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900 mb-4">{t('checkout.title')}</h1>

        {/* Steps Indicator */}
        <nav aria-label="Checkout steps">
          <div className="flex items-center gap-2">
            {steps.map((s, i) => (
              <div key={s.num} className="flex items-center gap-2">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-semibold ${
                  step >= s.num ? 'bg-green-500 text-white' : 'bg-gray-200 text-gray-500'
                }`} aria-current={step === s.num ? 'step' : undefined}>
                  {step > s.num ? <CheckIcon className="w-4 h-4" /> : s.num}
                </div>
                <span className={`text-sm font-medium ${step >= s.num ? 'text-green-600' : 'text-gray-400'}`}>
                  {t(`checkout.steps.${s.label.toLowerCase()}`)}
                </span>
                {i < steps.length - 1 && <ChevronRightIcon className="w-4 h-4 text-gray-300" aria-hidden="true" />}
              </div>
            ))}
          </div>
        </nav>
      </div>

      <form onSubmit={handleSubmit} aria-label="Checkout form">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left: Shipping & Payment */}
          <div className="lg:col-span-2 space-y-6">
            {/* Step 1: Shipping Info */}
            {step === 1 && (
              <Card className="p-6">
                <h2 className="font-semibold text-gray-900 mb-4 flex items-center gap-2">
                  <TruckIcon className="w-5 h-5" />
                  Shipping Information
                </h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div>
                    <Input
                      label="Full Name *"
                      value={shippingInfo.fullName}
                      onChange={(e) => { setShippingInfo({ ...shippingInfo, fullName: e.target.value }); setErrors({...errors, fullName: null}) }}
                      placeholder="Your full name"
                    />
                    {errors.fullName && <p className="text-red-500 text-xs mt-1">{errors.fullName}</p>}
                  </div>
                  <div>
                    <Input
                      label="Phone *"
                      type="tel"
                      value={shippingInfo.phone}
                      onChange={(e) => { setShippingInfo({ ...shippingInfo, phone: e.target.value }); setErrors({...errors, phone: null}) }}
                      placeholder="+212 6XX XXX XXX"
                    />
                    {errors.phone && <p className="text-red-500 text-xs mt-1">{errors.phone}</p>}
                  </div>
                  <div>
                    <Input
                      label="City *"
                      value={shippingInfo.city}
                      onChange={(e) => { setShippingInfo({ ...shippingInfo, city: e.target.value }); setErrors({...errors, city: null}) }}
                      placeholder="Casablanca"
                    />
                    {errors.city && <p className="text-red-500 text-xs mt-1">{errors.city}</p>}
                  </div>
                  <div className="sm:col-span-2">
                    <label htmlFor="checkout-address" className="input-label">Address *</label>
                    <textarea
                      id="checkout-address"
                      value={shippingInfo.address}
                      onChange={(e) => { setShippingInfo({ ...shippingInfo, address: e.target.value }); setErrors({...errors, address: null}) }}
                      className={`input h-20 resize-none ${errors.address ? 'border-red-500' : ''}`}
                      placeholder="الشارع، المبنى، الشقة..."
                    />
                    {errors.address && <p className="text-red-500 text-xs mt-1">{errors.address}</p>}
                  </div>

                  {/* Location Picker */}
                  <div className="sm:col-span-2">
                    <LocationPicker
                      value={deliveryLocation}
                      onChange={(loc) => {
                        setDeliveryLocation(loc)
                        setErrors({...errors, location: null})
                      }}
                      city={shippingInfo.city}
                      required
                    />
                    {errors.location && (
                      <p className="text-red-500 text-xs mt-2 flex items-center gap-1">
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                        </svg>
                        {errors.location}
                      </p>
                    )}
                  </div>

                  <div className="sm:col-span-2">
                    <label htmlFor="checkout-notes" className="input-label">Notes (optional)</label>
                    <textarea
                      id="checkout-notes"
                      value={shippingInfo.notes}
                      onChange={(e) => setShippingInfo({ ...shippingInfo, notes: e.target.value })}
                      className="input h-16 resize-none"
                      placeholder="Delivery instructions, apartment number, etc."
                    />
                  </div>
                </div>
                <button type="button" onClick={handleNext} className="btn-primary w-full mt-6">
                  Continue to Delivery Selection
                </button>
              </Card>
            )}

            {/* Step 2: Driver Selection */}
            {step === 2 && (
              <Card className="p-6">
                <h2 className="font-semibold text-gray-900 mb-4 flex items-center gap-2">
                  <TruckIcon className="w-5 h-5" />
                  Delivery Driver
                </h2>

                {loadingDrivers ? (
                  <div className="flex items-center justify-center py-8">
                    <LoadingSpinner size="md" />
                    <p className="text-sm text-gray-600 ml-3">Finding available drivers...</p>
                  </div>
                ) : noDriversAvailable ? (
                  <NoDriverAvailable
                    vendorId={items[0]?.vendor_id}
                    productId={items[0]?.id}
                    productName={items[0]?.name}
                  />
                ) : (
                  <>
                    {/* Delivery Address Summary */}
                    <div className="p-4 bg-gray-50 rounded-xl mb-4">
                      <div className="flex items-start gap-2">
                        <MapPinIcon className="w-5 h-5 text-gray-400 mt-0.5" />
                        <div className="flex-1">
                          <p className="text-sm font-medium text-gray-900">Delivery to:</p>
                          <p className="text-sm text-gray-600">{shippingInfo.address}</p>
                          <p className="text-sm text-gray-600">{shippingInfo.city}</p>
                          {shippingInfo_data && (
                            <div className="mt-2 pt-2 border-t border-gray-200">
                              <div className="flex justify-between text-xs">
                                <span className="text-gray-500">Estimated cost:</span>
                                <span className="font-semibold text-green-600">
                                  {shippingLoading ? 'Calculating...' : formatPrice(shippingCost)}
                                </span>
                              </div>
                              {shippingInfo_data.distance && (
                                <div className="flex justify-between text-xs mt-1">
                                  <span className="text-gray-500">Distance:</span>
                                  <span>{shippingInfo_data.distance.toFixed(1)} km</span>
                                </div>
                              )}
                              {estimatedDeliveryTime && (
                                <div className="flex justify-between text-xs mt-1">
                                  <span className="text-gray-500">Est. time:</span>
                                  <span className="flex items-center gap-1">
                                    <ClockIcon className="w-3 h-3" />
                                    {estimatedDeliveryTime}
                                  </span>
                                </div>
                              )}
                              {shippingInfo_data.pricingSource && (
                                <div className="flex justify-between text-xs mt-1">
                                  <span className="text-gray-500">Pricing from:</span>
                                  <span className="capitalize">{shippingInfo_data.pricingSource}</span>
                                </div>
                              )}
                            </div>
                          )}
                        </div>
                      </div>
                    </div>

                    <DriverSelection
                      selectedDriver={selectedDriver}
                      onChange={setSelectedDriver}
                    />

                    <div className="flex gap-3 mt-6">
                      <button type="button" onClick={() => setStep(1)} className="btn-outline flex-1">
                        Back
                      </button>
                      <button
                        type="button"
                        onClick={() => selectedDriver && setStep(3)}
                        disabled={!selectedDriver}
                        className="btn-primary flex-1 disabled:opacity-50 disabled:cursor-not-allowed"
                      >
                        Continue to Payment
                      </button>
                    </div>
                  </>
                )}
              </Card>
            )}

            {/* Step 3: Payment */}
            {step === 3 && (
              <Card className="p-6">
                <h2 className="font-semibold text-gray-900 mb-4 flex items-center gap-2">
                  <CreditCardIcon className="w-5 h-5" />
                  Payment Method
                </h2>
                <div className="space-y-3">
                  <label className={`flex items-center gap-3 p-4 border-2 rounded-xl cursor-pointer transition-all ${
                    paymentMethod === 'cod' ? 'border-green-500 bg-green-50' : 'border-gray-200 hover:border-gray-300'
                  }`}>
                    <input
                      type="radio"
                      name="payment"
                      value="cod"
                      checked={paymentMethod === 'cod'}
                      onChange={(e) => setPaymentMethod(e.target.value)}
                      className="text-green-500"
                    />
                    <BanknotesIcon className="w-5 h-5 text-gray-500" />
                    <div>
                      <p className="font-medium">Cash on Delivery</p>
                      <p className="text-sm text-gray-500">Pay when you receive your order</p>
                    </div>
                  </label>
                  <label className={`flex items-center gap-3 p-4 border-2 rounded-xl cursor-pointer transition-all ${
                    paymentMethod === 'bank' ? 'border-green-500 bg-green-50' : 'border-gray-200 hover:border-gray-300'
                  }`}>
                    <input
                      type="radio"
                      name="payment"
                      value="bank"
                      checked={paymentMethod === 'bank'}
                      onChange={(e) => setPaymentMethod(e.target.value)}
                      className="text-green-500"
                    />
                    <BuildingLibraryIcon className="w-5 h-5 text-gray-500" />
                    <div>
                      <p className="font-medium">Bank Transfer</p>
                      <p className="text-sm text-gray-500">Transfer to our bank account</p>
                    </div>
                  </label>
                  <label className={`flex items-center gap-3 p-4 border-2 rounded-xl cursor-pointer transition-all ${
                    paymentMethod === 'card' ? 'border-green-500 bg-green-50' : 'border-gray-200 hover:border-gray-300'
                  }`}>
                    <input
                      type="radio"
                      name="payment"
                      value="card"
                      checked={paymentMethod === 'card'}
                      onChange={(e) => setPaymentMethod(e.target.value)}
                      className="text-green-500"
                    />
                    <CreditCardIcon className="w-5 h-5 text-gray-500" />
                    <div>
                      <p className="font-medium">Credit/Debit Card</p>
                      <p className="text-sm text-gray-500">Coming soon - Pay securely with your card</p>
                    </div>
                  </label>
                </div>

                {/* Bank Selection */}
                {paymentMethod === 'bank' && (
                  <div className="mt-6 space-y-4">
                    <div className="p-4 bg-blue-50 border border-blue-200 rounded-xl">
                      <h3 className="font-semibold text-blue-900 mb-3 flex items-center gap-2">
                        <BuildingLibraryIcon className="w-5 h-5" />
                        اختر بنكك
                      </h3>
                      <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                        {[
                          { name: 'Attijariwafa Bank', color: '#F37021' },
                          { name: 'BMCE Bank of Africa', color: '#0066B3' },
                          { name: 'Banque Populaire', color: '#E30613' },
                          { name: 'CIH Bank', color: '#6B2D8B' },
                          { name: 'Crédit du Maroc', color: '#009639' },
                          { name: 'Société Générale', color: '#E2001A' },
                          { name: 'Al Barid Bank', color: '#FFD100' },
                          { name: 'CFG Bank', color: '#003366' },
                          { name: 'Umnia Bank', color: '#8B0000' },
                          { name: 'Bank Assafa', color: '#00A651' },
                          { name: 'Dar Al Amane', color: '#0057B8' },
                          { name: 'CDG Capital', color: '#005EB8' },
                        ].map((bank) => (
                          <button
                            key={bank.name}
                            type="button"
                            onClick={() => setSelectedBank(bank.name)}
                            className={`p-2 border-2 rounded-lg text-xs font-medium transition-all ${
                              selectedBank === bank.name
                                ? 'border-blue-500 bg-blue-50'
                                : 'border-gray-200 hover:border-blue-500 hover:bg-blue-50'
                            }`}
                          >
                            <div
                              className="w-2 h-2 rounded-full mx-auto mb-1"
                              style={{ backgroundColor: bank.color }}
                            />
                            <span className="text-[10px]">{bank.name}</span>
                          </button>
                        ))}
                      </div>
                    </div>

                    {selectedBank && (
                      <div className="p-4 bg-green-50 border border-green-200 rounded-xl">
                        <p className="text-sm text-green-800">
                          ✓ البنك المحدد: <strong>{selectedBank}</strong>
                        </p>
                        <p className="text-xs text-green-700 mt-2">
                          سيتم تحويلك إلى بوابة الدفع البنكية بعد تأكيد الطلب
                        </p>
                      </div>
                    )}

                    <div className="p-4 bg-yellow-50 border border-yellow-200 rounded-lg">
                      <p className="text-xs text-yellow-800">
                        ⚠️ <strong>مهم:</strong> يجب إكمال التحويل البنكي خلال 24 ساعة لتأكيد الطلب
                      </p>
                    </div>
                  </div>
                )}

                {/* Shipping Summary */}
                <div className="mt-6 p-4 bg-gray-50 rounded-xl">
                  <h3 className="font-medium text-sm text-gray-700 mb-2">Shipping to:</h3>
                  <p className="text-sm text-gray-600">{shippingInfo.fullName}</p>
                  <p className="text-sm text-gray-600">{shippingInfo.address}</p>
                  <p className="text-sm text-gray-600">{shippingInfo.city} • {shippingInfo.phone}</p>
                </div>

                <div className="flex gap-3 mt-6">
                  <button type="button" onClick={() => setStep(2)} className="btn-outline flex-1">
                    Back
                  </button>
                  <button type="submit" className="btn-primary flex-1" disabled={loading}>
                    {loading ? <LoadingSpinner size="sm" /> : `Place Order - ${formatPrice(total + subtotal * 0.02)}`}
                  </button>
                </div>
              </Card>
            )}
          </div>

          {/* Right: Order Summary */}
          <div className="lg:col-span-1">
            <Card className="p-6 sticky top-24">
              <h2 className="font-semibold text-gray-900 mb-4">Order Summary</h2>
              <div className="space-y-3 mb-4 max-h-60 overflow-y-auto">
                {items.map((item) => (
                  <div key={item.id} className="flex items-center gap-3">
                    {item.image ? (
                      <img src={item.image} alt={item.name} className="w-12 h-12 rounded-lg object-cover" />
                    ) : (
                      <div className="w-12 h-12 bg-gray-100 rounded-lg flex items-center justify-center text-gray-400">
                        <span className="text-lg">🌱</span>
                      </div>
                    )}
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium truncate">{item.name}</p>
                      <p className="text-xs text-gray-500">Qty: {item.quantity}</p>
                    </div>
                    <span className="text-sm font-semibold">{formatPrice((item.price_per_unit || item.price) * item.quantity)}</span>
                  </div>
                ))}
              </div>
              <div className="border-t pt-4 space-y-2">
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">Subtotal</span>
                  <span>{formatPrice(subtotal)}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">VAT (20%)</span>
                  <span>{formatPrice(tax)}</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">
                    Delivery
                    {shippingLoading && <LoadingSpinner size="sm" className="ml-2 inline-block" />}
                  </span>
                  {shippingLoading ? (
                    <span className="text-gray-400">Calculating...</span>
                  ) : shippingCost > 0 ? (
                    <span>{formatPrice(shippingCost)}</span>
                  ) : (
                    <span className="text-green-600">Free</span>
                  )}
                </div>
                {estimatedDeliveryTime && (
                  <div className="flex justify-between text-xs text-gray-500">
                    <span className="flex items-center gap-1">
                      <ClockIcon className="w-3 h-3" />
                      Est. delivery time
                    </span>
                    <span>{estimatedDeliveryTime}</span>
                  </div>
                )}
                {shippingInfo_data && shippingInfo_data.distance && (
                  <div className="flex justify-between text-xs text-gray-500">
                    <span>Distance</span>
                    <span>{shippingInfo_data.distance.toFixed(1)} km</span>
                  </div>
                )}
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">Platform Fee (2%)</span>
                  <span>{formatPrice(subtotal * 0.02)}</span>
                </div>

                {/* Coupon Input */}
                <div className="border-t pt-3">
                  <div className="flex gap-2">
                    <div className="relative flex-1">
                      <TagIcon className="w-4 h-4 text-gray-400 absolute left-2.5 top-1/2 -translate-y-1/2" />
                      <input
                        type="text"
                        value={couponCode}
                        onChange={(e) => setCouponCode(e.target.value.toUpperCase())}
                        placeholder="Coupon code"
                        className="w-full pl-8 pr-3 py-2 text-sm border border-gray-200 rounded-lg uppercase font-mono focus:ring-2 focus:ring-green-500 focus:border-green-500"
                        disabled={couponLoading || !!appliedCoupon}
                      />
                    </div>
                    {appliedCoupon ? (
                      <button
                        type="button"
                        onClick={() => { setAppliedCoupon(null); setCouponCode('') }}
                        className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                        aria-label="Remove coupon"
                      >
                        <XMarkIcon className="w-5 h-5" />
                      </button>
                    ) : (
                      <button
                        type="button"
                        onClick={() => couponCode && validateCoupon(couponCode)}
                        disabled={couponLoading || !couponCode}
                        className="px-3 py-2 text-sm font-medium bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                      >
                        {couponLoading ? <LoadingSpinner size="sm" /> : 'Apply'}
                      </button>
                    )}
                  </div>
                  {appliedCoupon && (
                    <div className="mt-2 flex items-center gap-1.5 text-xs text-green-700 bg-green-50 px-2.5 py-1.5 rounded-lg">
                      <CheckIcon className="w-3.5 h-3.5 flex-shrink-0" />
                      <span className="font-medium">{appliedCoupon.code}</span>
                      <span>—</span>
                      <span>{appliedCoupon.discount_type === 'percentage' ? `${appliedCoupon.discount_value}%` : formatPrice(appliedCoupon.discount_value)} off</span>
                    </div>
                  )}
                </div>

                {/* Coupon Discount Line */}
                {appliedCoupon && (
                  <div className="flex justify-between text-sm text-green-700 font-medium">
                    <span>Coupon ({appliedCoupon.code})</span>
                    <span>-{formatPrice(couponDiscount)}</span>
                  </div>
                )}

                <div className="flex justify-between font-semibold text-lg border-t pt-2">
                  <span>Total</span>
                  <span className="text-green-600">{formatPrice(total + subtotal * 0.02)}</span>
                </div>
              </div>
            </Card>
          </div>
        </div>
      </form>
    </div>
  )
}

