import { useState, useEffect, useCallback } from 'react'
import { useSearchParams } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { supabase } from '@/services/supabase'
import { sanitizePostgRESTFilter } from '@/utils/sanitization'
import { ProductCard } from '@/components/ui'
import ErrorBoundary from '@/components/ErrorBoundary'
import { MagnifyingGlassIcon, FunnelIcon, XMarkIcon, ChevronLeftIcon, ChevronRightIcon } from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'
import { logger } from '@/utils/logger'

const ITEMS_PER_PAGE = 12

const MarketplacePage = () => {
  const { t } = useTranslation()
  const [searchParams, setSearchParams] = useSearchParams()
  const [loading, setLoading] = useState(true)
  const [products, setProducts] = useState([])
  const [filtersOpen, setFiltersOpen] = useState(false)
  const [totalCount, setTotalCount] = useState(0)
  const [currentPage, setCurrentPage] = useState(parseInt(searchParams.get('page') || '1'))
  const [searchTimeout, setSearchTimeout] = useState(null)

  // Helper to get initial filters from URL
  const getInitialFilters = () => ({
    search: searchParams.get('search') || '',
    category: searchParams.get('category') || 'all',
    region: searchParams.get('region') || 'all',
    minPrice: searchParams.get('minPrice') || '',
    maxPrice: searchParams.get('maxPrice') || '',
    sortBy: searchParams.get('sortBy') || 'newest',
  })

  const [filters, setFilters] = useState(getInitialFilters)

  const [availableRegions, setAvailableRegions] = useState([])

  // Sync filters when URL changes (browser back/forward navigation)
  useEffect(() => {
    const newFilters = getInitialFilters()
    setFilters(newFilters)
    setCurrentPage(parseInt(searchParams.get('page') || '1'))
  }, [searchParams])

  // Load products when filters or page changes
  useEffect(() => {
    loadProducts()
  }, [currentPage, filters])

  // Load all available regions from vendor profiles
  useEffect(() => {
    loadRegions()
  }, [])

  // Cleanup search timeout on unmount
  useEffect(() => {
    return () => {
      if (searchTimeout) clearTimeout(searchTimeout)
    }
  }, [searchTimeout])

  const loadRegions = async () => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('city')
        .eq('role', 'vendor')
        .not('city', 'is', null)

      if (error) throw error

      const uniqueCities = [...new Set(data.map(p => p.city).filter(Boolean))]
      setAvailableRegions(['all', ...uniqueCities.sort()])
    } catch (error) {
      logger.error('Error loading regions:', error)
    }
  }

  const loadProducts = async () => {
    setLoading(true)
    try {
      let query = supabase
        .from('products')
        .select(`
          *,
          product_images(url, is_primary)
        `, { count: 'exact', head: false })
        .eq('is_available', true)
        .eq('approval_status', 'approved') // Only show admin-approved products

      // Apply category filter
      if (filters.category !== 'all') {
        query = query.eq('category', filters.category)
      }

      // Note: Region filtering would require a separate query to profiles table
      // For now, we'll remove this filter as it needs vendor data
      // TODO: Implement proper region filtering after fetching vendor data

      // Apply price range filters
      if (filters.minPrice) {
        query = query.gte('price_per_unit', parseFloat(filters.minPrice))
      }
      if (filters.maxPrice) {
        query = query.lte('price_per_unit', parseFloat(filters.maxPrice))
      }

      // Apply search filter
      if (filters.search) {
        query = query.or(`name.ilike.%${sanitizePostgRESTFilter(filters.search)}%,description.ilike.%${sanitizePostgRESTFilter(filters.search)}%`)
      }

      // Apply sorting
      switch (filters.sortBy) {
        case 'priceLow':
          query = query.order('price_per_unit', { ascending: true })
          break
        case 'priceHigh':
          query = query.order('price_per_unit', { ascending: false })
          break
        case 'name':
          query = query.order('name', { ascending: true })
          break
        case 'newest':
        default:
          query = query.order('created_at', { ascending: false })
          break
      }

      // Apply pagination
      const from = (currentPage - 1) * ITEMS_PER_PAGE
      const to = from + ITEMS_PER_PAGE - 1
      query = query.range(from, to)

      const { data, error, count } = await query

      if (error) {
        logger.error('Error fetching products:', error)
        toast.error('Failed to load products. Please try again.')
        setProducts([])
        setTotalCount(0)
        return
      }

      setProducts(data || [])
      setTotalCount(count || 0)
    } catch (error) {
      logger.error('Error loading products:', error)
      toast.error('Failed to load products')
      setProducts([])
      setTotalCount(0)
    } finally {
      setLoading(false)
    }
  }

  const updateFilters = (newFilters) => {
    const updated = { ...filters, ...newFilters }
    setFilters(updated)
    setCurrentPage(1) // Reset to first page when filters change

    const params = new URLSearchParams()
    if (updated.search) params.set('search', updated.search)
    if (updated.category !== 'all') params.set('category', updated.category)
    if (updated.region !== 'all') params.set('region', updated.region)
    if (updated.minPrice) params.set('minPrice', updated.minPrice)
    if (updated.maxPrice) params.set('maxPrice', updated.maxPrice)
    if (updated.sortBy !== 'newest') params.set('sortBy', updated.sortBy)
    // page param will be reset to 1 (deleted from URL)
    setSearchParams(params)
    // loadProducts will be called by useEffect when filters change
  }

  // Debounced search handler
  const handleSearchChange = useCallback((e) => {
    const value = e.target.value
    setFilters(prev => ({ ...prev, search: value }))

    // Clear previous timeout
    if (searchTimeout) clearTimeout(searchTimeout)

    // Set new timeout to debounce search
    const timeout = setTimeout(() => {
      const params = new URLSearchParams(searchParams)
      if (value) params.set('search', value)
      else params.delete('search')
      params.delete('page') // Reset to page 1
      setSearchParams(params)
      setCurrentPage(1)
      // loadProducts will be called by useEffect
    }, 500) // 500ms debounce

    setSearchTimeout(timeout)
  }, [searchParams, setSearchParams, searchTimeout])

  const clearFilters = () => {
    setFilters({
      search: '',
      category: 'all',
      region: 'all',
      minPrice: '',
      maxPrice: '',
      sortBy: 'newest',
    })
    setCurrentPage(1)
    setSearchParams({})
    // loadProducts will be called by useEffect
  }

  const categories = [
    { id: 'all', label: t('marketplace.categories.all', 'All Categories') },
    { id: 'plants', label: t('marketplace.categories.plants', 'Plants & Trees') },
    { id: 'vegetables', label: t('marketplace.categories.vegetables', 'Vegetables') },
    { id: 'fruits', label: t('marketplace.categories.fruits', 'Fruits') },
    { id: 'herbs', label: t('marketplace.categories.herbs', 'Herbs & Spices') },
    { id: 'seeds', label: t('marketplace.categories.seeds', 'Seeds & Bulbs') },
  ]

  // Use pre-loaded regions instead of computing from current page products
  const uniqueRegions = availableRegions

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-2xl sm:text-3xl font-bold text-gray-900 mb-2">
          {t('marketplace.title', 'Marketplace')}
        </h1>
        <p className="text-gray-600">{t('marketplace.subtitle', 'Find wholesale plants, vegetables, and fruits')}</p>
      </div>

      {/* Search Bar */}
      <div className="mb-6">
        <div className="relative">
          <MagnifyingGlassIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          <input
            type="text"
            placeholder={t('marketplace.searchPlaceholder', 'Search products...')}
            value={filters.search}
            onChange={handleSearchChange}
            className="input pl-12 pr-4 py-3 text-base"
            aria-label={t('marketplace.searchLabel', 'Search products')}
            aria-describedby="search-help"
            id="search-input"
          />
        </div>
        <span id="search-help" className="sr-only">
          {t('marketplace.searchHelp', 'Type to search for products by name or description')}
        </span>
      </div>

      {/* Category Tabs */}
      <div className="mb-6 overflow-x-auto scrollbar-thin" role="tablist" aria-label={t('marketplace.categoryTabs', 'Product categories')}>
        <div className="flex gap-2 pb-2">
          {categories.map((cat) => (
            <button
              key={cat.id}
              onClick={() => updateFilters({ category: cat.id })}
              role="tab"
              aria-selected={filters.category === cat.id}
              aria-controls="products-grid"
              className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                filters.category === cat.id
                  ? 'bg-green-500 text-white'
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              }`}
            >
              {cat.label}
            </button>
          ))}
        </div>
      </div>

      <div className="flex gap-8">
        {/* Filters Sidebar (Desktop) */}
        <aside className="hidden lg:block w-64 flex-shrink-0" aria-label={t('marketplace.filtersLabel', 'Filters')}>
          <div className="sticky top-24 space-y-6">
            <div className="flex items-center justify-between">
              <h3 className="font-semibold text-gray-900">{t('marketplace.filtersLabel', 'Filters')}</h3>
              <button 
                onClick={clearFilters} 
                className="text-sm text-green-600 hover:underline"
                aria-label={t('marketplace.clearAllFilters', 'Clear all filters')}
              >
                {t('marketplace.clearAll', 'Clear all')}
              </button>
            </div>

            {/* Region Filter */}
            <div>
              <label htmlFor="region-select" className="input-label">{t('marketplace.region', 'Region')}</label>
              <select
                id="region-select"
                value={filters.region}
                onChange={(e) => updateFilters({ region: e.target.value })}
                className="input"
                disabled={loading}
              >
                {uniqueRegions.map(region => (
                  <option key={region} value={region}>
                    {region === 'all' ? t('marketplace.allRegions', 'All Regions') : region}
                  </option>
                ))}
              </select>
            </div>

            {/* Price Range */}
            <div>
              <label className="input-label">{t('marketplace.priceRange', 'Price Range')}</label>
              <div className="grid grid-cols-2 gap-3">
                <input
                  type="number"
                  placeholder={t('marketplace.min', 'Min')}
                  value={filters.minPrice}
                  onChange={(e) => { const val = e.target.value; if (val === '' || parseFloat(val) >= 0) updateFilters({ minPrice: val }) }}
                  min="0"
                  className="input"
                  disabled={loading}
                  aria-label={t('marketplace.minPrice', 'Minimum price')}
                />
                <input
                  type="number"
                  placeholder={t('marketplace.max', 'Max')}
                  value={filters.maxPrice}
                  onChange={(e) => { const val = e.target.value; if (val === '' || parseFloat(val) >= 0) updateFilters({ maxPrice: val }) }}
                  min="0"
                  className="input"
                  disabled={loading}
                  aria-label={t('marketplace.maxPrice', 'Maximum price')}
                />
              </div>
            </div>

            {/* Sort */}
            <div>
              <label htmlFor="sort-select" className="input-label">{t('marketplace.sortByLabel', 'Sort By')}</label>
              <select
                id="sort-select"
                value={filters.sortBy}
                onChange={(e) => updateFilters({ sortBy: e.target.value })}
                className="input"
                disabled={loading}
              >
                <option value="newest">{t('marketplace.sort.newest', 'Newest First')}</option>
                <option value="priceLow">{t('marketplace.sort.priceLow', 'Price: Low to High')}</option>
                <option value="priceHigh">{t('marketplace.sort.priceHigh', 'Price: High to Low')}</option>
                <option value="name">{t('marketplace.sort.name', 'Name: A to Z')}</option>
              </select>
            </div>
          </div>
        </aside>

        {/* Mobile Filters Button */}
        <button
          onClick={() => setFiltersOpen(!filtersOpen)}
          className="lg:hidden fixed bottom-20 right-4 z-30 p-3 bg-green-500 text-white rounded-full shadow-lg"
          aria-label={t('marketplace.openFilters', 'Open filters')}
          aria-expanded={filtersOpen}
          aria-controls="mobile-filters-panel"
        >
          <FunnelIcon className="w-6 h-6" />
        </button>

        {/* Mobile Filters Panel */}
        {filtersOpen && (
          <div 
            className="lg:hidden fixed inset-0 z-40"
            role="dialog"
            aria-modal="true"
            aria-label={t('marketplace.filtersPanel', 'Filter options')}
            id="mobile-filters-panel"
          >
            <button
              type="button"
              className="absolute inset-0 bg-black/50"
              onClick={() => setFiltersOpen(false)}
              aria-label={t('common.close', 'Close')}
            />
            <div className="absolute bottom-0 left-0 right-0 bg-white rounded-t-2xl p-6 max-h-[80vh] overflow-y-auto">
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-semibold" id="mobile-filters-title">
                  {t('marketplace.filters', 'Filters')}
                </h3>
                <button 
                  onClick={() => setFiltersOpen(false)}
                  aria-label={t('common.close', 'Close')}
                >
                  <XMarkIcon className="w-6 h-6" />
                </button>
              </div>

              <div className="space-y-4">
                <div>
                  <label htmlFor="mobile-region" className="input-label">{t('marketplace.region', 'Region')}</label>
                  <select id="mobile-region" value={filters.region} onChange={(e) => updateFilters({ region: e.target.value })} className="input">
                    {uniqueRegions.map(region => (
                      <option key={region} value={region}>
                        {region === 'all' ? t('marketplace.allRegions', 'All Regions') : region}
                      </option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="input-label">{t('marketplace.priceRange', 'Price Range')}</label>
                  <div className="grid grid-cols-2 gap-3">
                    <input type="number" placeholder={t('marketplace.min', 'Min')} value={filters.minPrice} onChange={(e) => { const val = e.target.value; if (val === '' || parseFloat(val) >= 0) updateFilters({ minPrice: val }) }} min="0" className="input" aria-label={t('marketplace.minPrice', 'Minimum price')} />
                    <input type="number" placeholder={t('marketplace.max', 'Max')} value={filters.maxPrice} onChange={(e) => { const val = e.target.value; if (val === '' || parseFloat(val) >= 0) updateFilters({ maxPrice: val }) }} min="0" className="input" aria-label={t('marketplace.maxPrice', 'Maximum price')} />
                  </div>
                </div>
                <div>
                  <label htmlFor="mobile-sort" className="input-label">{t('marketplace.sortBy', 'Sort By')}</label>
                  <select id="mobile-sort" value={filters.sortBy} onChange={(e) => updateFilters({ sortBy: e.target.value })} className="input">
                    <option value="newest">{t('marketplace.sort.newest', 'Newest First')}</option>
                    <option value="priceLow">{t('marketplace.sort.priceLow', 'Price: Low to High')}</option>
                    <option value="priceHigh">{t('marketplace.sort.priceHigh', 'Price: High to Low')}</option>
                    <option value="name">{t('marketplace.sort.name', 'Name: A to Z')}</option>
                  </select>
                </div>
                <button onClick={() => setFiltersOpen(false)} className="btn-primary w-full">
                  {t('marketplace.showResults', 'Show {{count}} results', { count: totalCount })}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Products Grid */}
        <div className="flex-1">
          {loading ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6" id="products-grid" role="tabpanel" aria-label={t('marketplace.productsGrid', 'Products list')}>
              {[...Array(6)].map((_, i) => (
                <div key={i} className="card animate-pulse">
                  <div className="aspect-square bg-gray-200"></div>
                  <div className="p-4 space-y-3">
                    <div className="h-4 bg-gray-200 rounded w-3/4"></div>
                    <div className="h-3 bg-gray-200 rounded w-1/2"></div>
                    <div className="h-6 bg-gray-200 rounded w-1/3"></div>
                  </div>
                </div>
              ))}
            </div>
          ) : products.length > 0 || totalCount > 0 ? (
            <>
              <p className="text-sm text-gray-500 mb-4">
                {t('marketplace.showingResults', 'Showing {{current}} of {{total}} products', {
                  current: products.length,
                  total: totalCount
                })}
              </p>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6" id="products-grid" role="tabpanel" aria-label={t('marketplace.productsGrid', 'Products list')}>
                {products.map((product) => (
                  <ProductCard key={product.id} product={product} />
                ))}
              </div>

              {/* Pagination */}
              {totalCount > ITEMS_PER_PAGE && (
                <nav className="mt-8 flex items-center justify-center gap-2" aria-label={t('marketplace.pagination', 'Product pagination')}>
                  <button
                    onClick={() => {
                      const newPage = Math.max(1, currentPage - 1)
                      setCurrentPage(newPage)
                      const params = new URLSearchParams(searchParams)
                      if (newPage === 1) params.delete('page')
                      else params.set('page', newPage)
                      setSearchParams(params)
                      window.scrollTo({ top: 0, behavior: 'smooth' })
                    }}
                    disabled={currentPage === 1}
                    className="p-2 rounded-lg border border-gray-300 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100"
                    aria-label={t('marketplace.previousPage', 'Previous page')}
                  >
                    <ChevronLeftIcon className="w-5 h-5" />
                  </button>

                  {Array.from({ length: Math.min(5, Math.ceil(totalCount / ITEMS_PER_PAGE)) }, (_, i) => {
                    const totalPages = Math.ceil(totalCount / ITEMS_PER_PAGE)
                    let pageNum

                    if (totalPages <= 5) {
                      pageNum = i + 1
                    } else if (currentPage <= 3) {
                      pageNum = i + 1
                    } else if (currentPage >= totalPages - 2) {
                      pageNum = totalPages - 4 + i
                    } else {
                      pageNum = currentPage - 2 + i
                    }

                    return (
                      <button
                        key={pageNum}
                        onClick={() => {
                          setCurrentPage(pageNum)
                          const params = new URLSearchParams(searchParams)
                          params.set('page', pageNum)
                          setSearchParams(params)
                          window.scrollTo({ top: 0, behavior: 'smooth' })
                        }}
                        className={`w-10 h-10 rounded-lg font-medium transition-colors ${
                          currentPage === pageNum
                            ? 'bg-green-600 text-white'
                            : 'border border-gray-300 hover:bg-gray-100'
                        }`}
                        aria-label={t('marketplace.pageNumber', 'Page {{num}}', { num: pageNum })}
                        aria-current={currentPage === pageNum ? 'page' : undefined}
                      >
                        {pageNum}
                      </button>
                    )
                  })}

                  <button
                    onClick={() => {
                      const newPage = Math.min(Math.ceil(totalCount / ITEMS_PER_PAGE), currentPage + 1)
                      setCurrentPage(newPage)
                      const params = new URLSearchParams(searchParams)
                      params.set('page', newPage)
                      setSearchParams(params)
                      window.scrollTo({ top: 0, behavior: 'smooth' })
                    }}
                    disabled={currentPage >= Math.ceil(totalCount / ITEMS_PER_PAGE)}
                    className="p-2 rounded-lg border border-gray-300 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100"
                    aria-label={t('marketplace.nextPage', 'Next page')}
                  >
                    <ChevronRightIcon className="w-5 h-5" />
                  </button>
                </nav>
              )}
            </>
          ) : (
            <div className="text-center py-16">
              <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <MagnifyingGlassIcon className="w-12 h-12 text-gray-400" />
              </div>
              <h3 className="text-lg font-semibold text-gray-900 mb-2">
                {t('marketplace.empty.title', 'No products found')}
              </h3>
              <p className="text-gray-500 mb-4">
                {t('marketplace.empty.description', 'Try adjusting your filters or search terms')}
              </p>
              <button onClick={clearFilters} className="btn-primary">
                {t('marketplace.empty.clearFilters', 'Clear Filters')}
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

