    case 'order_update':
      return { icon: ShoppingBagIcon, color: 'text-blue-600', bg: 'bg-blue-100' }
    case 'payment':
      return { icon: BanknotesIcon, color: 'text-green-600', bg: 'bg-green-100' }
    case 'system':
