// ============================================================
// HELPER: Update navbar badge
// ============================================================
const updateNotificationBadge = (unreadCount) => {
  window.dispatchEvent(new CustomEvent('notification-badge-update', {
    detail: { unreadCount }
  }))
}

// ============================================================
// HELPER: Group notifications by date
// ============================================================
const groupByDate = (notifications) => {
  const groups = {}
  const today = new Date()
  const yesterday = new Date(today)
  yesterday.setDate(yesterday.getDate() - 1)
  const weekAgo = new Date(today)
  weekAgo.setDate(weekAgo.getDate() - 7)

  notifications.forEach(notification => {
    const date = new Date(notification.created_at)
    let label

    if (date.toDateString() === today.toDateString()) {
      label = 'Today'
    } else if (date.toDateString() === yesterday.toDateString()) {
      label = 'Yesterday'
    } else if (date > weekAgo) {
      label = 'This Week'
    } else {
      label = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
    }

    if (!groups[label]) groups[label] = []
    groups[label].push(notification)
  })

  return groups
}

const Notifications = () => {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { user } = useAuthStore()
  const [notifications, setNotifications] = useState([])
  const [loading, setLoading] = useState(true)
  const [loadingMore, setLoadingMore] = useState(false)
  const [actionLoading, setActionLoading] = useState(null)
  const [page, setPage] = useState(1)
  const [hasMore, setHasMore] = useState(true)
  const [filter, setFilter] = useState('all')
  const observerTarget = useRef(null)

  useEffect(() => {
    if (user) {
      loadNotifications()
      realtimeService.initialize()
    }
  }, [user])

  // Realtime subscription for new notifications
  useEffect(() => {
    if (!user?.id) return

    const unsubscribe = realtimeService.subscribeToNotifications(
      user.id,
      (payload) => {
        logger.info('New notification received:', payload)

        // SECURITY: Check if notification already exists to prevent duplicates
        setNotifications(prev => {
          const exists = prev.some(n => n.id === payload.new.id)
          if (exists) return prev
          return [payload.new, ...prev]
        })

        // Update badge count
        setNotifications(prev => {
          const updated = [payload.new, ...prev]
          const unreadCount = updated.filter(n => !n.is_read).length
          updateNotificationBadge(unreadCount)
          return updated
        })
      }
    )

    return () => unsubscribe()
  }, [user?.id])

  // Infinite scroll with IntersectionObserver
  useEffect(() => {
    const observer = new IntersectionObserver(
      entries => {
        if (entries[0].isIntersecting && hasMore && !loadingMore) {
          loadNotifications(page + 1, true)
        }
      },
      { threshold: 0.1 }
    )

    if (observerTarget.current) {
      observer.observe(observerTarget.current)
    }

    return () => observer.disconnect()
  }, [hasMore, loadingMore, page])

  const loadNotifications = useCallback(async (pageNum = 1, append = false) => {
    try {
      if (!append) setLoading(true)
      else setLoadingMore(true)

      const from = (pageNum - 1) * NOTIFICATIONS_PER_PAGE
      const to = from + NOTIFICATIONS_PER_PAGE - 1

      let query = supabase
        .from('notifications')
        .select('*', { count: 'exact' })
        .eq('user_id', user?.id)
        .order('created_at', { ascending: false })
        .range(from, to)

      // Apply filter if not 'all'
      if (filter !== 'all') {
        query = query.eq('type', filter)
      }

      const { data, error, count } = await query

      if (error) throw error

      if (append) {
        setNotifications(prev => [...prev, ...(data || [])])
        setHasMore(data?.length === NOTIFICATIONS_PER_PAGE)
        setPage(pageNum)
      } else {
        setNotifications(data || [])
        setHasMore(data?.length === NOTIFICATIONS_PER_PAGE)
        setPage(1)
      }

      // Update badge count
      const allNotifications = append ? [...notifications, ...(data || [])] : (data || [])
      const unreadCount = allNotifications.filter(n => !n.is_read).length
      updateNotificationBadge(unreadCount)
    } catch (error) {
      logger.error('Error loading notifications:', error)
    } finally {
      setLoading(false)
      setLoadingMore(false)
    }
  }, [user?.id, filter, notifications])

  // Reload when filter changes
  useEffect(() => {
    if (user) {
      loadNotifications(1, false)
    }
  }, [filter])

  const markAsRead = async (id) => {
    setActionLoading(id)
    try {
      const { error } = await supabase
        .from('notifications')
        .update({ is_read: true })
        .eq('id', id)

      if (error) throw error

      setNotifications(prev => {
        const updated = prev.map(n => n.id === id ? { ...n, is_read: true } : n)
        const unreadCount = updated.filter(n => !n.is_read).length
        updateNotificationBadge(unreadCount)
        return updated
      })
    } catch (error) {
      logger.error('Mark as read error:', error)
      toast.error(t('notifications.errors.markAsReadFailed', 'Failed to mark as read'))
    } finally {
      setActionLoading(null)
    }
  }

  const deleteNotification = async (id) => {
    setActionLoading(id)
    try {
      const { error } = await supabase
        .from('notifications')
        .delete()
        .eq('id', id)

      if (error) throw error

      setNotifications(prev => {
        const updated = prev.filter(n => n.id !== id)
        const unreadCount = updated.filter(n => !n.is_read).length
        updateNotificationBadge(unreadCount)
        return updated
      })
      toast.success(t('notifications.deleted', 'Notification deleted'))
    } catch (error) {
      logger.error('Delete notification error:', error)
      toast.error(t('notifications.errors.deleteFailed', 'Failed to delete notification'))
    } finally {
      setActionLoading(null)
    }
  }

  const markAllAsRead = async () => {
    try {
      const { error } = await supabase
        .from('notifications')
        .update({ is_read: true })
        .eq('user_id', user?.id)

      if (error) throw error

      setNotifications(prev => prev.map(n => ({ ...n, is_read: true })))
      updateNotificationBadge(0)
      toast.success(t('notifications.allMarkedRead', 'All notifications marked as read'))
    } catch (error) {
      logger.error('Mark all as read error:', error)
      toast.error(t('notifications.errors.markAllFailed', 'Failed to update notifications'))
    }
  }

  const deleteAllRead = async () => {
    if (!confirm(t('notifications.confirmDeleteRead', 'Are you sure you want to delete all read notifications?'))) return

    try {
      const { error } = await supabase
        .from('notifications')
        .delete()
        .eq('user_id', user?.id)
        .eq('is_read', true)

      if (error) throw error

      setNotifications(prev => {
        const updated = prev.filter(n => !n.is_read)
        updateNotificationBadge(updated.length)
        return updated
      })
      toast.success(t('notifications.allReadDeleted', 'All read notifications deleted'))
    } catch (error) {
      logger.error('Delete all read error:', error)
      toast.error(t('notifications.errors.deleteAllFailed', 'Failed to delete notifications'))
    }
  }

  const handleNotificationClick = (notification) => {
    // Mark as read if not already
    if (!notification.is_read) {
      markAsRead(notification.id)
    }

    // Navigate based on notification type and data
    if (notification.link) {
      navigate(notification.link)
    } else if (notification.type === 'order_update' && notification.order_id) {
      navigate(`/orders/${notification.order_id}`)
    } else if (notification.type === 'message' && notification.conversation_id) {
      navigate(`/messages?conversation=${notification.conversation_id}`)
    } else if (notification.type === 'driver_verification') {
      navigate('/admin/drivers/verification')
    }
  }

  if (!user) {
    navigate('/login', { state: { from: '/notifications' } })
    return null
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  const unreadCount = notifications.filter(n => !n.is_read).length
  const groupedNotifications = groupByDate(notifications)

  // Filter types for tabs
  const filterTypes = [
    { id: 'all', label: t('notifications.filters.all', 'All') },
    { id: 'order_update', label: t('notifications.filters.orders', 'Orders') },
    { id: 'payment', label: t('notifications.filters.payments', 'Payments') },
    { id: 'message', label: t('notifications.filters.messages', 'Messages') },
    { id: 'system', label: t('notifications.filters.system', 'System') },
  ]

  return (
    <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <BellIcon className="w-6 h-6" />
            {t('notifications.title', 'Notifications')}
          </h1>
          {unreadCount > 0 && (
            <p className="text-sm text-gray-500 mt-1">
              {t('notifications.unread', '{{count}} unread', { count: unreadCount })}
            </p>
          )}
        </div>
        <div className="flex gap-3">
          {unreadCount < notifications.length && notifications.length > 0 && (
            <button
              onClick={deleteAllRead}
              className="text-sm text-red-600 hover:underline"
            >
              {t('notifications.deleteAllRead', 'Delete all read')}
            </button>
          )}
          {unreadCount > 0 && (
            <button
              onClick={markAllAsRead}
              className="text-sm text-green-600 hover:underline"
            >
              {t('notifications.markAllRead', 'Mark all as read')}
            </button>
          )}
        </div>
      </div>

      {/* Filter Tabs */}
      <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
        {filterTypes.map(type => (
          <button
            key={type.id}
            onClick={() => setFilter(type.id)}
            className={`px-3 py-1.5 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
              filter === type.id
                ? 'bg-green-500 text-white'
                : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
          >
            {type.label}
          </button>
        ))}
      </div>

      {/* Notifications List */}
      {notifications.length > 0 ? (
        <div className="space-y-6">
          {Object.entries(groupedNotifications).map(([dateLabel, dateNotifications]) => (
            <div key={dateLabel}>
              <h2 className="text-sm font-semibold text-gray-500 mb-3 sticky top-0 bg-gray-50 py-2">
                {dateLabel}
              </h2>
              <div className="space-y-3">
                {dateNotifications.map((notification) => {
                  const { icon: Icon, color, bg } = getNotificationConfig(notification.type)

                  return (
                    <Card
                      key={notification.id}
                      className={`p-4 transition-colors cursor-pointer ${
                        !notification.is_read ? 'bg-green-50 border-green-200' : ''
                      }`}
                      onClick={() => handleNotificationClick(notification)}
                    >
                      <div className="flex items-start gap-3">
                        <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${
                          !notification.is_read ? bg : 'bg-gray-100'
                        }`}>
                          <Icon className={`w-5 h-5 ${!notification.is_read ? color : 'text-gray-400'}`} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className={`text-sm ${!notification.is_read ? 'font-medium text-gray-900' : 'text-gray-600'}`}>
                            {notification.title}
                          </p>
                          <p className="text-xs text-gray-500 mt-1">{notification.message}</p>
                          <p className="text-xs text-gray-400 mt-2">
                            {new Date(notification.created_at).toLocaleString()}
                          </p>
                        </div>
                        <div className="flex items-center gap-1">
                          {!notification.is_read && (
                            <button
                              onClick={(e) => {
                                e.stopPropagation()
                                markAsRead(notification.id)
                              }}
                              disabled={actionLoading === notification.id}
                              className="p-1.5 text-gray-400 hover:text-green-600 hover:bg-green-50 rounded-lg transition-colors disabled:opacity-50"
                              title={t('notifications.markAsRead', 'Mark as read')}
                            >
                              {actionLoading === notification.id ? (
                                <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                                </svg>
                              ) : (
                                <CheckIcon className="w-4 h-4" />
                              )}
                            </button>
                          )}
                          <button
                            onClick={(e) => {
                              e.stopPropagation()
                              deleteNotification(notification.id)
                            }}
                            disabled={actionLoading === notification.id}
                            className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
                            title={t('notifications.delete', 'Delete')}
                          >
                            {actionLoading === notification.id ? (
                              <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                              </svg>
                            ) : (
                              <TrashIcon className="w-4 h-4" />
                            )}
                          </button>
                        </div>
                      </div>
                    </Card>
                  )
                })}
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-16">
          <BellIcon className="w-16 h-16 text-gray-300 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-gray-900 mb-2">
            {t('notifications.empty.title', 'No notifications')}
          </h3>
          <p className="text-gray-500">
            {t('notifications.empty.description', filter !== 'all' ? 'No notifications of this type' : "You're all caught up!")}
          </p>
        </div>
      )}

      {/* Loading more indicator */}
      {loadingMore && (
        <div className="flex justify-center py-4">
          <LoadingSpinner size="sm" />
        </div>
      )}

      {/* Intersection observer target */}
      {hasMore && <div ref={observerTarget} className="h-4" />}

      {/* End of list message */}
      {!hasMore && notifications.length > 0 && (
        <p className="text-center text-sm text-gray-500 py-4">
          {t('notifications.noMore', 'No more notifications')}
        </p>
      )}
    </div>
  )
}

