                    checked={returnItems.includes(item.id)}
                    onChange={(e) => {
                      if (e.target.checked) {
                        setReturnItems((prev) => [...prev, item.id])
                      } else {
                        setReturnItems((prev) => prev.filter((id) => id !== item.id))
                      }
