        ) : (
          <Card className="p-12 text-center">
            <MagnifyingGlassIcon className="w-12 h-12 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-gray-900 mb-2">No products found</h3>
            <p className="text-gray-500 mb-4">
              {productSearch || categoryFilter !== 'all'
                ? 'Try adjusting your filters or search terms'
                : 'This store doesn\'t have any products yet'}
            </p>
            {(productSearch || categoryFilter !== 'all') && (
              <button onClick={clearProductFilters} className="btn-primary">
                Clear Filters
              </button>
            )}
          </Card>
        )}
      </div>

      {/* ===== LOCATION MAP ===== */}
      {(store.latitude || store.longitude || store.city) && (
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pb-12">
          <h2 className="text-xl font-bold text-gray-900 mb-4">Store Location</h2>
          <Card className="overflow-hidden">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-0">
              {/* Location Info */}
              <div className="p-6 bg-gray-50 lg:col-span-1">
                <h3 className="font-semibold text-gray-900 text-lg mb-4">{displayName}</h3>
                <div className="space-y-3">
                  {store.city && (
                    <div className="flex items-start gap-3 text-sm">
                      <MapPinIcon className="w-5 h-5 text-gray-400 flex-shrink-0 mt-0.5" />
                      <div>
                        <p className="text-gray-500">Address</p>
                        <p className="text-gray-900 font-medium">
                          {store.address ? `${store.address}, ` : ''}{store.city}{store.country ? `, ${store.country}` : ''}
                        </p>
                      </div>
                    </div>
                  )}
                  {store.phone && (
                    <div className="flex items-start gap-3 text-sm">
                      <PhoneIcon className="w-5 h-5 text-gray-400 flex-shrink-0 mt-0.5" />
                      <div>
                        <p className="text-gray-500">Phone</p>
                        <a href={`tel:${store.phone}`} className="text-green-600 hover:underline font-medium">
                          {store.phone}
                        </a>
                      </div>
                    </div>
                  )}
                  {store.email && (
                    <div className="flex items-start gap-3 text-sm">
                      <EnvelopeIcon className="w-5 h-5 text-gray-400 flex-shrink-0 mt-0.5" />
                      <div>
                        <p className="text-gray-500">Email</p>
                        <a href={`mailto:${store.email}`} className="text-green-600 hover:underline font-medium">
                          {store.email}
                        </a>
                      </div>
                    </div>
                  )}
                  {/* Open/Closed Status */}
                  <div className="flex items-start gap-3 text-sm">
                    <ClockIcon className="w-5 h-5 text-gray-400 flex-shrink-0 mt-0.5" />
                    <div>
                      <p className="text-gray-500">Status</p>
                      {isVendorOpen === null ? (
                        <p className="text-gray-400 text-sm">Checking...</p>
                      ) : isVendorOpen ? (
                        <p className="text-green-600 font-semibold flex items-center gap-1">
                          <CheckCircleIcon className="w-4 h-4" />
                          Open Now
                        </p>
                      ) : (
                        <p className="text-red-600 font-semibold flex items-center gap-1">
                          <XMarkIcon className="w-4 h-4" />
                          Closed
                        </p>
                      )}
                    </div>
                  </div>
                  {store.business_hours && (
                    <div className="flex items-start gap-3 text-sm">
                      <ClockIcon className="w-5 h-5 text-gray-400 flex-shrink-0 mt-0.5" />
                      <div>
                        <p className="text-gray-500">Business Hours</p>
                        <p className="text-gray-900 font-medium">{store.business_hours}</p>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Map */}
              <div className="lg:col-span-2">
                <Map
                  center={[
                    store.latitude || 33.5731,
                    store.longitude || -7.5898
                  ]}
                  zoom={12}
                  markers={
                    store.latitude && store.longitude
                      ? [{
                          lat: store.latitude,
                          lng: store.longitude,
                          popup: displayName
                        }]
                      : []
                  }
                  height="350px"
                />
              </div>
            </div>
          </Card>
        </div>
      )}

      {/* ===== REVIEWS SECTION ===== */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pb-12">
        <h2 className="text-xl font-bold text-gray-900 mb-6">
          Reviews
          <span className="text-gray-400 font-normal ml-1">({totalReviews})</span>
        </h2>

        {/* Rating Summary */}
        <Card className="p-6 mb-6">
          <div className="flex flex-col sm:flex-row sm:items-center gap-4">
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 bg-yellow-50 rounded-full flex items-center justify-center">
                <span className="text-3xl font-bold text-yellow-500">
                  {averageRating > 0 ? averageRating.toFixed(1) : '—'}
                </span>
              </div>
              <div>
                <SimpleRating rating={averageRating} size="lg" />
                <p className="text-sm text-gray-500 mt-1">
                  {totalReviews} {totalReviews === 1 ? 'review' : 'reviews'}
                </p>
              </div>
            </div>
          </div>
        </Card>

        {/* Write Review */}
        {user ? (
          <Card className="p-6 mb-6">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Write a Review</h3>
            <div className="mb-4">
              <p className="block text-sm font-medium text-gray-700 mb-2">Rating</p>
              <StarRating
                rating={userRating}
                size="lg"
                onRate={(rating) => setUserRating(rating)}
              />
            </div>
            <div className="mb-4">
              <label htmlFor="store-review-text" className="block text-sm font-medium text-gray-700 mb-2">
                Your Review (optional)
              </label>
              <textarea
                id="store-review-text"
                value={reviewText}
                onChange={(e) => setReviewText(e.target.value)}
                rows={3}
                className="w-full px-4 py-2 border border-gray-300 rounded-xl focus:ring-2 focus:ring-green-500 focus:border-transparent resize-none"
                placeholder="Share your experience with this store..."
              />
            </div>
            <button
              onClick={handleSubmitReview}
              disabled={submittingReview || userRating === 0}
              className="btn-primary disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {submittingReview ? 'Submitting...' : 'Submit Review'}
            </button>
          </Card>
        ) : (
          <Card className="p-6 mb-6 bg-blue-50 border-blue-200 text-center">
            <p className="text-blue-800">
              Please{' '}
              <Link to="/login" className="font-semibold underline hover:text-blue-600">
                login
              </Link>
              {' '}to write a review
            </p>
          </Card>
        )}

        {/* Reviews List */}
        <div className="space-y-4">
          {reviews.length === 0 ? (
            <Card className="p-12 text-center">
              <ChatBubbleLeftRightIcon className="w-12 h-12 text-gray-300 mx-auto mb-4" />
              <h3 className="text-lg font-semibold text-gray-900 mb-2">No reviews yet</h3>
              <p className="text-gray-500">Be the first to review this store</p>
            </Card>
          ) : (
            reviews.map((review) => (
              <Card key={review.id} className="p-6">
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center flex-shrink-0">
                      <span className="text-white font-bold text-sm">
                        {review.reviewer?.first_name?.[0]}{review.reviewer?.last_name?.[0] || 'U'}
                      </span>
                    </div>
                    <div>
                      <p className="font-medium text-gray-900">
                        {review.reviewer ? `${review.reviewer.first_name} ${review.reviewer.last_name}` : 'User'}
                      </p>
                      <p className="text-xs text-gray-500">
                        {new Date(review.created_at).toLocaleDateString('en-US', {
                          year: 'numeric',
                          month: 'short',
                          day: 'numeric'
                        })}
                      </p>
                    </div>
                  </div>
                  <StarRating rating={review.rating} size="sm" />
                </div>
                {review.comment && (
                  <p className="text-gray-600 leading-relaxed">{review.comment}</p>
                )}
              </Card>
            ))
          )}
        </div>
      </div>
    </div>
  )
}

// Wrap with Error Boundary to prevent page crashes
const StoreDetailWithErrorBoundary = () => (
  <ErrorBoundary componentName="StoreDetailPage">
    <StoreDetail />
  </ErrorBoundary>
)

export default StoreDetailWithErrorBoundary

import { useState, useEffect, useMemo, useCallback } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { supabase } from '@/services/supabase'
import { Card, LoadingSpinner, SimpleRating } from '@/components/ui'
import ErrorBoundary from '@/components/ErrorBoundary'
import {
  MagnifyingGlassIcon,
  MapPinIcon,
  AdjustmentsHorizontalIcon,
  XMarkIcon,
  CheckBadgeIcon,
  ArrowTopRightOnSquareIcon,
} from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'
import { logger } from '@/utils/logger'

const SPECIALTY_OPTIONS = [
  { id: 'plants', label: 'Plants', emoji: '🌿' },
  { id: 'vegetables', label: 'Vegetables', emoji: '🥬' },
  { id: 'fruits', label: 'Fruits', emoji: '🍎' },
  { id: 'herbs', label: 'Herbs', emoji: '🌱' },
  { id: 'seeds', label: 'Seeds', emoji: '🌰' },
]

const SORT_OPTIONS = [
  { id: 'newest', label: 'Newest First' },
  { id: 'oldest', label: 'Oldest First' },
  { id: 'highest_rated', label: 'Highest Rated' },
  { id: 'most_reviewed', label: 'Most Reviewed' },
]

const Stores = () => {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [searchParams, setSearchParams] = useSearchParams()
  const [stores, setStores] = useState([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState(searchParams.get('search') || '')
  const [cityFilter, setCityFilter] = useState(searchParams.get('city') || '')
  const [categoryFilter, setCategoryFilter] = useState(searchParams.get('category') || '')
  const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'newest')
  const [storeRatings, setStoreRatings] = useState({})
  const [storeCategories, setStoreCategories] = useState({})
  const [filtersOpen, setFiltersOpen] = useState(false)
  const [error, setError] = useState(null)
  const [searchTimeout, setSearchTimeout] = useState(null)

  // Update URL when filters change
  useEffect(() => {
    const params = new URLSearchParams()
    if (search) params.set('search', search)
    if (cityFilter) params.set('city', cityFilter)
    if (categoryFilter) params.set('category', categoryFilter)
    if (sortBy !== 'newest') params.set('sort', sortBy)
    setSearchParams(params)
  }, [search, cityFilter, categoryFilter, sortBy])

  // Sync from URL changes (browser back/forward)
  useEffect(() => {
    setSearch(searchParams.get('search') || '')
    setCityFilter(searchParams.get('city') || '')
    setCategoryFilter(searchParams.get('category') || '')
    setSortBy(searchParams.get('sort') || 'newest')
  }, [searchParams])

  // Cleanup search timeout on unmount
  useEffect(() => {
    return () => {
      if (searchTimeout) clearTimeout(searchTimeout)
    }
  }, [searchTimeout])

  useEffect(() => {
    loadStores()
  }, [])

  const loadStores = async () => {
    setLoading(true)
    setError(null)
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('role', 'vendor')
        .order('created_at', { ascending: false })

      if (error) throw error
      setStores(data || [])

      // Batch fetch ratings and categories (NOT N+1!)
      if (data && data.length > 0) {
        const vendorIds = data.map(s => s.id)

        // Fetch all reviews at once
        const { data: allReviews } = await supabase
          .from('reviews')
          .select('vendor_id, rating')
          .in('vendor_id', vendorIds)

        // Fetch all product categories at once
        const { data: allProducts } = await supabase
          .from('products')
          .select('vendor_id, category')
          .in('vendor_id', vendorIds)
          .eq('is_available', true)

        // Process reviews into ratings
        const ratings = {}
        vendorIds.forEach(id => { ratings[id] = { average: 0, count: 0 } })

        if (allReviews && allReviews.length > 0) {
          const grouped = allReviews.reduce((acc, r) => {
            if (!acc[r.vendor_id]) acc[r.vendor_id] = []
            acc[r.vendor_id].push(r.rating)
            return acc
          }, {})

          Object.entries(grouped).forEach(([vendorId, ratingsList]) => {
            ratings[vendorId] = {
              average: ratingsList.reduce((a, b) => a + b, 0) / ratingsList.length,
              count: ratingsList.length
            }
          })
        }

        // Process products into categories
        const categories = {}
        vendorIds.forEach(id => { categories[id] = [] })

        if (allProducts && allProducts.length > 0) {
          const grouped = allProducts.reduce((acc, p) => {
            if (!acc[p.vendor_id]) acc[p.vendor_id] = new Set()
            acc[p.vendor_id].add(p.category)
            return acc
          }, {})

          Object.entries(grouped).forEach(([vendorId, catSet]) => {
            categories[vendorId] = [...catSet]
          })
        }

        setStoreRatings(ratings)
        setStoreCategories(categories)
      }
    } catch (error) {
      logger.error('Error loading stores:', error)
      setError('Failed to load stores. Please try again.')
      toast.error('Failed to load stores')
    } finally {
      setLoading(false)
    }
  }

  const filteredAndSortedStores = useMemo(() => {
    let result = stores.filter(store => {
      const matchesSearch = search === '' ||
        store.store_name?.toLowerCase().includes(search.toLowerCase()) ||
        store.first_name?.toLowerCase().includes(search.toLowerCase()) ||
        store.last_name?.toLowerCase().includes(search.toLowerCase())
      const matchesCity = cityFilter === '' || store.city?.toLowerCase().includes(cityFilter.toLowerCase())
      const matchesCategory = categoryFilter === '' || (storeCategories[store.id] || []).includes(categoryFilter)
      return matchesSearch && matchesCity && matchesCategory
    })

    // Sort
    result.sort((a, b) => {
      switch (sortBy) {
        case 'oldest':
          return new Date(a.created_at) - new Date(b.created_at)
        case 'highest_rated':
          return (storeRatings[b.id]?.average || 0) - (storeRatings[a.id]?.average || 0)
        case 'most_reviewed':
          return (storeRatings[b.id]?.count || 0) - (storeRatings[a.id]?.count || 0)
        case 'newest':
        default:
          return new Date(b.created_at) - new Date(a.created_at)
      }
    })

    return result
  }, [stores, search, cityFilter, categoryFilter, sortBy, storeRatings, storeCategories])

  const cities = useMemo(() => [...new Set(stores.map(s => s.city).filter(Boolean))], [stores])

  const activeSpecialtyTags = useMemo(() => {
    const allCats = new Set(Object.values(storeCategories).flat())
    return SPECIALTY_OPTIONS.filter(opt => allCats.has(opt.id))
  }, [storeCategories])

  const clearAllFilters = () => {
    setSearch('')
    setCityFilter('')
    setCategoryFilter('')
    setSortBy('newest')
  }

  const hasActiveFilters = search || cityFilter || categoryFilter || sortBy !== 'newest'

  // Debounced search handler
  const handleSearchChange = useCallback((e) => {
    const value = e.target.value
    setSearch(value)

    if (searchTimeout) clearTimeout(searchTimeout)

    const timeout = setTimeout(() => {
      // URL update handled by useEffect
    }, 500)

    setSearchTimeout(timeout)
  }, [searchTimeout])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  if (error) {
    return (
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 text-center">
        <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6">
          <XMarkIcon className="w-10 h-10 text-red-400" />
        </div>
