import { useState, useEffect, useRef } from 'react'
import { useTranslation } from 'react-i18next'
import { Card, LoadingSpinner, Map } from '@/components/ui'
import {
  TruckIcon,
  DocumentCheckIcon,
  ClockIcon,
  UserGroupIcon,
  CheckCircleIcon,
  XCircleIcon,
  MapPinIcon,
  EyeIcon,
  PhoneIcon,
  EnvelopeIcon,
} from '@heroicons/react/24/outline'
import { Link } from 'react-router-dom'
import { supabase } from '@/services/supabase'
import { logger } from '@/utils/logger'
import toast from 'react-hot-toast'

const AdminDrivers = () => {
  const { t } = useTranslation()
  const channelRef = useRef(null)
  const [loading, setLoading] = useState(true)
  const [drivers, setDrivers] = useState([])
  const [activeDrivers, setActiveDrivers] = useState([])
  const [pendingCount, setPendingCount] = useState(0)
  const [stats, setStats] = useState({
    totalDrivers: 0,
    verifiedDrivers: 0,
    onlineDrivers: 0,
    pendingDocuments: 0,
  })
  const [filter, setFilter] = useState('all') // all, online, verified, unverified
  const [selectedDriver, setSelectedDriver] = useState(null)

  useEffect(() => {
    loadData()
    setupRealtimeTracking()
    return () => cleanupRealtimeTracking()
  }, [])

  const loadData = async () => {
    try {
      // Parallel fetch: drivers, active locations, pending count
      const [driversRes, locationsRes, pendingRes] = await Promise.all([
        supabase
          .from('profiles')
          .select('id, first_name, last_name, email, phone, city, vehicle_type, vehicle_plate, license_verified, insurance_verified, license_expiry_date, insurance_expiry_date, is_available_for_delivery, created_at')
          .eq('role', 'driver')
          .order('created_at', { ascending: false }),
        supabase
          .from('driver_locations')
          .select('driver_id, latitude, longitude, speed_kmh, heading, is_online, last_active_at, accuracy_meters')
          .eq('is_online', true),
        supabase
          .from('driver_verification_documents')
          .select('*', { count: 'exact', head: true })
          .eq('status', 'pending'),
      ])

      if (driversRes.error) throw driversRes.error
      if (locationsRes.error) throw locationsRes.error
      if (pendingRes.error) throw pendingRes.error

      const driversList = driversRes.data || []
      const locationsList = locationsRes.data || []

      // Merge driver data with location data
      const driversWithLocation = driversList.map(driver => {
        const loc = locationsList.find(l => l.driver_id === driver.id)
        return { ...driver, location: loc || null }
      })

      setDrivers(driversWithLocation)
      setActiveDrivers(locationsList)

      const verifiedCount = driversList.filter(d => d.license_verified && d.insurance_verified).length
      setStats({
        totalDrivers: driversList.length,
        verifiedDrivers: verifiedCount,
        onlineDrivers: locationsList.length,
        pendingDocuments: pendingRes.count || 0,
      })
    } catch (error) {
      logger.error('Error loading admin drivers:', error)
      toast.error(t('admin.drivers.notifications.loadFailed', 'Failed to load drivers'))
    } finally {
      setLoading(false)
    }
  }

  // Real-time tracking of driver locations
  const setupRealtimeTracking = () => {
    const channel = supabase
      .channel('admin-driver-locations')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'driver_locations',
        },
        (payload) => {
          if (payload.eventType === 'UPDATE' || payload.eventType === 'INSERT') {
            setActiveDrivers(prev => {
              const idx = prev.findIndex(d => d.driver_id === payload.new.driver_id)
              if (idx >= 0) {
                const updated = [...prev]
                updated[idx] = payload.new
                return updated
              }
              if (payload.new.is_online) {
                return [...prev, payload.new]
              }
              return prev
            })

            // Update driver in main list
            setDrivers(prev =>
              prev.map(d =>
                d.id === payload.new.driver_id
                  ? { ...d, location: payload.new.is_online ? payload.new : null }
                  : d
              )
            )
          } else if (payload.eventType === 'DELETE') {
            setActiveDrivers(prev => prev.filter(d => d.driver_id !== payload.old.driver_id))
          }
        }
      )
      .subscribe()

    channelRef.current = channel
  }

  const cleanupRealtimeTracking = () => {
    if (channelRef.current) {
      supabase.removeChannel(channelRef.current)
    }
  }

  const filteredDrivers = drivers.filter(driver => {
    if (filter === 'online') return driver.location?.is_online
    if (filter === 'verified') return driver.license_verified && driver.insurance_verified
    if (filter === 'unverified') return !driver.license_verified || !driver.insurance_verified
    return true
  })

  const getVerificationStatus = (driver) => {
    if (driver.license_verified && driver.insurance_verified) {
      return { label: t('admin.drivers.verificationStatus.verified', 'Verified'), color: 'bg-green-100 text-green-700', icon: CheckCircleIcon }
    }
    if (driver.license_verified || driver.insurance_verified) {
      return { label: t('admin.drivers.verificationStatus.partial', 'Partial'), color: 'bg-yellow-100 text-yellow-700', icon: ClockIcon }
    }
    return { label: t('admin.drivers.verificationStatus.unverified', 'Unverified'), color: 'bg-red-100 text-red-700', icon: XCircleIcon }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  // Map markers for active drivers
  const mapMarkers = activeDrivers.map(driver => ({
    lat: parseFloat(driver.latitude),
    lng: parseFloat(driver.longitude),
    popup: `Driver ${driver.driver_id?.substring(0, 8) || 'Unknown'}`,
    icon: '🚚',
  }))

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{t('admin.drivers.title', 'Manage Drivers')}</h1>
          <p className="text-gray-500">{t('admin.drivers.subtitle', 'View drivers, verify documents, and track active locations')}</p>
        </div>
        <Link
          to="/admin/drivers/verification"
          className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors font-medium"
        >
          <DocumentCheckIcon className="w-5 h-5" />
          {t('admin.drivers.reviewDocuments', 'Review Documents')} ({stats.pendingDocuments} {t('admin.drivers.stats.pendingDocs', 'pending')})
        </Link>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <Card className="p-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-blue-100 rounded-xl flex items-center justify-center">
              <UserGroupIcon className="w-6 h-6 text-blue-600" />
            </div>
            <div>
              <p className="text-2xl font-bold text-gray-900">{stats.totalDrivers}</p>
              <p className="text-sm text-gray-500">{t('admin.drivers.stats.totalDrivers', 'Total Drivers')}</p>
            </div>
          </div>
        </Card>

        <Card className="p-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-green-100 rounded-xl flex items-center justify-center">
              <CheckCircleIcon className="w-6 h-6 text-green-600" />
            </div>
            <div>
              <p className="text-2xl font-bold text-gray-900">{stats.verifiedDrivers}</p>
              <p className="text-sm text-gray-500">{t('admin.drivers.stats.verified', 'Verified')}</p>
            </div>
          </div>
        </Card>

        <Card className="p-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-cyan-100 rounded-xl flex items-center justify-center">
              <MapPinIcon className="w-6 h-6 text-cyan-600" />
            </div>
            <div>
              <p className="text-2xl font-bold text-gray-900">{stats.onlineDrivers}</p>
              <p className="text-sm text-gray-500">{t('admin.drivers.stats.onlineNow', 'Online Now')}</p>
            </div>
          </div>
        </Card>

        <Link to="/admin/drivers/verification">
          <Card className="p-6 hover:shadow-lg transition-shadow cursor-pointer border-2 border-yellow-200 bg-yellow-50">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-yellow-100 rounded-xl flex items-center justify-center">
                <ClockIcon className="w-6 h-6 text-yellow-600" />
              </div>
              <div>
                <p className="text-2xl font-bold text-yellow-700">{stats.pendingDocuments}</p>
                <p className="text-sm text-yellow-600">{t('admin.drivers.stats.pendingDocs', 'Pending Docs')}</p>
              </div>
            </div>
          </Card>
        </Link>
      </div>

      {/* Active Drivers Map */}
      {activeDrivers.length > 0 ? (
        <Card className="p-6">
          <div className="flex items-center gap-2 mb-4">
            <MapPinIcon className="w-5 h-5 text-green-600" />
            <h3 className="text-lg font-semibold text-gray-900">{t('admin.drivers.map.title', 'Active Drivers Map')}</h3>
            <span className="ml-auto flex items-center gap-1 text-sm text-green-600">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              {activeDrivers.length} {t('admin.drivers.map.online', 'online')}
            </span>
          </div>
          <Map
            center={[33.5731, -7.5898]}
            zoom={12}
            markers={mapMarkers}
            height="400px"
          />
        </Card>
      ) : (
        <Card className="p-12 text-center">
          <MapPinIcon className="w-16 h-16 text-gray-300 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-gray-900 mb-2">{t('admin.drivers.map.noActiveDrivers', 'No Active Drivers')}</h3>
          <p className="text-gray-500">{t('admin.drivers.map.noActiveDriversDesc', 'No drivers are currently online')}</p>
        </Card>
      )}

      {/* Filter Tabs */}
      <div className="flex gap-2 border-b border-gray-200">
        {[
          { key: 'all', label: `${t('admin.drivers.filters.all', 'All')} (${stats.totalDrivers})` },
          { key: 'online', label: `${t('admin.drivers.filters.online', 'Online')} (${stats.onlineDrivers})` },
          { key: 'verified', label: `${t('admin.drivers.filters.verified', 'Verified')} (${stats.verifiedDrivers})` },
          { key: 'unverified', label: `${t('admin.drivers.filters.unverified', 'Unverified')} (${stats.totalDrivers - stats.verifiedDrivers})` },
        ].map(tab => (
          <button
            key={tab.key}
            onClick={() => setFilter(tab.key)}
            className={`px-4 py-2 font-medium text-sm border-b-2 transition-colors ${
              filter === tab.key
                ? 'border-green-600 text-green-600'
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Drivers List */}
      {filteredDrivers.length === 0 ? (
        <Card className="p-12 text-center">
          <TruckIcon className="w-16 h-16 text-gray-300 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-gray-900 mb-2">{t('admin.drivers.noDriversFound', 'No Drivers Found')}</h3>
          <p className="text-gray-500">{t('admin.drivers.noDriversFoundDesc', 'No drivers match the selected filter')}</p>
        </Card>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {filteredDrivers.map(driver => {
            const status = getVerificationStatus(driver)
            const StatusIcon = status.icon
            return (
              <Card key={driver.id} className="p-6">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-3 mb-3">
                      <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center">
                        <TruckIcon className="w-5 h-5 text-gray-600" />
                      </div>
                      <div>
                        <h4 className="font-semibold text-gray-900">
                          {driver.first_name} {driver.last_name}
                        </h4>
                        <div className="flex items-center gap-2">
                          <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium ${status.color}`}>
                            <StatusIcon className="w-3 h-3" />
                            {status.label}
                          </span>
                          {driver.location?.is_online && (
                            <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium bg-cyan-100 text-cyan-700">
                              <span className="w-1.5 h-1.5 bg-cyan-500 rounded-full"></span>
                              {t('admin.drivers.filters.online', 'Online')}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>

                    <div className="space-y-1 text-sm text-gray-600">
                      {driver.email && (
                        <div className="flex items-center gap-2">
                          <EnvelopeIcon className="w-4 h-4 text-gray-400" />
                          <span>{driver.email}</span>
                        </div>
                      )}
                      {driver.phone && (
                        <div className="flex items-center gap-2">
                          <PhoneIcon className="w-4 h-4 text-gray-400" />
                          <span>{driver.phone}</span>
                        </div>
                      )}
                      {driver.vehicle_type && (
                        <div className="flex items-center gap-2">
                          <TruckIcon className="w-4 h-4 text-gray-400" />
                          <span className="capitalize">{driver.vehicle_type}</span>
                          {driver.vehicle_plate && (
                            <span className="text-gray-400">• {driver.vehicle_plate}</span>
                          )}
                        </div>
                      )}
                      {driver.city && (
                        <div className="flex items-center gap-2">
                          <MapPinIcon className="w-4 h-4 text-gray-400" />
                          <span>{driver.city}</span>
                        </div>
                      )}
                    </div>

                    {/* Verification Details */}
                    <div className="mt-3 flex gap-3 text-xs">
                      <span className={driver.license_verified ? 'text-green-600' : 'text-gray-400'}>
                        {driver.license_verified ? '✅' : '❌'} {t('admin.drivers.details.license', 'License')}
                      </span>
                      <span className={driver.insurance_verified ? 'text-green-600' : 'text-gray-400'}>
                        {driver.insurance_verified ? '✅' : '❌'} {t('admin.drivers.details.insurance', 'Insurance')}
                      </span>
                      {driver.license_expiry_date && (
                        <span className="text-gray-500">
                          {t('admin.drivers.details.expires', 'Expires')}: {new Date(driver.license_expiry_date).toLocaleDateString()}
                        </span>
                      )}
                    </div>
                  </div>

                  <div className="flex gap-2 ml-4">
                    {driver.location && (
                      <button
                        onClick={() => setSelectedDriver(driver)}
                        className="p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        title={t('admin.drivers.details.viewOnMap', 'View on Map')}
                      >
                        <MapPinIcon className="w-5 h-5" />
                      </button>
                    )}
                    <Link
                      to={`/admin/drivers/verification`}
                      className="p-2 text-gray-600 hover:text-green-600 hover:bg-green-50 rounded-lg transition-colors"
                      title={t('admin.drivers.details.viewDocuments', 'View Documents')}
                    >
                      <EyeIcon className="w-5 h-5" />
                    </Link>
                  </div>
                </div>
              </Card>
            )
          })}
        </div>
      )}

      {/* Driver Location Detail Modal */}
      {selectedDriver && selectedDriver.location && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <Card className="max-w-2xl w-full p-6">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-bold text-gray-900">
                {selectedDriver.first_name} {selectedDriver.last_name} — {t('admin.drivers.details.location', 'Location')}
              </h2>
              <button
                onClick={() => setSelectedDriver(null)}
                className="p-2 hover:bg-gray-100 rounded-lg"
              >
                <XCircleIcon className="w-6 h-6 text-gray-500" />
              </button>
            </div>

            <Map
              center={[parseFloat(selectedDriver.location.latitude), parseFloat(selectedDriver.location.longitude)]}
              zoom={15}
              markers={[{
                lat: parseFloat(selectedDriver.location.latitude),
                lng: parseFloat(selectedDriver.location.longitude),
                popup: `${selectedDriver.first_name} ${selectedDriver.last_name}`,
                icon: '🚚',
              }]}
              height="300px"
            />

            <div className="mt-4 grid grid-cols-2 gap-4 text-sm">
              <div>
                <p className="text-gray-500">{t('admin.drivers.details.speed', 'Speed')}</p>
                <p className="font-semibold">{selectedDriver.location.speed_kmh || 0} km/h</p>
              </div>
              <div>
                <p className="text-gray-500">{t('admin.drivers.details.accuracy', 'Accuracy')}</p>
                <p className="font-semibold">{selectedDriver.location.accuracy_meters || 'N/A'} m</p>
              </div>
              <div>
                <p className="text-gray-500">{t('admin.drivers.details.lastActive', 'Last Active')}</p>
                <p className="font-semibold">{new Date(selectedDriver.location.last_active_at).toLocaleString()}</p>
              </div>
              <div>
                <p className="text-gray-500">{t('admin.drivers.details.coordinates', 'Coordinates')}</p>
                <p className="font-semibold">
                  {parseFloat(selectedDriver.location.latitude).toFixed(4)}, {parseFloat(selectedDriver.location.longitude).toFixed(4)}
                </p>
              </div>
            </div>
          </Card>
        </div>
      )}
    </div>
  )
}

export default AdminDrivers

import { useState, useEffect, useRef } from 'react'
import { useTranslation } from 'react-i18next'
import { useAuthStore } from '@/store/authStore'
import { supabase } from '@/services/supabase'
import { auditLogger } from '@/services/auditLogger'
import { Card, LoadingSpinner } from '@/components/ui'
import {
  FlagIcon,
  CheckCircleIcon,
  XCircleIcon,
  ExclamationTriangleIcon,
  EyeIcon,
  UserIcon,
  ClockIcon,
  ShieldExclamationIcon,
  BoltIcon,
  BellIcon,
} from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'
import { logger } from '@/utils/logger'

const AdminModerationPage = () => {
  const { t } = useTranslation()
  const { user } = useAuthStore()
  const channelRef = useRef(null)
  const [loading, setLoading] = useState(true)
  const [reports, setReports] = useState([])
  const [stats, setStats] = useState({ pending: 0, reviewing: 0, resolved: 0, dismissed: 0 })
  const [filter, setFilter] = useState('pending')
  const [selectedReport, setSelectedReport] = useState(null)
  const [actionLoading, setActionLoading] = useState(false)
  const [actionNotes, setActionNotes] = useState('')
  const [suspensionHours, setSuspensionHours] = useState(24)

  // Load reports for the current filter
  useEffect(() => {
    loadReports()
  }, [filter])

  // Load overall stats (all statuses) on mount
  useEffect(() => {
    loadStats()
  }, [])

  // Set up real-time subscription for new reports
  useEffect(() => {
    const channel = supabase
      .channel('moderation-reports-realtime')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'user_reports' },
        (payload) => {
          // If the new report matches our current filter, prepend it
          if (filter === 'pending' || payload.new.status === filter) {
            setReports(prev => [payload.new, ...prev])
          }
          // Always update stats
          loadStats()
          toast(t('admin.moderation.newReport', 'New {{type}} report', { type: payload.new.report_type.replace('_', ' ') }), { icon: '🚩' })
        }
      )
      .on(
        'postgres_changes',
        { event: 'UPDATE', schema: 'public', table: 'user_reports' },
        (payload) => {
          // Update the report in the list or remove it if status changed
          setReports(prev => {
            if (payload.new.status !== filter) {
              return prev.filter(r => r.id !== payload.new.id)
            }
            return prev.map(r => r.id === payload.new.id ? payload.new : r)
          })
          loadStats()
        }
      )
      .subscribe()

    channelRef.current = channel

    return () => {
      supabase.removeChannel(channel)
    }
  }, [filter])

  const loadStats = async () => {
    try {
      const { data, error } = await supabase
        .from('user_reports')
        .select('status')

      if (error) throw error

      const counts = { pending: 0, reviewing: 0, resolved: 0, dismissed: 0 }
      data?.forEach(r => { counts[r.status] = (counts[r.status] || 0) + 1 })
      setStats(counts)
    } catch (error) {
      logger.error('Load stats error:', error)
    }
  }

  const loadReports = async () => {
    try {
      setLoading(true)
      const { data, error } = await supabase
        .from('user_reports')
        .select(`
          *,
          reporter:profiles!reporter_id(first_name, last_name, email),
          reported_user:profiles!reported_user_id(first_name, last_name, email, role, is_suspended)
        `)
        .eq('status', filter)
        .order('created_at', { ascending: false })
        .limit(100)

      if (error) throw error
      setReports(data || [])
    } catch (error) {
      logger.error('Load reports error:', error)
      toast.error(t('admin.moderation.loadReportsFailed', 'Failed to load reports'))
    } finally {
      setLoading(false)
    }
  }

  // ✅ FIX: Send notification to user when moderation action is taken
  const notifyUser = async (userId, title, message, type = 'moderation', data = {}) => {
    try {
      const { error } = await supabase.from('notifications').insert({
        user_id: userId,
        title,
        message,
        type,
        data: JSON.stringify(data),
        is_read: false,
        created_at: new Date().toISOString(),
      })
      if (error) {
        logger.error('Failed to notify user:', error)
      }
    } catch (error) {
      logger.error('Notify user error:', error)
    }
  }

  const handleResolve = async (reportId, action, notes = null) => {
    try {
      setActionLoading(true)

      // Get report details BEFORE updating
      const report = reports.find(r => r.id === reportId)
      if (!report) {
        toast.error(t('admin.moderation.reportNotFound', 'Report not found'))
        return
      }

      // Update report
      const { error: reportError } = await supabase
        .from('user_reports')
        .update({
          status: 'resolved',
          action_taken: action,
          admin_notes: notes || actionNotes,
          suspension_duration_hours: action === 'suspension' ? suspensionHours : null,
          resolved_by: user.id,
          resolved_at: new Date().toISOString(),
        })
        .eq('id', reportId)

      if (reportError) throw reportError

      // ✅ FIX: Log to audit trail
      await auditLogger.log({
        action: 'MODERATION_RESOLVED',
        entityType: 'moderation',
        entityId: reportId,
        oldValues: { status: report.status, action_taken: null },
        newValues: { status: 'resolved', action_taken: action, notes: notes || actionNotes },
        userId: user?.id,
        metadata: {
          reportType: report.report_type,
          priority: report.priority,
          reportedUserId: report.reported_user_id,
          reporterId: report.reporter_id,
          suspensionHours: action === 'suspension' ? suspensionHours : null,
          resolvedBy: user?.email || 'admin',
        }
      })

      // If action requires user suspension
      if (action === 'suspension' && report.reported_user_id) {
        const { error: suspendError } = await supabase.rpc('suspend_user', {
          p_user_id: report.reported_user_id,
          p_reason: notes || actionNotes,
          p_duration_hours: suspensionHours,
          p_admin_id: user.id,
        })

        if (suspendError) throw suspendError

        // ✅ FIX: Notify the suspended user
        await notifyUser(
          report.reported_user_id,
          t('admin.moderation.accountSuspended', 'Account Suspended'),
          t('admin.moderation.accountSuspendedMsg', 'Your account has been suspended for {{hours}} hours. Reason: {{reason}}. Please contact support if you believe this is an error.', { hours: suspensionHours, reason: notes || actionNotes || t('admin.moderation.violationGuidelines', 'Violation of community guidelines') }),
          'moderation',
          { action: 'suspension', duration: suspensionHours, reportId, reportType: report.report_type }
        )
      }

      // If action requires ban
      if (action === 'ban' && report.reported_user_id) {
        const { error: banError } = await supabase.rpc('ban_user_permanently', {
          p_user_id: report.reported_user_id,
          p_reason: notes || actionNotes,
          p_admin_id: user.id,
        })

        if (banError) throw banError

        // ✅ FIX: Notify the banned user
        await notifyUser(
          report.reported_user_id,
          t('admin.moderation.accountBanned', 'Account Permanently Banned'),
          t('admin.moderation.accountBannedMsg', 'Your account has been permanently banned. Reason: {{reason}}. This action cannot be undone.', { reason: notes || actionNotes || t('admin.moderation.severeViolation', 'Severe violation of community guidelines') }),
          'moderation',
          { action: 'ban', reportId, reportType: report.report_type }
        )
      }

      // If action is a warning
      if (action === 'warning' && report.reported_user_id) {
        // ✅ FIX: Notify the warned user
        await notifyUser(
          report.reported_user_id,
          t('admin.moderation.warningIssued', 'Warning Issued'),
          t('admin.moderation.warningIssuedMsg', 'You have received a warning regarding your {{reportType}}. {{notes}}', { reportType: report.report_type.replace('_', ' '), notes: notes || actionNotes ? t('admin.moderation.note', 'Note') + ': ' + (notes || actionNotes) : t('admin.moderation.reviewGuidelines', 'Please review and follow our community guidelines.') }),
          'moderation',
          { action: 'warning', reportId, reportType: report.report_type }
        )
      }

      // If action is content_removed
      if (action === 'content_removed' && report.reported_user_id) {
        await notifyUser(
          report.reported_user_id,
          t('admin.moderation.contentRemoved', 'Content Removed'),
          t('admin.moderation.contentRemovedMsg', 'Your content has been removed due to a {{reportType}} report. {{reason}}', { reportType: report.report_type.replace('_', ' '), reason: notes || actionNotes ? t('admin.moderation.reason', 'Reason') + ': ' + (notes || actionNotes) : t('admin.moderation.reviewGuidelines2', 'Please review our community guidelines.') }),
          'moderation',
          { action: 'content_removed', reportId, reportType: report.report_type }
        )
      }

      toast.success(t('admin.moderation.reportResolved', 'Report resolved successfully'))
      setSelectedReport(null)
      setActionNotes('')
      await loadReports()
      await loadStats()
    } catch (error) {
      logger.error('Resolve report error:', error)
      toast.error(t('admin.moderation.resolveFailed', 'Failed to resolve report'))
    } finally {
      setActionLoading(false)
    }
  }

  const handleDismiss = async (reportId) => {
    try {
      const report = reports.find(r => r.id === reportId)
      if (!report) {
        toast.error(t('admin.moderation.reportNotFound', 'Report not found'))
        return
      }

      const { error } = await supabase
        .from('user_reports')
        .update({
          status: 'dismissed',
          admin_notes: actionNotes || 'No violation found',
          resolved_by: user.id,
          resolved_at: new Date().toISOString(),
        })
        .eq('id', reportId)

      if (error) throw error

      // ✅ FIX: Log dismissal to audit trail
      await auditLogger.log({
        action: 'MODERATION_DISMISSED',
        entityType: 'moderation',
        entityId: reportId,
        oldValues: { status: report.status },
        newValues: { status: 'dismissed', notes: actionNotes || t('admin.moderation.noViolation', 'No violation found') },
        userId: user?.id,
        metadata: {
          reportType: report.report_type,
          priority: report.priority,
          reportedUserId: report.reported_user_id,
          dismissedBy: user?.email || 'admin',
        }
      })

      // ✅ FIX: Optionally notify the reported user that they were cleared
      if (report.reported_user_id) {
        await notifyUser(
          report.reported_user_id,
          t('admin.moderation.reportDismissed', 'Report Dismissed'),
          t('admin.moderation.reportDismissedMsg', 'A report against you ({{reportType}}) has been reviewed and dismissed. No action was taken.', { reportType: report.report_type.replace('_', ' ') }),
          'moderation',
          { action: 'dismissed', reportId, reportType: report.report_type }
        )
      }

      toast.success(t('admin.moderation.reportDismissed', 'Report dismissed'))
      setSelectedReport(null)
      setActionNotes('')
      await loadReports()
      await loadStats()
    } catch (error) {
      logger.error('Dismiss report error:', error)
      toast.error(t('admin.moderation.dismissFailed', 'Failed to dismiss report'))
    }
  }

  const handleStartReview = async (reportId) => {
    try {
      const { error } = await supabase
        .from('user_reports')
        .update({ status: 'reviewing' })
        .eq('id', reportId)

      if (error) throw error

      setReports(prev => prev.map(r => r.id === reportId ? { ...r, status: 'reviewing' } : r))
      setStats(prev => ({
        ...prev,
        pending: prev.pending - 1,
        reviewing: prev.reviewing + 1,
      }))
      toast.success(t('admin.moderation.reportMarkedReviewing', 'Report marked as reviewing'))
    } catch (error) {
      logger.error('Start review error:', error)
      toast.error(t('admin.moderation.startReviewFailed', 'Failed to start review'))
    }
  }

  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'critical': return 'bg-red-100 text-red-800'
      case 'high': return 'bg-orange-100 text-orange-800'
      case 'medium': return 'bg-yellow-100 text-yellow-800'
      default: return 'bg-gray-100 text-gray-800'
    }
  }

  const getTypeIcon = (type) => {
    switch (type) {
      case 'illegal_activity': return '🚫'
      case 'false_info': return '⚠️'
      case 'fee_circumvention': return '💰'
      case 'harassment': return '👥'
      case 'security_violation': return '🔒'
      case 'spam': return '📧'
      default: return '🚩'
    }
  }

  if (loading && reports.length === 0) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  return (
