  useEffect(() => {
    const timer = setTimeout(() => {
      setPage(1)
      loadUsers()
    }, 400)
    return () => clearTimeout(timer)
  }, [search])

  const loadUsers = async () => {
    try {
      setLoading(true)
      setError(null)

      const filters = {
        role: roleFilter,
        search: search.trim() || undefined,
        sortBy,
        limit: PAGE_SIZE,
        offset: (page - 1) * PAGE_SIZE,
      }

      const { data, count } = await usersApi.getAll(filters)
      setUsers(data || [])
      setTotalCount(count || 0)
    } catch (err) {
      logger.error('Error loading users:', err)
      setError(t('admin.users.errors.loadFailed', 'Failed to load users'))
      toast.error(t('admin.users.errors.loadFailed', 'Failed to load users'))
    } finally {
      setLoading(false)
    }
  }

  const openEditModal = (user) => {
    setEditingUser(user)
    setEditForm({
      role: user.role || 'buyer',
      is_approved: user.is_approved || false,
      is_suspended: user.is_suspended || false,
    })
    setEditModalOpen(true)
  }

  const handleSaveEdit = async () => {
    if (!editingUser) return

    setSaving(true)
    try {
      const updates = {
        role: editForm.role,
        is_approved: editForm.is_approved,
        is_suspended: editForm.is_suspended,
      }

      const updated = await usersApi.update(editingUser.id, updates)

      // Log audit
      await auditLogger.logProfileAction('USER_UPDATED', {
        id: editingUser.id,
        ...updates,
      }, editingUser)

      toast.success(t('admin.users.notifications.updatedSuccess', 'User updated successfully'))
      setEditModalOpen(false)
      setEditingUser(null)
      await loadUsers()
    } catch (err) {
      logger.error('Error updating user:', err)
      toast.error(t('admin.users.errors.updateFailed', 'Failed to update user'))
    } finally {
      setSaving(false)
    }
  }

  const openDeleteModal = (user) => {
    setDeletingUser(user)
    setDeleteModalOpen(true)
  }

  const handleDelete = async () => {
    if (!deletingUser) return

    setDeleting(true)
    try {
      // Log audit before deletion
      await auditLogger.logProfileAction('USER_DELETED', {
        id: deletingUser.id,
        email: deletingUser.email,
        name: `${deletingUser.first_name} ${deletingUser.last_name}`,
        role: deletingUser.role,
      })

      // Delete user via Supabase Admin API
      const { error: deleteError } = await supabase.auth.admin.deleteUser(deletingUser.id)

      if (deleteError) {
        // Fallback: soft delete by updating profile
        logger.warn('Admin delete failed, falling back to profile deletion:', deleteError)
        await supabase
          .from('profiles')
          .delete()
          .eq('id', deletingUser.id)
      }

      toast.success(t('admin.users.notifications.deletedSuccess', 'User deleted successfully'))
      setDeleteModalOpen(false)
      setDeletingUser(null)
      await loadUsers()
    } catch (err) {
      logger.error('Error deleting user:', err)
      toast.error(t('admin.users.errors.deleteFailed', 'Failed to delete user'))
    } finally {
      setDeleting(false)
    }
  }

  const handleToggleSuspend = async (user) => {
    try {
      const newSuspended = !user.is_suspended
      const { error } = await supabase
        .from('profiles')
        .update({ is_suspended: newSuspended })
        .eq('id', user.id)

      if (error) throw error

      await auditLogger.logProfileAction(newSuspended ? 'USER_SUSPENDED' : 'USER_UNSUSPENDED', {
        id: user.id,
        email: user.email,
      })

      toast.success(
        newSuspended
          ? t('admin.users.notifications.suspendedSuccess', 'User suspended')
          : t('admin.users.notifications.unsuspendedSuccess', 'User unsuspended')
      )
      await loadUsers()
    } catch (err) {
      logger.error('Error toggling suspension:', err)
      toast.error(t('admin.users.errors.suspendFailed', 'Failed to update suspension'))
    }
  }

  const totalPages = Math.ceil(totalCount / PAGE_SIZE)

  const getFullName = (user) => {
    if (user.first_name && user.last_name) return `${user.first_name} ${user.last_name}`
    return user.first_name || user.last_name || user.email || 'N/A'
  }

  const roleColors = {
    buyer: 'badge-primary',
    vendor: 'badge-secondary',
    driver: 'bg-blue-100 text-blue-800 badge',
    admin: 'bg-purple-100 text-purple-800 badge',
  }

  if (loading && users.length === 0) {
    return <LoadingSpinner size="lg" />
  }

  return (
    <div>
      <h1 className="text-2xl font-bold text-gray-900 mb-8">{t('admin.users.title')}</h1>

      {/* Error State */}
      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
          <p className="text-red-800">{error}</p>
          <Button variant="outline" size="sm" className="mt-2" onClick={loadUsers}>
            {t('admin.users.errors.retry', 'Retry')}
          </Button>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-4 mb-6">
        <div className="flex-1">
          <Input
            placeholder={t('admin.users.searchPlaceholder', 'Search by name or email...')}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            leftIcon={<MagnifyingGlassIcon className="w-5 h-5" />}
          />
        </div>
        <div className="flex gap-2 flex-wrap">
          {['all', ...ROLES].map((role) => (
            <button
              key={role}
              onClick={() => { setRoleFilter(role); setPage(1) }}
              className={`px-4 py-2 rounded-lg text-sm font-medium capitalize ${
                roleFilter === role
                  ? 'bg-primary-600 text-white'
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              }`}
            >
              {t(`admin.users.roles.${role}`, role)}
            </button>
          ))}
        </div>
        <select
          value={sortBy}
          onChange={(e) => { setSortBy(e.target.value); setPage(1) }}
          className="px-4 py-2 rounded-lg text-sm font-medium bg-gray-100 text-gray-700 border-0"
        >
          <option value="created">{t('admin.users.sort.newest', 'Newest First')}</option>
          <option value="name">{t('admin.users.sort.name', 'Name A-Z')}</option>
        </select>
      </div>

      {/* Users Table */}
      <Card>
        <div className="overflow-x-auto">
          <table className="table">
            <thead>
              <tr>
                <th>{t('admin.users.name', 'Name')}</th>
                <th>{t('admin.users.email', 'Email')}</th>
                <th>{t('admin.users.role', 'Role')}</th>
                <th>{t('admin.users.status', 'Status')}</th>
                <th>{t('admin.users.joined', 'Joined')}</th>
                <th>{t('admin.users.actions', 'Actions')}</th>
              </tr>
            </thead>
            <tbody>
              {users.length === 0 ? (
                <tr>
                  <td colSpan="6" className="text-center py-8 text-gray-500">
                    {t('admin.users.noUsers', 'No users found')}
                  </td>
                </tr>
              ) : (
                users.map((user) => (
                  <tr key={user.id}>
                    <td className="font-medium">{getFullName(user)}</td>
                    <td>{user.email || 'N/A'}</td>
                    <td>
                      <span className={`badge ${roleColors[user.role] || 'badge'}`}>
                        {t(`admin.users.roles.${user.role}`, user.role || 'N/A')}
                      </span>
                    </td>
                    <td>
                      {user.is_suspended ? (
                        <Badge variant="danger">{t('admin.users.suspended', 'Suspended')}</Badge>
                      ) : user.is_approved ? (
                        <Badge variant="success">{t('admin.users.approved', 'Approved')}</Badge>
                      ) : (
                        <Badge variant="warning">{t('admin.users.pending', 'Pending')}</Badge>
                      )}
                    </td>
                    <td className="text-gray-500">
                      {user.created_at ? new Date(user.created_at).toLocaleDateString() : 'N/A'}
                    </td>
                    <td>
                      <div className="flex items-center gap-2">
                        <button
                          className="p-2 text-gray-600 hover:text-primary-600 hover:bg-primary-50 rounded-lg"
                          onClick={() => openEditModal(user)}
                          title={t('admin.users.edit', 'Edit')}
                        >
                          <PencilIcon className="w-5 h-5" />
                        </button>
                        {user.role !== 'admin' && (
                          <button
                            className="p-2 text-gray-600 hover:text-red-600 hover:bg-red-50 rounded-lg"
                            onClick={() => openDeleteModal(user)}
                            title={t('admin.users.delete', 'Delete')}
                          >
                            <TrashIcon className="w-5 h-5" />
                          </button>
                        )}
                        <button
                          className={`p-2 rounded-lg ${
                            user.is_suspended
                              ? 'text-green-600 hover:bg-green-50'
                              : 'text-yellow-600 hover:bg-yellow-50'
                          }`}
                          onClick={() => handleToggleSuspend(user)}
                          title={
                            user.is_suspended
                              ? t('admin.users.unsuspend', 'Unsuspend')
                              : t('admin.users.suspend', 'Suspend')
                          }
                        >
                          <ExclamationTriangleIcon className="w-5 h-5" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between px-6 py-4 border-t border-gray-200">
            <p className="text-sm text-gray-600">
              {t('admin.users.pagination.info', 'Showing {{from}}-{{to}} of {{total}}', {
                from: (page - 1) * PAGE_SIZE + 1,
                to: Math.min(page * PAGE_SIZE, totalCount),
                total: totalCount,
              })}
            </p>
            <div className="flex items-center gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                leftIcon={<ChevronLeftIcon className="w-4 h-4" />}
              >
                {t('admin.users.pagination.previous', 'Previous')}
              </Button>
              <span className="text-sm text-gray-600">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                rightIcon={<ChevronRightIcon className="w-4 h-4" />}
              >
                {t('admin.users.pagination.next', 'Next')}
              </Button>
            </div>
          </div>
        )}
      </Card>

      {/* Edit User Modal */}
      <Modal
        isOpen={editModalOpen}
        onClose={() => { setEditModalOpen(false); setEditingUser(null) }}
        title={t('admin.users.editModal.title', 'Edit User')}
        size="md"
      >
        {editingUser && (
          <div className="space-y-4">
            <div className="p-4 bg-gray-50 rounded-lg">
              <p className="text-sm font-medium text-gray-900">{getFullName(editingUser)}</p>
              <p className="text-sm text-gray-600">{editingUser.email}</p>
            </div>

            <div>
              <label className="input-label">{t('admin.users.editModal.role', 'Role')}</label>
              <select
                value={editForm.role}
                onChange={(e) => setEditForm((prev) => ({ ...prev, role: e.target.value }))}
                className="input"
              >
                {ROLES.map((role) => (
                  <option key={role} value={role}>
                    {t(`admin.users.roles.${role}`, role)}
                  </option>
                ))}
              </select>
            </div>

            <div className="flex items-center gap-3">
              <input
                type="checkbox"
                id="edit-is-approved"
                checked={editForm.is_approved}
                onChange={(e) => setEditForm((prev) => ({ ...prev, is_approved: e.target.checked }))}
                className="w-4 h-4 text-primary-600 rounded"
              />
              <label htmlFor="edit-is-approved" className="text-sm text-gray-700">
                {t('admin.users.editModal.isApproved', 'Approved')}
              </label>
            </div>

            <div className="flex items-center gap-3">
              <input
                type="checkbox"
                id="edit-is-suspended"
                checked={editForm.is_suspended}
                onChange={(e) => setEditForm((prev) => ({ ...prev, is_suspended: e.target.checked }))}
                className="w-4 h-4 text-primary-600 rounded"
              />
              <label htmlFor="edit-is-suspended" className="text-sm text-gray-700">
                {t('admin.users.editModal.isSuspended', 'Suspended')}
              </label>
            </div>

            <div className="flex gap-3 pt-4">
              <Button
                variant="primary"
                onClick={handleSaveEdit}
                disabled={saving}
                className="flex-1"
              >
                {saving ? (
                  <>
                    <LoadingSpinner size="sm" />
                    {t('admin.users.editModal.saving', 'Saving...')}
                  </>
                ) : (
                  t('admin.users.editModal.save', 'Save Changes')
                )}
              </Button>
              <Button
                variant="outline"
                onClick={() => { setEditModalOpen(false); setEditingUser(null) }}
                disabled={saving}
              >
                {t('common.cancel', 'Cancel')}
              </Button>
            </div>
          </div>
        )}
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal
        isOpen={deleteModalOpen}
        onClose={() => { setDeleteModalOpen(false); setDeletingUser(null) }}
        title={t('admin.users.deleteModal.title', 'Delete User')}
        size="md"
      >
        {deletingUser && (
          <div className="space-y-4">
            <div className="p-4 bg-red-50 border border-red-200 rounded-lg">
              <p className="text-sm text-red-800">
                {t('admin.users.deleteModal.warning', 'You are about to permanently delete the user "{{name}}" ({{email}}). This action cannot be undone.', {
                  name: getFullName(deletingUser),
                  email: deletingUser.email,
                })}
              </p>
            </div>

            <div className="flex gap-3 pt-2">
              <Button
                variant="primary"
                onClick={handleDelete}
                disabled={deleting}
                className="flex-1 bg-red-600 hover:bg-red-700"
              >
                {deleting ? (
                  <>
                    <LoadingSpinner size="sm" />
                    {t('admin.users.deleteModal.deleting', 'Deleting...')}
                  </>
                ) : (
                  t('admin.users.deleteModal.confirmDelete', 'Delete User')
                )}
              </Button>
              <Button
                variant="outline"
                onClick={() => { setDeleteModalOpen(false); setDeletingUser(null) }}
                disabled={deleting}
              >
                {t('common.cancel', 'Cancel')}
              </Button>
            </div>
          </div>
        )}
      </Modal>
    </div>
  )
}

export default AdminUsers

import { useState, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import { Card, Badge, Button, Map, LoadingSpinner, Modal } from '@/components/ui'
import {
  CheckIcon,
  XMarkIcon,
  MapPinIcon,
  ExclamationTriangleIcon,
  EyeIcon,
  BellIcon,
  UserIcon,
} from '@heroicons/react/24/outline'
import { supabase } from '@/services/supabase'
import { logger } from '@/utils/logger'
import { auditLogger } from '@/services/auditLogger'
import toast from 'react-hot-toast'

const rejectionReasons = [
  { value: 'incomplete_documents', label: 'Incomplete Documents', labelAr: 'مستندات غير مكتملة' },
  { value: 'invalid_business_license', label: 'Invalid Business License', labelAr: 'رخصة تجارية غير صالحة' },
  { value: 'policy_violation', label: 'Policy Violation', labelAr: 'انتهاك السياسة' },
  { value: 'duplicate_account', label: 'Duplicate Account', labelAr: 'حساب مكرر' },
  { value: 'fraudulent_information', label: 'Fraudulent Information', labelAr: 'معلومات احتيالية' },
  { value: 'other', label: 'Other', labelAr: 'أخرى' },
]

const suspensionReasons = [
  { value: 'repeated_violations', label: 'Repeated Violations', labelAr: 'مخالفات متكررة' },
  { value: 'fraudulent_activity', label: 'Fraudulent Activity', labelAr: 'نشاط احتيالي' },
  { value: 'quality_complaints', label: 'Quality Complaints', labelAr: 'شكاوى الجودة' },
  { value: 'delivery_issues', label: 'Delivery Issues', labelAr: 'مشاكل التوصيل' },
  { value: 'customer_complaints', label: 'Customer Complaints', labelAr: 'شكاوى العملاء' },
  { value: 'policy_violation', label: 'Policy Violation', labelAr: 'انتهاك السياسة' },
  { value: 'other', label: 'Other', labelAr: 'أخرى' },
]

const AdminVendors = () => {
  const { t } = useTranslation()
  const [statusFilter, setStatusFilter] = useState('all')
  const [vendors, setVendors] = useState([])
  const [loading, setLoading] = useState(true)

  // Rejection modal state
  const [rejectModalOpen, setRejectModalOpen] = useState(false)
  const [rejectingVendorId, setRejectingVendorId] = useState(null)
  const [rejectingVendorName, setRejectingVendorName] = useState('')
  const [selectedRejectionReason, setSelectedRejectionReason] = useState('')
  const [customRejectionReason, setCustomRejectionReason] = useState('')
  const [rejecting, setRejecting] = useState(false)

  // Suspension modal state
  const [suspendModalOpen, setSuspendModalOpen] = useState(false)
  const [suspendingVendorId, setSuspendingVendorId] = useState(null)
  const [suspendingVendorName, setSuspendingVendorName] = useState('')
  const [selectedSuspensionReason, setSelectedSuspensionReason] = useState('')
  const [customSuspensionReason, setCustomSuspensionReason] = useState('')
  const [suspensionEndDate, setSuspensionEndDate] = useState('')
  const [suspending, setSuspending] = useState(false)

  // View vendor details modal
  const [viewModalOpen, setViewModalOpen] = useState(false)
  const [viewingVendor, setViewingVendor] = useState(null)

  useEffect(() => {
    loadVendors()
  }, [])

  const loadVendors = async () => {
    try {
      setLoading(true)

      // Fetch all vendors from profiles
      const { data: profilesData, error: profilesError } = await supabase
        .from('profiles')
        .select('id, first_name, last_name, email, phone, city, country, store_name, store_description, role, vendor_status, is_verified, vendor_warning_count, latitude, longitude, created_at')
        .eq('role', 'vendor')
        .order('created_at', { ascending: false })

      if (profilesError) throw profilesError

      // Fetch product count and average rating for each vendor
      const vendorsWithProducts = await Promise.all(
        (profilesData || []).map(async (vendor) => {
          const { count } = await supabase
            .from('products')
            .select('*', { count: 'exact', head: true })
            .eq('vendor_id', vendor.id)

          // Fetch average rating from reviews
          const { data: reviewData } = await supabase
            .from('reviews')
            .select('rating')
            .eq('vendor_id', vendor.id)

          const avgRating = reviewData && reviewData.length > 0
            ? reviewData.reduce((sum, r) => sum + r.rating, 0) / reviewData.length
            : null

          // Determine status from vendor_status field
          const status = vendor.vendor_status || 'pending'

          return {
            id: vendor.id,
            store_name: vendor.store_name || `${vendor.first_name} ${vendor.last_name}`,
            owner: `${vendor.first_name} ${vendor.last_name}`,
            email: vendor.email,
            phone: vendor.phone,
            city: vendor.city,
            country: vendor.country,
            store_description: vendor.store_description,
            location: vendor.city || 'N/A',
            status,
            vendor_status: vendor.vendor_status,
            is_suspended: status === 'suspended',
            suspension_reason: null,
            suspension_start: null,
            suspension_end: null,
            violation_count: vendor.vendor_warning_count || 0,
            rating: avgRating ? parseFloat(avgRating.toFixed(1)) : null,
            products: count || 0,
            latitude: vendor.latitude,
            longitude: vendor.longitude,
            created_at: vendor.created_at,
          }
        })
      )

      setVendors(vendorsWithProducts)
    } catch (error) {
      logger.error('Error loading vendors:', error)
      toast.error(t('admin.vendors.errors.loadFailed', 'Failed to load vendors data'))
    } finally {
      setLoading(false)
    }
  }

  const filteredVendors = statusFilter === 'all'
    ? vendors
    : vendors.filter(v => v.status === statusFilter)

  // Send notification to vendor
  const sendVendorNotification = async (vendorId, title, message, type = 'system') => {
    try {
      const { error } = await supabase
        .from('notifications')
        .insert({
          user_id: vendorId,
          title,
          message,
          type,
          data: { source: 'admin' }
        })

      if (error) {
        logger.error('Error sending notification:', error)
      }
    } catch (error) {
      logger.error('Error sending notification:', error)
    }
  }

  const handleApprove = async (id, vendorName) => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({
          vendor_status: 'approved',
          is_verified: true,
        })
        .eq('id', id)

      if (error) throw error

      // Send approval notification to vendor
      await sendVendorNotification(
        id,
        t('admin.vendors.notifications.approvedTitle', '✅ Vendor Application Approved'),
        t('admin.vendors.notifications.approvedMessage', 'Congratulations! Your vendor application has been approved. You can now list products and start selling on Qotoof.'),
        'system'
      )

      // Log audit
      await auditLogger.logProfileAction('VENDOR_APPROVED', {
        vendor_id: id,
        vendor_name: vendorName,
      })

      toast.success(t('admin.vendors.notifications.approvedSuccess', 'Vendor approved successfully'))
      await loadVendors()
    } catch (error) {
      logger.error('Error approving vendor:', error)
      toast.error(t('admin.vendors.errors.approveFailed', 'Failed to approve vendor'))
    }
  }

  const openRejectModal = (vendor) => {
    setRejectingVendorId(vendor.id)
    setRejectingVendorName(vendor.store_name)
    setSelectedRejectionReason('')
    setCustomRejectionReason('')
    setRejectModalOpen(true)
  }

  const handleReject = async () => {
    if (!selectedRejectionReason) {
      toast.error(t('admin.vendors.errors.selectRejectionReason', 'Please select a rejection reason'))
      return
    }

    if (selectedRejectionReason === 'other' && !customRejectionReason.trim()) {
      toast.error(t('admin.vendors.errors.customRejectionReason', 'Please provide a rejection reason'))
      return
    }

    setRejecting(true)

    try {
      const finalReason = selectedRejectionReason === 'other'
        ? customRejectionReason
        : rejectionReasons.find(r => r.value === selectedRejectionReason)?.label || selectedRejectionReason

      const { error } = await supabase
        .from('profiles')
        .update({
          vendor_status: 'rejected',
          is_verified: false,
        })
        .eq('id', rejectingVendorId)

      if (error) throw error

      // Send rejection notification to vendor with reason
      await sendVendorNotification(
        rejectingVendorId,
        t('admin.vendors.notifications.rejectedTitle', '❌ Vendor Application Rejected'),
        t('admin.vendors.notifications.rejectedMessage', 'Your vendor application has been rejected. Reason: {{reason}}. You may reapply after addressing the issues.', { reason: finalReason }),
        'system'
      )

      // Log audit
      await auditLogger.logProfileAction('VENDOR_REJECTED', {
        vendor_id: rejectingVendorId,
        vendor_name: rejectingVendorName,
        rejection_reason: finalReason,
      })

      toast.success(t('admin.vendors.notifications.rejectedSuccess', 'Vendor application rejected'))
      setRejectModalOpen(false)
      await loadVendors()
    } catch (error) {
      logger.error('Error rejecting vendor:', error)
      toast.error(t('admin.vendors.errors.rejectFailed', 'Failed to reject vendor'))
    } finally {
      setRejecting(false)
    }
  }

  const openSuspendModal = (vendor) => {
    setSuspendingVendorId(vendor.id)
    setSuspendingVendorName(vendor.store_name)
    setSelectedSuspensionReason('')
    setCustomSuspensionReason('')
    setSuspensionEndDate('')
    setSuspendModalOpen(true)
  }

  const handleSuspend = async () => {
    if (!selectedSuspensionReason) {
      toast.error(t('admin.vendors.errors.selectSuspensionReason', 'Please select a suspension reason'))
      return
    }

    if (selectedSuspensionReason === 'other' && !customSuspensionReason.trim()) {
      toast.error(t('admin.vendors.errors.customSuspensionReason', 'Please provide a suspension reason'))
      return
    }

    setSuspending(true)

    try {
      const finalReason = selectedSuspensionReason === 'other'
        ? customSuspensionReason
        : suspensionReasons.find(r => r.value === selectedSuspensionReason)?.label || selectedSuspensionReason

      const updateData = {
        vendor_status: 'suspended',
        vendor_warning_count: (vendors.find(v => v.id === suspendingVendorId)?.violation_count || 0) + 1,
      }

      if (suspensionEndDate) {
        // Date is currently used for notification messaging only in this schema.
      }

      const { error } = await supabase
        .from('profiles')
        .update(updateData)
        .eq('id', suspendingVendorId)

      if (error) throw error

      // Send suspension notification to vendor
      const suspensionMsg = suspensionEndDate
        ? t('admin.vendors.notifications.suspendedWithEndMessage', 'Your vendor account has been suspended. Reason: {{reason}}. Suspension end date: {{endDate}}. You cannot list or sell products during this period.', { reason: finalReason, endDate: new Date(suspensionEndDate).toLocaleDateString() })
        : t('admin.vendors.notifications.suspendedIndefiniteMessage', 'Your vendor account has been suspended indefinitely. Reason: {{reason}}. You cannot list or sell products until the suspension is lifted.', { reason: finalReason })

      await sendVendorNotification(
        suspendingVendorId,
        t('admin.vendors.notifications.suspendedTitle', '⚠️ Vendor Account Suspended'),
        suspensionMsg,
        'system'
      )

      // Log audit
      await auditLogger.logProfileAction('VENDOR_SUSPENDED', {
        vendor_id: suspendingVendorId,
        vendor_name: suspendingVendorName,
        suspension_reason: finalReason,
        suspension_end: suspensionEndDate || 'indefinite',
      })

      toast.success(t('admin.vendors.notifications.suspendedSuccess', 'Vendor account suspended'))
      setSuspendModalOpen(false)
      await loadVendors()
    } catch (error) {
      logger.error('Error suspending vendor:', error)
      toast.error(t('admin.vendors.errors.suspendFailed', 'Failed to suspend vendor'))
    } finally {
      setSuspending(false)
    }
  }

  const handleUnsuspend = async (id, vendorName) => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({
          vendor_status: 'approved',
        })
        .eq('id', id)

      if (error) throw error

      // Send unsuspension notification to vendor
      await sendVendorNotification(
        id,
        t('admin.vendors.notifications.unsuspendedTitle', '✅ Vendor Account Restored'),
        t('admin.vendors.notifications.unsuspendedMessage', 'Your vendor account has been restored. You can now list products and resume selling on Qotoof.'),
        'system'
      )

      // Log audit
      await auditLogger.logProfileAction('VENDOR_UNSUSPENDED', {
        vendor_id: id,
        vendor_name: vendorName,
      })

      toast.success(t('admin.vendors.notifications.unsuspendedSuccess', 'Vendor account restored'))
      await loadVendors()
    } catch (error) {
      logger.error('Error unsuspending vendor:', error)
      toast.error(t('admin.vendors.errors.unsuspendFailed', 'Failed to restore vendor'))
    }
  }

  const openViewModal = (vendor) => {
    setViewingVendor(vendor)
    setViewModalOpen(true)
  }

  const getStatusBadge = (vendor) => {
    if (vendor.status === 'suspended') {
      return <Badge variant="danger">{t('admin.vendors.suspended', 'Suspended')}</Badge>
    }
    if (vendor.status === 'approved') {
      return <Badge variant="primary">{t('admin.vendors.approved', 'Approved')}</Badge>
