          { key: 'pending', label: t('admin.vendors.filters.pending', 'Pending') },
          { key: 'rejected', label: t('admin.vendors.filters.rejected', 'Rejected') },
          { key: 'suspended', label: t('admin.vendors.filters.suspended', 'Suspended') },
        ].map((status) => (
          <button
