import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuthStore } from '@/store/authStore'
import { Card, LoadingSpinner } from '@/components/ui'
import { useTranslation } from 'react-i18next'
import { supabase } from '@/services/supabase'
import { formatPrice } from '@/utils/currency'
import {
  StarIcon,
  TrophyIcon,
  ArrowTrendingUpIcon,
  GiftIcon,
  ArrowLeftIcon,
  ShoppingBagIcon,
} from '@heroicons/react/24/outline'
import { StarIcon as StarSolid } from '@heroicons/react/24/solid'

const TIERS = [
  { name: 'Bronze', minPoints: 0, color: 'from-amber-600 to-amber-800', bg: 'bg-amber-50', text: 'text-amber-700', icon: '🥉' },
  { name: 'Silver', minPoints: 500, color: 'from-gray-400 to-gray-600', bg: 'bg-gray-50', text: 'text-gray-700', icon: '🥈' },
  { name: 'Gold', minPoints: 2000, color: 'from-yellow-400 to-yellow-600', bg: 'bg-yellow-50', text: 'text-yellow-700', icon: '🥇' },
  { name: 'Platinum', minPoints: 5000, color: 'from-purple-500 to-purple-700', bg: 'bg-purple-50', text: 'text-purple-700', icon: '💎' },
]

const BuyerLoyalty = () => {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { user } = useAuthStore()
  const [points, setPoints] = useState(0)
  const [loading, setLoading] = useState(true)
  const [history, setHistory] = useState([])
  const [lifetimeSpent, setLifetimeSpent] = useState(0)

  useEffect(() => {
    loadLoyalty()
  }, [])

  const loadLoyalty = async () => {
    setLoading(true)
    try {
      // Get points
      const { data: pointsData } = await supabase
        .from('loyalty_points')
        .select('points, lifetime_points')
        .eq('user_id', user.id)
        .single()

      setPoints(pointsData?.points || 0)

      // Get lifetime spent
      const { data: orders } = await supabase
        .from('orders')
        .select('total')
        .eq('buyer_id', user.id)
        .eq('status', 'delivered')

      const total = orders?.reduce((sum, o) => sum + (o.total || 0), 0) || 0
      setLifetimeSpent(total)

      // Get history
      const { data: historyData } = await supabase
        .from('loyalty_transactions')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false })
        .limit(20)

      setHistory(historyData || [])
    } catch {
      // No loyalty data yet
    } finally {
      setLoading(false)
    }
  }

  const currentTier = [...TIERS].reverse().find(t => points >= t.minPoints) || TIERS[0]
  const nextTier = TIERS.find(t => t.minPoints > points)
  const progressToNext = nextTier
    ? Math.round(((points - currentTier.minPoints) / (nextTier.minPoints - currentTier.minPoints)) * 100)
    : 100

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <LoadingSpinner size="lg" />
      </div>
    )
  }

  return (
    <div>
      {/* Header */}
      <div className="flex items-center gap-4 mb-8">
        <button onClick={() => navigate('/buyer/dashboard')} className="p-2 hover:bg-gray-100 rounded-lg">
          <ArrowLeftIcon className="w-5 h-5 text-gray-600" />
        </button>
        <div>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <TrophyIcon className="w-7 h-7 text-amber-500" />
            {t('buyer.loyalty.title', 'Loyalty Program')}
          </h1>
          <p className="text-sm text-gray-500 mt-1">{t('buyer.loyalty.subtitle', 'Earn points with every purchase')}</p>
        </div>
      </div>

      {/* Points Card */}
      <Card className={`p-8 mb-8 bg-gradient-to-r ${currentTier.color} text-white`}>
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-6">
          <div>
            <p className="text-white/80 text-sm mb-1">{t('buyer.loyalty.pointsBalance', 'Your Points Balance')}</p>
            <p className="text-5xl font-bold">{points.toLocaleString()}</p>
            <p className="text-white/70 text-sm mt-1">
              {t('buyer.loyalty.lifetimeSpent', 'Lifetime spent')}: {formatPrice(lifetimeSpent)}
            </p>
          </div>
          <div className="text-center sm:text-right">
            <span className="text-4xl">{currentTier.icon}</span>
            <p className="text-white font-semibold text-lg mt-1">{t('buyer.loyalty.tierMember', '{{tier}} Member', { tier: currentTier.name })}</p>
          </div>
        </div>

        {/* Progress to Next Tier */}
        {nextTier && (
          <div className="mt-6">
            <div className="flex items-center justify-between text-sm text-white/80 mb-2">
              <span>{currentTier.name}</span>
              <span>{t('buyer.loyalty.pointsToNext', '{{points}} / {{nextMin}} points to {{nextTier}}', { points, nextMin: nextTier.minPoints, nextTier: nextTier.name })}</span>
            </div>
            <div className="h-3 bg-white/20 rounded-full overflow-hidden">
              <div
                className="h-full bg-white rounded-full transition-all duration-700"
                style={{ width: `${Math.min(100, progressToNext)}%` }}
              />
            </div>
          </div>
        )}
      </Card>

      {/* Tier Benefits */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {TIERS.map(tier => (
          <Card key={tier.name} className={`p-4 text-center border-2 ${
            tier.name === currentTier.name ? 'border-green-400 shadow-lg' : 'border-gray-100'
          }`}>
            <span className="text-3xl">{tier.icon}</span>
            <h3 className={`font-semibold mt-2 ${tier.name === currentTier.name ? 'text-green-600' : 'text-gray-900'}`}>
              {t(`buyer.loyalty.tiers.${tier.name.toLowerCase()}`, tier.name)}
            </h3>
            <p className="text-xs text-gray-500 mt-1">{tier.minPoints}+ points</p>
            {tier.name === currentTier.name && (
              <span className="inline-block mt-2 text-xs px-2 py-0.5 bg-green-100 text-green-700 rounded-full font-medium">
                {t('buyer.loyalty.currentBadge', 'Current')}
              </span>
            )}
          </Card>
        ))}
      </div>

      {/* Points History */}
      <Card>
        <div className="p-4 sm:p-6 border-b border-gray-200">
          <h2 className="font-semibold text-gray-900 flex items-center gap-2">
            <ArrowTrendingUpIcon className="w-5 h-5 text-green-600" />
            {t('buyer.loyalty.historyTitle', 'Points History')}
          </h2>
        </div>
        {history.length === 0 ? (
          <div className="p-12 text-center text-gray-500">
            <GiftIcon className="w-12 h-12 text-gray-300 mx-auto mb-3" />
            <p>{t('buyer.loyalty.emptyHistory', 'No points earned yet. Start shopping to earn loyalty points!')}</p>
          </div>
        ) : (
          <div className="divide-y divide-gray-100">
            {history.map(tx => (
              <div key={tx.id} className="p-4 flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-900">{tx.description || t('buyer.loyalty.pointsEarned', 'Points earned')}</p>
                  <p className="text-xs text-gray-400">{new Date(tx.created_at).toLocaleDateString()}</p>
                </div>
                <span className={`font-semibold ${tx.points_change > 0 ? 'text-green-600' : 'text-red-600'}`}>
                  {tx.points_change > 0 ? '+' : ''}{tx.points_change}
                </span>
              </div>
            ))}
          </div>
        )}
      </Card>
    </div>
  )
}

export default BuyerLoyalty

import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react'
