// ============================================
// Date Range Presets
// ============================================

const DATE_RANGES = [
  { id: '7d', label: 'Last 7 Days', labelAr: 'آخر 7 أيام', days: 7, granularity: 'day' },
  { id: '30d', label: 'Last 30 Days', labelAr: 'آخر 30 يوم', days: 30, granularity: 'day' },
  { id: '3m', label: 'Last 3 Months', labelAr: 'آخر 3 أشهر', days: 90, granularity: 'week' },
  { id: '6m', label: 'Last 6 Months', labelAr: 'آخر 6 أشهر', days: 180, granularity: 'week' },
  { id: '1y', label: 'Last Year', labelAr: 'آخر سنة', days: 365, granularity: 'month' },
]

const VendorAnalytics = () => {
  const { t } = useTranslation()
  const { user } = useAuthStore()
  const [loading, setLoading] = useState(true)
  const [exporting, setExporting] = useState(false)
  const [selectedRange, setSelectedRange] = useState('30d')
  const [customDateFrom, setCustomDateFrom] = useState('')
  const [customDateTo, setCustomDateTo] = useState('')
  const [showCustomPicker, setShowCustomPicker] = useState(false)
  const [analytics, setAnalytics] = useState({
    revenueData: { labels: [], datasets: [] },
    topProductsData: { labels: [], datasets: [] },
    categoryData: { labels: [], datasets: [] },
    keyMetrics: {
      totalRevenue: 0,
      totalOrders: 0,
      avgOrderValue: 0,
      conversionRate: 0,
      repeatCustomers: 0,
      avgDeliveryTime: 0,
    },
    rawOrders: [],
    rawProducts: [],
  })

  // ============================================
  // Load Analytics — recalculates on date range change
  // ============================================

  const loadAnalytics = useCallback(async () => {
    if (!user) return

    try {
      setLoading(true)

      // Determine date range
      const now = new Date()
      let startDate, endDate

      if (showCustomPicker && customDateFrom && customDateTo) {
        startDate = new Date(customDateFrom)
        endDate = new Date(customDateTo)
        endDate.setHours(23, 59, 59, 999)
      } else {
        const range = DATE_RANGES.find(r => r.id === selectedRange) || DATE_RANGES[1]
        endDate = now
        startDate = subDays(now, range.days)
      }

      // Fetch vendor's orders within date range
      const { data: orders, error: ordersError } = await supabase
        .from('orders')
        .select(`
          id,
          total,
          status,
          created_at,
          delivered_at,
          order_items (
            id,
            product_id,
            quantity,
            unit_price
          )
        `)
        .eq('vendor_id', user.id)
        .gte('created_at', startDate.toISOString())
        .lte('created_at', endDate.toISOString())
        .order('created_at', { ascending: true })

      if (ordersError) throw ordersError

      // Fetch vendor's products
      const { data: products, error: productsError } = await supabase
        .from('products')
        .select('id, name, category, price_per_unit')
        .eq('vendor_id', user.id)

      if (productsError) throw productsError

      const productsById = new Map((products || []).map((p) => [p.id, p]))

      // Determine granularity and generate time buckets
      const range = DATE_RANGES.find(r => r.id === selectedRange)
      const granularity = showCustomPicker
        ? (Math.ceil((endDate - startDate) / (1000 * 60 * 60 * 24)) > 90 ? 'week' : 'day')
        : range?.granularity || 'day'

      const timeBuckets = []
      const labels = []

      if (granularity === 'day') {
        const days = eachDayOfInterval({ start: startDate, end: endDate })
        days.forEach(day => {
          timeBuckets.push({ start: day, end: day })
          labels.push(format(day, 'dd/MM'))
        })
      } else if (granularity === 'week') {
        const weeks = eachWeekOfInterval({ start: startDate, end: endDate }, { weekStartsOn: 1 })
        weeks.forEach(week => {
          const weekStart = startOfWeek(week, { weekStartsOn: 1 })
          const weekEnd = endOfWeek(week, { weekStartsOn: 1 })
          timeBuckets.push({ start: weekStart, end: weekEnd })
          labels.push(format(weekStart, 'dd/MM'))
        })
      } else {
        const months = eachMonthOfInterval({ start: startDate, end: endDate })
        months.forEach(month => {
          const monthStart = startOfMonth(month)
          const monthEnd = endOfMonth(month)
          timeBuckets.push({ start: monthStart, end: monthEnd })
          labels.push(format(monthStart, 'MMM yy'))
        })
      }

      // Calculate revenue per time bucket
      const revenueByBucket = timeBuckets.map(bucket => {
        const bucketOrders = (orders || []).filter(order => {
          const orderDate = new Date(order.created_at)
          return orderDate >= bucket.start && orderDate <= bucket.end
        })
        return bucketOrders.reduce((sum, order) => sum + (order.total || 0), 0)
      })

      const revenueData = {
        labels,
        datasets: [
          {
            label: t('vendor.analytics.revenue') || 'Revenue (MAD)',
            data: revenueByBucket,
            borderColor: '#16a34a',
            backgroundColor: 'rgba(22, 163, 74, 0.1)',
            fill: true,
            tension: 0.4,
          },
        ],
      }

      // Calculate top products by sales
      const productSales = {}
      orders?.forEach(order => {
        order.order_items?.forEach(item => {
          if (!productSales[item.product_id]) {
            productSales[item.product_id] = { name: '', total: 0, quantity: 0 }
          }
          productSales[item.product_id].total += item.quantity * (item.unit_price || 0)
          productSales[item.product_id].quantity += item.quantity
        })
      })

      // Hydrate product names from already-fetched products (avoid extra query)
      Object.keys(productSales).forEach((productId) => {
        const product = productsById.get(productId)
        if (product) productSales[productId].name = product.name
      })

      // Sort by total and get top 5
      const topProducts = Object.entries(productSales)
        .sort((a, b) => b[1].total - a[1].total)
        .slice(0, 5)

      const topProductsData = {
        labels: topProducts.map(([_, data]) => data.name || 'منتج'),
        datasets: [
          {
            label: t('vendor.analytics.sales') || 'Sales (MAD)',
            data: topProducts.map(([_, data]) => data.total),
            backgroundColor: [
              'rgba(22, 163, 74, 0.8)',
              'rgba(59, 130, 246, 0.8)',
              'rgba(249, 115, 22, 0.8)',
              'rgba(168, 85, 247, 0.8)',
              'rgba(236, 72, 153, 0.8)',
            ],
          },
        ],
      }

      // Calculate category distribution
      const categorySales = {}
      orders?.forEach(order => {
        order.order_items?.forEach(item => {
          const product = productsById.get(item.product_id)
          if (product) {
            const category = product.category || 'أخرى'
            if (!categorySales[category]) {
              categorySales[category] = 0
            }
            categorySales[category] += item.quantity * (item.unit_price || 0)
          }
        })
      })

      const categoryColors = [
        'rgba(22, 163, 74, 0.8)',
        'rgba(249, 115, 22, 0.8)',
        'rgba(59, 130, 246, 0.8)',
        'rgba(168, 85, 247, 0.8)',
        'rgba(236, 72, 153, 0.8)',
      ]

      const categoryData = {
        labels: Object.keys(categorySales),
        datasets: [
          {
            data: Object.values(categorySales),
            backgroundColor: categoryColors.slice(0, Object.keys(categorySales).length),
          },
        ],
      }

      // ============================================
      // Calculate REAL key metrics (no random data!)
      // ============================================

      const totalRevenue = orders?.reduce((sum, order) => sum + (order.total || 0), 0) || 0
      const totalOrders = orders?.length || 0
      const avgOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0

      // Conversion rate: orders / unique product views (using order_items as proxy)
      const totalItemsSold = orders?.reduce((sum, order) =>
        sum + (order.order_items?.reduce((s, item) => s + item.quantity, 0) || 0), 0) || 0
      const conversionRate = totalOrders > 0
        ? Math.round((totalOrders / Math.max(1, totalItemsSold)) * 100)
        : 0

      // Repeat customers: buyers with more than 1 order
      const buyerOrderCount = {}
      orders?.forEach(order => {
        if (order.buyer_id) {
          buyerOrderCount[order.buyer_id] = (buyerOrderCount[order.buyer_id] || 0) + 1
        }
      })
      const repeatBuyers = Object.values(buyerOrderCount).filter(count => count > 1).length
      const uniqueBuyers = Object.keys(buyerOrderCount).length
      const repeatCustomers = uniqueBuyers > 0
        ? Math.round((repeatBuyers / uniqueBuyers) * 100)
        : 0

      // Average delivery time from delivered_at - created_at
      const deliveredOrders = orders?.filter(o => o.delivered_at && o.created_at) || []
      let avgDeliveryTime = 0
      if (deliveredOrders.length > 0) {
        const totalDays = deliveredOrders.reduce((sum, order) => {
          const created = new Date(order.created_at)
          const delivered = new Date(order.delivered_at)
          return sum + ((delivered - created) / (1000 * 60 * 60 * 24))
        }, 0)
        avgDeliveryTime = (totalDays / deliveredOrders.length).toFixed(1)
      }

      const keyMetrics = {
        totalRevenue,
        totalOrders,
        avgOrderValue,
        conversionRate,
        repeatCustomers: Math.max(0, repeatCustomers),
        avgDeliveryTime,
      }

      setAnalytics({
        revenueData,
        topProductsData,
        categoryData,
        keyMetrics,
        rawOrders: orders || [],
        rawProducts: products || [],
      })
    } catch (error) {
      logger.error('Error loading analytics:', error)
    } finally {
      setLoading(false)
    }
  }, [user, selectedRange, customDateFrom, customDateTo, showCustomPicker, t])

  useEffect(() => {
    loadAnalytics()
  }, [loadAnalytics])

  // ============================================
  // Export to CSV
  // ============================================

  const handleExportCSV = async () => {
    setExporting(true)
    try {
      const { rawOrders } = analytics

      if (rawOrders.length === 0) {
        toast.error('No data to export')
        return
      }

      // Build CSV content
      const headers = ['Order ID', 'Date', 'Status', 'Total (MAD)', 'Items Count', 'Buyer ID']
      const rows = rawOrders.map(order => [
        order.id.slice(0, 8),
        new Date(order.created_at).toLocaleDateString('en-CA'),
        order.status,
        (order.total || 0).toFixed(2),
        order.order_items?.length || 0,
        order.buyer_id?.slice(0, 8) || '',
      ])

      const csvContent = [
        headers.join(','),
        ...rows.map(row => row.map(cell => `"${cell}"`).join(',')),
      ].join('\n')

      // Download
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' })
      const url = URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = `vendor-analytics-${new Date().toISOString().split('T')[0]}.csv`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)

      toast.success('Analytics exported as CSV!')
    } catch (error) {
      logger.error('Export error:', error)
      toast.error('Failed to export data')
    } finally {
      setExporting(false)
    }
  }

  // ============================================
  // Chart Options
  // ============================================

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      tooltip: {
        callbacks: {
          label: (context) => `${context.dataset.label}: ${formatPrice(context.parsed.y)}`,
        },
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        grid: { color: 'rgba(0, 0, 0, 0.05)' },
        ticks: {
          callback: (value) => formatPrice(value),
        },
      },
      x: {
        grid: { display: false },
      },
    },
  }

  const doughnutOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'bottom',
      },
      tooltip: {
        callbacks: {
          label: (context) => `${context.label}: ${formatPrice(context.parsed)}`,
        },
      },
    },
  }

  // ============================================
  // Loading State
  // ============================================

  if (loading) {
    return <LoadingSpinner size="lg" />
  }

  // ============================================
  // Main Render
  // ============================================

  const currentRange = DATE_RANGES.find(r => r.id === selectedRange)

  return (
    <div>
      {/* Header with Date Range Picker and Export */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-8 gap-4">
        <h1 className="text-2xl font-bold text-gray-900">{t('vendor.analytics.title')}</h1>

        <div className="flex flex-wrap items-center gap-3">
          {/* Date Range Selector */}
          <div className="flex items-center gap-2">
            <CalendarIcon className="w-5 h-5 text-gray-400" />
            <select
              value={showCustomPicker ? 'custom' : selectedRange}
              onChange={(e) => {
                if (e.target.value === 'custom') {
                  setShowCustomPicker(true)
                } else {
                  setShowCustomPicker(false)
                  setSelectedRange(e.target.value)
                }
              }}
              className="input text-sm py-2 pr-8"
            >
              {DATE_RANGES.map(range => (
                <option key={range.id} value={range.id}>
                  {range.labelAr}
                </option>
              ))}
              <option value="custom">تاريخ مخصص</option>
            </select>
          </div>

          {/* Custom Date Range */}
          {showCustomPicker && (
            <div className="flex items-center gap-2">
              <input
                type="date"
                value={customDateFrom}
                onChange={(e) => setCustomDateFrom(e.target.value)}
                className="input text-sm py-2"
              />
              <span className="text-gray-400">→</span>
              <input
                type="date"
                value={customDateTo}
                onChange={(e) => setCustomDateTo(e.target.value)}
                className="input text-sm py-2"
              />
              <button
                onClick={() => {
                  if (customDateFrom && customDateTo) {
                    setShowCustomPicker(false)
                    loadAnalytics()
                  }
                }}
                className="btn-primary text-sm py-2 px-3"
              >
                تطبيق
              </button>
            </div>
          )}

          {/* Export Button */}
          <button
            onClick={handleExportCSV}
            disabled={exporting || analytics.rawOrders.length === 0}
            className="btn-outline text-sm py-2 px-3 flex items-center gap-2 disabled:opacity-50"
          >
            {exporting ? (
              <LoadingSpinner size="sm" />
            ) : (
              <ArrowDownTrayIcon className="w-4 h-4" />
            )}
            Export CSV
          </button>
        </div>
      </div>

      {/* Key Metrics Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        <Card className="p-4 bg-gradient-to-br from-green-50 to-emerald-50 border-green-200">
          <p className="text-sm text-green-600 mb-1">إجمالي الإيرادات</p>
          <p className="text-2xl font-bold text-green-900">{formatPrice(analytics.keyMetrics.totalRevenue)}</p>
          <p className="text-xs text-green-500 mt-1">{analytics.keyMetrics.totalOrders} طلب</p>
        </Card>
        <Card className="p-4 bg-gradient-to-br from-blue-50 to-indigo-50 border-blue-200">
          <p className="text-sm text-blue-600 mb-1">متوسط قيمة الطلب</p>
          <p className="text-2xl font-bold text-blue-900">{formatPrice(analytics.keyMetrics.avgOrderValue)}</p>
        </Card>
        <Card className="p-4 bg-gradient-to-br from-purple-50 to-violet-50 border-purple-200">
          <p className="text-sm text-purple-600 mb-1">العملاء المتكررون</p>
          <p className="text-2xl font-bold text-purple-900">{analytics.keyMetrics.repeatCustomers}%</p>
        </Card>
        <Card className="p-4 bg-gradient-to-br from-orange-50 to-amber-50 border-orange-200">
          <p className="text-sm text-orange-600 mb-1">متوسط وقت التوصيل</p>
          <p className="text-2xl font-bold text-orange-900">{analytics.keyMetrics.avgDeliveryTime} أيام</p>
        </Card>
      </div>

      {/* Charts Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        {/* Revenue Trend */}
        <Card className="p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">
            {t('vendor.analytics.revenueTrend')}
            {currentRange && !showCustomPicker && (
              <span className="text-sm font-normal text-gray-400 ml-2">— {currentRange.labelAr}</span>
            )}
          </h3>
          <div className="h-64">
            <Line data={analytics.revenueData} options={chartOptions} />
          </div>
        </Card>

        {/* Top Products */}
        <Card className="p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">{t('vendor.analytics.topProducts')}</h3>
          <div className="h-64">
            <Bar data={analytics.topProductsData} options={chartOptions} />
          </div>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Category Distribution */}
        <Card className="p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">
            {t('vendor.analytics.categoryDistribution') || 'المبيعات حسب الفئة'}
          </h3>
          <div className="h-64">
            <Doughnut
              data={analytics.categoryData}
              options={doughnutOptions}
            />
          </div>
        </Card>

        {/* Orders by Status */}
        <Card className="p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">الطلبات حسب الحالة</h3>
          <div className="space-y-3">
            {(() => {
              const statusCounts = {}
              analytics.rawOrders.forEach(order => {
                statusCounts[order.status] = (statusCounts[order.status] || 0) + 1
              })
              return Object.entries(statusCounts)
                .sort((a, b) => b[1] - a[1])
                .map(([status, count]) => (
                  <div key={status} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <span className="text-sm text-gray-600 capitalize">{status.replace(/_/g, ' ')}</span>
                    <span className="text-sm font-semibold text-gray-900">{count}</span>
                  </div>
                ))
            })()}
          </div>
        </Card>
      </div>
    </div>
  )
}

export default VendorAnalytics

