import { useState, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import { useAuthStore } from '@/store/authStore'
import { supabase } from '@/services/supabase'
import { ordersApi, deliveriesApi } from '@/services/deliveries'
import { Card, Badge, Button, Modal, Map, ChatComponent, OrderTimeline } from '@/components/ui'
import ErrorBoundary from '@/components/ErrorBoundary'
import { formatPrice } from '@/utils/currency'
import {
  EyeIcon,
  CheckCircleIcon,
  XCircleIcon,
  TruckIcon,
  MapPinIcon,
  XMarkIcon,
  ChatBubbleLeftRightIcon,
  ClockIcon,
} from '@heroicons/react/24/outline'
import toast from 'react-hot-toast'
import { logger } from '@/utils/logger'

const VendorOrders = () => {
  const { t, i18n } = useTranslation()
  const { profile } = useAuthStore()
  const [orders, setOrders] = useState([])
  const [drivers, setDrivers] = useState([])
  const [assignModalOpen, setAssignModalOpen] = useState(false)
  const [trackingModalOpen, setTrackingModalOpen] = useState(false)
  const [chatModalOpen, setChatModalOpen] = useState(false)
  const [timelineModalOpen, setTimelineModalOpen] = useState(false)
  const [selectedOrder, setSelectedOrder] = useState(null)
  const [selectedDriver, setSelectedDriver] = useState(null)
  const [trackingData, setTrackingData] = useState(null)
  const [chatReceiver, setChatReceiver] = useState(null)
  const [loading, setLoading] = useState(true)
  const [processingOrder, setProcessingOrder] = useState(null)
  const [filterStatus, setFilterStatus] = useState('all')

  useEffect(() => {
    loadOrders()

    // Subscribe to real-time updates with notification
    const channel = ordersApi.subscribeToVendorOrders(
      profile.id,
      (payload) => {
        // ✅ Show toast for new pending orders
        if (payload.eventType === 'INSERT' && payload.new?.status === 'pending') {
          toast.success(t('vendor.orders.notifications.newOrder', '🛒 New order received: {{orderNumber}}!', {
            orderNumber: payload.new.order_number || 'Order'
          }), {
            duration: 5000,
            icon: '🛒',
          })
        }

        // Reload orders list
        loadOrders()
      }
    )

    return () => channel.unsubscribe()
  }, [profile.id, t])

  const loadOrders = async () => {
    try {
      const { data, error } = await supabase
        .from('orders')
        .select(`
          *,
          buyer:profiles!buyer_id(first_name, last_name, phone),
          items:order_items(*, product:products(name)),
          deliveries:deliveries(
            id,
            status,
            driver:profiles!driver_id(first_name, last_name, phone),
            current_latitude,
            current_longitude,
            delivery_latitude,
            delivery_longitude
          )
        `)
        .eq('vendor_id', profile.id)
        .order('created_at', { ascending: false })

      if (error) throw error
      setOrders(data || [])
    } catch (error) {
      logger.error('Error loading orders:', error)
    } finally {
      setLoading(false)
    }
  }

  const loadAvailableDrivers = async () => {
    try {
      const driversList = await deliveriesApi.getAvailableDrivers(
        profile.latitude || 33.5731,
        profile.longitude || -7.5898,
        20
      )
      setDrivers(driversList)
    } catch (error) {
      logger.error('Error loading drivers:', error)
    }
  }

  const handleAcceptOrder = async (orderId) => {
    setProcessingOrder(orderId)
    try {
      await ordersApi.acceptOrder(orderId)
      toast.success(t('vendor.orders.notifications.orderAccepted', 'Order accepted!'))
      loadOrders()
    } catch (error) {
      logger.error('Error accepting order:', error)
      toast.error(t('vendor.orders.errors.acceptFailed', 'Failed to accept order'))
    } finally {
      setProcessingOrder(null)
    }
  }

  const handleRejectOrder = async (orderId) => {
    setProcessingOrder(orderId)
    try {
      await ordersApi.rejectOrder(orderId, 'Not available')
      toast.success(t('vendor.orders.notifications.orderRejected', 'Order rejected'))
      loadOrders()
    } catch (error) {
      logger.error('Error rejecting order:', error)
      toast.error(t('vendor.orders.errors.rejectFailed', 'Failed to reject order'))
    } finally {
      setProcessingOrder(null)
    }
  }

  const handleOpenAssignModal = async (order) => {
    setSelectedOrder(order)
    setAssignModalOpen(true)
    await loadAvailableDrivers()
  }

  const handleTrackOrder = async (order) => {
    const delivery = order.deliveries?.[0]
    if (delivery) {
      setTrackingData({
        driver: delivery.driver,
        currentLat: delivery.current_latitude,
        currentLng: delivery.current_longitude,
        deliveryLat: delivery.delivery_latitude,
        deliveryLng: delivery.delivery_longitude,
        status: delivery.status,
      })
      setTrackingModalOpen(true)
    }
  }

  const handleOpenChat = (order, driver) => {
    setSelectedOrder(order)
    setChatReceiver({
      id: driver?.driver_id || driver?.id,
      name: `${driver?.first_name || ''} ${driver?.last_name || ''}`,
      phone: driver?.phone
    })
    setChatModalOpen(true)
  }

  const handleOpenTimeline = (order) => {
    setSelectedOrder(order)
    setTimelineModalOpen(true)
  }

  const handleAssignDriver = async () => {
    if (!selectedOrder || !selectedDriver) return

    try {
      const delivery = selectedOrder.deliveries?.[0]
      if (delivery) {
        await deliveriesApi.assignDriver(delivery.id, selectedDriver.driver_id)
        toast.success('Driver assigned successfully!')
      }

      setAssignModalOpen(false)
      setSelectedOrder(null)
      setSelectedDriver(null)
      loadOrders()
    } catch (error) {
      toast.error('Failed to assign driver')
    }
  }

  const filteredOrders = filterStatus === 'all' 
    ? orders 
    : orders.filter(o => o.status === filterStatus)

  const statusColors = {
    pending: 'badge-warning',
    vendor_accepted: 'badge-primary',
    vendor_rejected: 'badge-danger',
    driver_assigned: 'bg-blue-100 text-blue-700 badge',
    driver_accepted: 'bg-blue-100 text-blue-700 badge',
    driver_picked_up: 'bg-purple-100 text-purple-700 badge',
    on_the_way: 'bg-indigo-100 text-indigo-700 badge',
    delivered: 'badge-gray',
    cancelled: 'badge-danger',
  }

  const statusLabels = {
    pending: 'Pending',
    vendor_accepted: 'Accepted',
    vendor_rejected: 'Rejected',
    driver_assigned: 'Driver Assigned',
    driver_accepted: 'Driver Accepted',
    driver_picked_up: 'Picked Up',
    on_the_way: 'On the Way',
    delivered: 'Delivered',
    cancelled: 'Cancelled',
  }

  return (
    <div>
      <h1 className="text-2xl font-bold text-gray-900 mb-8">Orders Management</h1>

      {/* Status Filter */}
      <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
        {['all', 'pending', 'vendor_accepted', 'driver_assigned', 'on_the_way', 'delivered'].map((status) => (
          <button
            key={status}
            onClick={() => setFilterStatus(status)}
            className={`px-4 py-2 rounded-xl text-sm font-medium whitespace-nowrap capitalize ${
              filterStatus === status
                ? 'bg-green-500 text-white'
                : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
          >
            {statusLabels[status] || status}
          </button>
        ))}
      </div>

      {/* Orders List */}
      <div className="space-y-4">
        {filteredOrders.length === 0 ? (
          <Card className="p-12 text-center">
            <TruckIcon className="w-16 h-16 text-gray-300 mx-auto mb-4" />
            <p className="text-gray-500">No orders found</p>
          </Card>
        ) : (
          filteredOrders.map((order) => (
            <Card key={order.id} className="p-6">
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="font-semibold text-gray-900">{order.order_number}</h3>
                    <Badge className={statusColors[order.status]}>
                      {statusLabels[order.status]}
                    </Badge>
                  </div>

                  <p className="text-sm text-gray-600 mb-1">
                    <span className="font-medium">Buyer:</span> {order.buyer?.first_name} {order.buyer?.last_name}
                  </p>
                  <p className="text-sm text-gray-500 mb-1">
                    <span className="font-medium">Items:</span> {order.items?.length || 0} items
                  </p>
                  <p className="text-sm text-gray-500">
                    {new Date(order.created_at).toLocaleDateString(
                      i18n.language === 'ar' ? 'ar-MA' : i18n.language === 'fr' ? 'fr-MA' : 'en-US',
                      { year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' }
                    )}
                  </p>
                </div>

                <div className="text-right">
                  <p className="text-xl font-bold text-gray-900 mb-3">{formatPrice(order.total)}</p>

                  <div className="flex flex-col gap-2">
                    {order.status === 'pending' && (
                      <>
                        <Button
                          variant="primary"
                          size="sm"
                          leftIcon={<CheckCircleIcon className="w-4 h-4" />}
                          onClick={() => handleAcceptOrder(order.id)}
                          disabled={processingOrder === order.id}
                        >
                          {processingOrder === order.id ? t('vendor.orders.accepting', 'Accepting...') : t('vendor.orders.accept', 'Accept')}
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          leftIcon={<XCircleIcon className="w-4 h-4" />}
                          onClick={() => handleRejectOrder(order.id)}
                          disabled={processingOrder === order.id}
                        >
                          {processingOrder === order.id ? t('vendor.orders.rejecting', 'Rejecting...') : t('vendor.orders.reject', 'Reject')}
                        </Button>
                      </>
                    )}

                    {order.status === 'vendor_accepted' && (
                      <Button
                        variant="primary"
                        size="sm"
                        leftIcon={<TruckIcon className="w-4 h-4" />}
                        onClick={() => handleOpenAssignModal(order)}
                      >
                        Assign Driver
                      </Button>
                    )}

                    {['driver_assigned', 'driver_accepted', 'driver_picked_up', 'on_the_way'].includes(order.status) && (
                      <div className="flex flex-col gap-2">
                        <Button
                          variant="outline"
                          size="sm"
                          leftIcon={<EyeIcon className="w-4 h-4" />}
                          onClick={() => handleTrackOrder(order)}
                        >
                          Track
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          leftIcon={<ChatBubbleLeftRightIcon className="w-4 h-4" />}
                          onClick={() => handleOpenChat(order, order.deliveries?.[0]?.driver)}
                        >
                          Chat
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          leftIcon={<ClockIcon className="w-4 h-4" />}
                          onClick={() => handleOpenTimeline(order)}
                        >
                          Timeline
                        </Button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </Card>
          ))
        )}
      </div>

      {/* Assign Driver Modal */}
      <Modal
        isOpen={assignModalOpen}
        onClose={() => {
          setAssignModalOpen(false)
          setSelectedOrder(null)
          setSelectedDriver(null)
        }}
        title="Assign Driver"
        size="lg"
      >
        <div className="space-y-4">
          <p className="text-sm text-gray-500">
            Select a driver to deliver order {selectedOrder?.order_number}
          </p>

          {drivers.length === 0 ? (
            <div className="text-center py-8">
              <TruckIcon className="w-12 h-12 text-gray-300 mx-auto mb-3" />
              <p className="text-gray-500">No available drivers nearby</p>
            </div>
          ) : (
            <div className="space-y-3 max-h-80 overflow-y-auto">
              {drivers.map((driver) => (
                <button
                  key={driver.driver_id}
                  onClick={() => setSelectedDriver(driver)}
                  className={`w-full flex items-center gap-4 p-4 rounded-xl border-2 text-left transition-all ${
                    selectedDriver?.driver_id === driver.driver_id
                      ? 'border-green-500 bg-green-50'
                      : 'border-gray-200 hover:border-gray-300'
                  }`}
                >
                  <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center">
                    <TruckIcon className="w-6 h-6 text-gray-600" />
                  </div>
                  <div className="flex-1">
                    <p className="font-semibold text-gray-900">
                      {driver.first_name} {driver.last_name}
                    </p>
                    <p className="text-sm text-gray-500 capitalize">
                      {driver.vehicle_type} • {driver.vehicle_plate || 'No plate'}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-medium text-gray-900">{driver.distance?.toFixed(1)} km</p>
                    <p className="text-xs text-gray-500">⭐ {driver.rating || 'New'}</p>
                  </div>
                </button>
              ))}
            </div>
          )}

          <div className="flex gap-3 pt-4">
            <Button
              variant="outline"
              className="flex-1"
              onClick={() => {
                setAssignModalOpen(false)
                setSelectedOrder(null)
                setSelectedDriver(null)
              }}
            >
              Cancel
            </Button>
            <Button
              variant="primary"
              className="flex-1"
              onClick={handleAssignDriver}
              disabled={!selectedDriver}
            >
              Assign Driver
            </Button>
          </div>
        </div>
      </Modal>

      {/* Tracking Modal */}
      <Modal
        isOpen={trackingModalOpen}
        onClose={() => {
          setTrackingModalOpen(false)
          setTrackingData(null)
        }}
        title="Order Tracking"
        size="lg"
      >
        {trackingData && (
          <div className="space-y-4">
            {/* Driver Info */}
            <div className="flex items-center gap-4 p-4 bg-gray-50 rounded-xl">
              <div className="w-12 h-12 bg-green-100 rounded-full flex items-center justify-center">
                <TruckIcon className="w-6 h-6 text-green-600" />
              </div>
              <div className="flex-1">
                <p className="font-semibold text-gray-900">
                  {trackingData.driver?.first_name} {trackingData.driver?.last_name}
                </p>
                <p className="text-sm text-gray-500">Status: {trackingData.status}</p>
              </div>
              <a
                href={`tel:${trackingData.driver?.phone}`}
                className="btn-sm btn-primary"
              >
                Call Driver
              </a>
            </div>

            {/* Map */}
            <Map
              center={[
                trackingData.currentLat || trackingData.deliveryLat || 33.5731,
                trackingData.currentLng || trackingData.deliveryLng || -7.5898
              ]}
              zoom={13}
              markers={[
                ...(trackingData.deliveryLat && trackingData.deliveryLng ? [{
                  lat: trackingData.deliveryLat,
                  lng: trackingData.deliveryLng,
                  popup: 'Delivery Location'
                }] : []),
                ...(trackingData.currentLat && trackingData.currentLng ? [{
                  lat: trackingData.currentLat,
                  lng: trackingData.currentLng,
                  popup: 'Driver Location'
                }] : [])
              ]}
              height="300px"
            />
          </div>
        )}
      </Modal>

      {/* Chat Modal */}
      <Modal
        isOpen={chatModalOpen}
        onClose={() => {
          setChatModalOpen(false)
          setChatReceiver(null)
        }}
        title={`Chat with ${chatReceiver?.name || 'Driver'}`}
        size="lg"
      >
        {selectedOrder && chatReceiver && (
          <div className="h-[500px]">
            <ChatComponent
              deliveryId={selectedOrder.deliveries?.[0]?.id}
              receiverId={chatReceiver.id}
              receiverName={chatReceiver.name}
              receiverPhone={chatReceiver.phone}
            />
          </div>
        )}
      </Modal>

      {/* Timeline Modal */}
      <Modal
        isOpen={timelineModalOpen}
        onClose={() => {
          setTimelineModalOpen(false)
          setSelectedOrder(null)
        }}
        title="Order Timeline"
        size="lg"
      >
        {selectedOrder && (
          <div className="max-h-[500px] overflow-y-auto">
            <OrderTimeline orderId={selectedOrder.id} />
          </div>
        )}
      </Modal>
    </div>
  )
}

