// ============================================
// 6. PERFORMANCE TRACKING
// ============================================

/**
 * Track page load time
 */
export const trackPageLoadTime = () => {
  if (import.meta.env.DEV) return

  window.addEventListener('load', () => {
    setTimeout(() => {
      const timing = performance.getEntriesByType('navigation')[0]
      if (timing) {
        trackEvent('page_load_time', {
          load_time: Math.round(timing.loadEventEnd - timing.startTime),
          dom_content_loaded: Math.round(timing.domContentLoadedEventEnd - timing.startTime),
          dom_complete: Math.round(timing.domComplete - timing.startTime),
        })
      }
    }, 0)
  })
}

// ============================================
// 7. REACT HOOKS
// ============================================

/**
 * Hook to track page views
 */
export const usePageViewTracking = () => {
  const location = useLocation()

  useEffect(() => {
    trackPageView(location.pathname + location.search, document.title)
  }, [location])
}

/**
 * Hook to track time on page
 */
export const useTimeOnPage = (pageName) => {
  useEffect(() => {
    const startTime = Date.now()

    return () => {
      const timeSpent = Math.round((Date.now() - startTime) / 1000)
      trackEvent('time_on_page', {
        page: pageName,
        seconds: timeSpent,
      })
    }
  }, [pageName])
}

// ============================================
// 8. OUTBOUND LINK TRACKING
// ============================================

/**
 * Track outbound link clicks
 */
export const setupOutboundLinkTracking = () => {
  if (import.meta.env.DEV) return

  document.addEventListener('click', (e) => {
    const link = e.target.closest('a')
    if (!link) return

    const href = link.getAttribute('href')
    if (!href || href.startsWith('/') || href.startsWith('#')) return

    // Outbound link
    trackEvent('outbound_click', {
      url: href,
      text: link.textContent?.substring(0, 100),
    })
  })
}

// ============================================
// 9. ERROR TRACKING
// ============================================

/**
 * Track JavaScript errors
 */
export const setupErrorTracking = () => {
  if (import.meta.env.DEV) return

  window.addEventListener('error', (event) => {
    trackEvent('js_error', {
      message: event.message?.substring(0, 200),
      filename: event.filename,
      lineno: event.lineno,
      colno: event.colno,
    })
  })

  window.addEventListener('unhandledrejection', (event) => {
    trackEvent('unhandled_promise', {
      reason: String(event.reason)?.substring(0, 200),
    })
  })
}

// ============================================
// 10. INITIALIZATION HELPER
// ============================================

/**
 * Initialize all analytics features
 */
export const initializeAllAnalytics = () => {
  initializeAnalytics()
  trackPageLoadTime()
  setupOutboundLinkTracking()
  setupErrorTracking()
}

// ============================================
// Default export
// ============================================
export default {
  initializeAnalytics,
  trackPageView,
  trackEvent,
  trackProductView,
  trackAddToCart,
  trackRemoveFromCart,
  trackCheckoutStart,
  trackPurchase,
  trackLoginAttempt,
  trackRegistration,
  trackSearch,
  trackFilter,
  trackPageLoadTime,
  usePageViewTracking,
  useTimeOnPage,
  setupOutboundLinkTracking,
  setupErrorTracking,
  initializeAllAnalytics,
}

/**
 * Authentication API Services
 * Complete auth endpoints with validation, error handling, and state management
 */

import { supabase } from '@/services/supabase';
import { authSchemas } from '../../utils/validators';
import { ApiError, retryWithBackoff, extractFieldErrors } from '../../utils/errorHandler';
import { API_ENDPOINTS, HTTP_STATUS, ERROR_MESSAGES } from '../../constants/apiEndpoints';

/**
 * Register new user
 */
export const registerUser = async (data) => {
  try {
    // Validate input
    const validated = await authSchemas.register.parseAsync(data);

    // Check if user already exists
    const { data: existingUser } = await supabase
      .from('profiles')
      .select('id')
      .eq('email', validated.email)
      .single();

    if (existingUser) {
      throw new ApiError(
        ERROR_MESSAGES.EMAIL_ALREADY_EXISTS,
        HTTP_STATUS.CONFLICT,
        [{ field: 'email', message: ERROR_MESSAGES.EMAIL_ALREADY_EXISTS }]
      );
    }

    // Create auth user with Supabase
    const { data: authData, error: authError } = await supabase.auth.signUp({
      email: validated.email,
      password: validated.password,
      options: {
        data: {
          full_name: validated.fullName,
          role: validated.role,
          phone: validated.phone,
        },
      },
    });

    if (authError) {
      throw new ApiError(authError.message, HTTP_STATUS.BAD_REQUEST, [], authError);
    }

    // Create profile
    const { data: profile, error: profileError } = await supabase
      .from('profiles')
      .insert({
        id: authData.user.id,
        email: validated.email,
        first_name: validated.fullName.split(' ')[0],
        last_name: validated.fullName.split(' ').slice(1).join(' '),
        phone: validated.phone,
        role: validated.role,
        store_name: validated.businessName,
        created_at: new Date().toISOString(),
      })
      .select()
      .single();

    if (profileError) {
      // Clean up auth user if profile creation fails
      await supabase.auth.admin.deleteUser(authData.user.id);
      throw new ApiError(profileError.message, HTTP_STATUS.BAD_REQUEST, [], profileError);
    }

    return {
      success: true,
      message: 'Registration successful. Please check your email to verify your account.',
      data: {
        userId: profile.id,
        email: profile.email,
        role: profile.role,
      },
    };
  } catch (error) {
    if (error instanceof ApiError) throw error;
    throw new ApiError(error.message, HTTP_STATUS.BAD_REQUEST, [], error);
  }
};

/**
 * Login user
 */
export const loginUser = async (data) => {
  try {
    // Validate input
    const validated = await authSchemas.login.parseAsync(data);

    // Sign in with Supabase
    const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
      email: validated.email,
      password: validated.password,
    });

    if (authError) {
      throw new ApiError(
        ERROR_MESSAGES.INVALID_CREDENTIALS,
        HTTP_STATUS.UNAUTHORIZED,
        []
      );
    }

    // Get user profile
    const { data: profile, error: profileError } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', authData.user.id)
      .single();

    if (profileError) {
      throw new ApiError(profileError.message, HTTP_STATUS.BAD_REQUEST, [], profileError);
    }

    // Check if email is verified
    if (!authData.user.email_confirmed_at && profile.role !== 'admin') {
      throw new ApiError(
        ERROR_MESSAGES.EMAIL_NOT_VERIFIED,
        HTTP_STATUS.FORBIDDEN
      );
    }

    return {
      success: true,
      message: 'Logged in successfully',
      data: {
        userId: profile.id,
        email: profile.email,
        role: profile.role,
        token: authData.session.access_token,
        refreshToken: authData.session.refresh_token,
        user: profile,
      },
    };
  } catch (error) {
    if (error instanceof ApiError) throw error;
    throw new ApiError(error.message, HTTP_STATUS.UNAUTHORIZED, [], error);
  }
};

/**
 * Verify email with OTP
 */
export const verifyEmail = async (data) => {
  try {
    // Validate input
    const validated = await authSchemas.verifyEmail.parseAsync(data);

    // Verify OTP (simplified - in production use proper OTP service)
    const { data: otpRecord, error: otpError } = await supabase
      .from('otp_tokens')
      .select('*')
      .eq('email', validated.email)
      .eq('token', validated.otp)
      .gt('expires_at', new Date().toISOString())
      .single();

    if (otpError || !otpRecord) {
      throw new ApiError('Invalid or expired OTP', HTTP_STATUS.BAD_REQUEST);
    }

    // Update user email_confirmed_at
    const { data: user } = await supabase.auth.admin.getUserById(otpRecord.user_id);
    await supabase.auth.admin.updateUserById(user.id, { email_confirmed_at: new Date().toISOString() });

    // Delete used OTP
    await supabase.from('otp_tokens').delete().eq('id', otpRecord.id);

    // Get updated profile
    const { data: profile } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', otpRecord.user_id)
      .single();

    return {
      success: true,
      message: 'Email verified successfully',
      data: {
        verified: true,
        profile,
      },
    };
  } catch (error) {
    if (error instanceof ApiError) throw error;
    throw new ApiError(error.message, HTTP_STATUS.BAD_REQUEST, [], error);
  }
};

